                <div
                  className="mb-6 p-4 rounded-xl border text-sm"
                  style={{
                    borderColor: isDark ? "rgba(16,185,129,0.35)" : "rgba(16,185,129,0.25)",
                    background: isDark ? "rgba(16,185,129,0.12)" : "rgba(16,185,129,0.08)",
                    color: isDark ? "#6EE7B7" : "#047857",
                  }}
                >
                  {t("shopItemAssigned")}
                </div>

                {viewingPurchase.description && (
                  <div className="mb-6">
                    <h3 className="text-sm font-semibold mb-2" style={{ color: textColors.primary }}>
                      {t("shopProductDescription")}
                    </h3>
                    <p className="text-sm" style={{ color: textColors.secondary }}>
                      {getLocalizedShopItemDesc(viewingPurchase as any, lang, t)}
                    </p>
                  </div>
                )}

                <button
                  type="button"
                  onClick={() => setViewingPurchase(null)}
                  className="w-full py-2.5 rounded-lg font-medium transition-colors"
                  style={{
                    color: textColors.primary,
                    background: isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.05)",
                    border: isDark ? "1px solid rgba(255,255,255,0.1)" : "1px solid rgba(0,0,0,0.1)",
                  }}
                >
                  {t("shopProductClose")}
                </button>
              </div>
            </div>
          </div>
        )}

        <CartSheet
          isOpen={isCartOpen}
          onClose={() => setIsCartOpen(false)}
          items={cartItems}
          onRemove={handleRemoveFromCart}
          onUpdateQuantity={handleUpdateCartQuantity}
          onCheckout={handleCheckout}
          totalCost={totalCartCost}
          userBalance={points}
          IconComponentMap={ICON_MAP}
        />

        <PurchaseSuccessModal
          isOpen={showSuccessModal}
          onClose={() => setShowSuccessModal(false)}
          itemTitle={successItemTitle}
          estimatedDeliveryDate={successDeliveryDate}
        />

        <DeliveryAddressModal
          isOpen={showDeliveryModal}
          onClose={() => {
            setShowDeliveryModal(false);
            setPendingPurchase(null);
          }}
          onSubmit={handleDeliverySubmit}
          isSubmitting={purchaseMutation.isPending || checkoutMutation.isPending}
