"use client";

import { useState, useEffect } from "react";
import { usePathname, useRouter } from "next/navigation";
import Link from "next/link";
import { useQuery } from "@tanstack/react-query";
import { api } from "@/api/client";
import { useAuthStore } from "@/store/authStore";
import { useLanguage } from "@/context/LanguageContext";
import type { TranslationKey } from "@/i18n/translations";
import { useTheme } from "@/context/ThemeContext";
import { getGlassCardStyle, getTextColors } from "@/utils/themeStyles";
import { FileText, ChevronDown, ChevronRight, Menu, X } from "lucide-react";

type Group = {
  id: number;
  course_id: number;
  course_title: string;
  group_name: string;
  teacher_id: number;
  students_count: number;
  created_at: string | null;
};

const GROUP_ACCENT_COLORS = [
  "#3B82F6", "#8B5CF6", "#10B981", "#F59E0B", "#EC4899", "#06B6D4", "#EF4444", "#14B8A6",
];

function SidebarContent({
  groups,
  pathname,
  onNavigate,
  textColors,
  borderSubtle,
  t,
}: {
  groups: Group[];
  pathname: string;
  onNavigate?: () => void;
  textColors: ReturnType<typeof getTextColors>;
  borderSubtle: string;
  t: (key: TranslationKey) => string;
}) {
  const [expanded, setExpanded] = useState(true);

  const reviewActive =
    pathname === "/app/teacher/courses/review" || pathname.startsWith("/app/teacher/courses/review/");

  return (
    <div className="flex flex-col h-full min-h-0">
      <button
        type="button"
        onClick={() => setExpanded(!expanded)}
        className="flex items-center justify-between w-full px-3 py-2.5 rounded-xl text-left transition-colors hover:bg-black/5 dark:hover:bg-white/5"
        style={{ color: textColors.primary }}
      >
        <span className="font-medium text-sm font-geologica">{t("teacherCoursesTabHint")}</span>
        {expanded ? <ChevronDown className="w-4 h-4 shrink-0 opacity-70" /> : <ChevronRight className="w-4 h-4 shrink-0 opacity-70" />}
      </button>

      {expanded && (
        <div className={`space-y-1 mt-2 pl-2 ml-1 border-l ${borderSubtle}`}>
          <Link
            href="/app/teacher/courses/review"
            onClick={onNavigate}
            className={`flex items-center gap-2 px-3 py-2 rounded-xl text-sm transition-colors ${
              reviewActive ? "bg-blue-600 text-white shadow-md" : "hover:bg-black/5 dark:hover:bg-white/5"
            }`}
            style={!reviewActive ? { color: textColors.primary } : undefined}
          >
            <FileText className="w-4 h-4 shrink-0" />
            {t("unreviewedAssignments")}
          </Link>

          {groups.map((g) => {
            const href = `/app/teacher/courses/${g.id}`;
            const active = pathname === href;
            const letter = (g.group_name?.trim()[0] || "?").toUpperCase();
            const color = GROUP_ACCENT_COLORS[Math.abs(g.id) % GROUP_ACCENT_COLORS.length];
            const year = g.created_at ? new Date(g.created_at).getFullYear() : "";

            return (
              <Link
                key={g.id}
                href={href}
                onClick={onNavigate}
                className={`flex items-center gap-3 px-3 py-2 rounded-xl text-sm transition-colors ${
                  active ? "bg-blue-600 text-white shadow-md" : "hover:bg-black/5 dark:hover:bg-white/5"
                }`}
                style={!active ? { color: textColors.primary } : undefined}
              >
                <span
                  className="w-9 h-9 rounded-full flex items-center justify-center text-sm font-bold shrink-0 text-white"
                  style={{ background: color }}
                >
                  {letter}
                </span>
                <span className="min-w-0 flex-1">
                  <span className="font-semibold block truncate">{g.group_name}</span>
                  {year ? (
                    <span
                      className={`text-xs block ${active ? "text-white/85" : ""}`}
                      style={!active ? { color: textColors.secondary } : undefined}
                    >
                      {year}
                    </span>
                  ) : null}
                </span>
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}

export default function TeacherCoursesLayout({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const { user, isTeacher } = useAuthStore();
  const { t } = useLanguage();
  const { theme } = useTheme();
  const glassStyle = getGlassCardStyle(theme);
  const textColors = getTextColors(theme);
  const [mobileOpen, setMobileOpen] = useState(false);

  const borderSubtle = theme === "dark" ? "border-white/12" : "border-black/10";
  const headerBorder = theme === "dark" ? "border-white/10" : "border-black/10";
  const asideBorder = theme === "dark" ? "border-white/10" : "border-black/10";

  useEffect(() => {
    if (user && !isTeacher()) {
      router.replace("/app");
    }
  }, [user, isTeacher, router]);

  useEffect(() => {
    setMobileOpen(false);
  }, [pathname]);

  const { data: groups = [] } = useQuery({
    queryKey: ["teacher-groups"],
    queryFn: async () => {
      const { data } = await api.get<Group[]>("/teacher/groups");
      return data;
    },
  });

  return (
    <div className="min-h-screen w-full max-w-full min-w-0 flex flex-col overflow-x-hidden lg:flex-row">
      <div
        className={`lg:hidden mb-3 flex items-center gap-3 rounded-xl border px-4 py-3 ${headerBorder}`}
        style={{ ...glassStyle }}
      >
        <button
          type="button"
          aria-label={t("openMenu")}
          onClick={() => setMobileOpen(true)}
          className="p-2 rounded-xl hover:bg-black/5 dark:hover:bg-white/10 transition-colors"
        >
          <Menu className="w-6 h-6" style={{ color: textColors.primary }} />
        </button>
        <span className="font-geologica font-semibold" style={{ color: textColors.primary }}>
          {t("teacherCoursesTab")}
        </span>
      </div>

      <aside
        className={`hidden lg:flex flex-col w-[280px] shrink-0 border-r min-h-screen p-4 overflow-y-auto ${asideBorder}`}
        style={{ ...glassStyle }}
      >
        <SidebarContent groups={groups} pathname={pathname} textColors={textColors} borderSubtle={borderSubtle} t={t} />
      </aside>

      {mobileOpen ? (
        <div className="lg:hidden fixed inset-0 z-50 flex">
          <button type="button" className="absolute inset-0 bg-black/50" aria-label={t("close")} onClick={() => setMobileOpen(false)} />
          <div
            className={`relative w-[280px] max-w-[85vw] h-full shadow-2xl flex flex-col p-4 border-r ${asideBorder} animate-in fade-in slide-in-from-left duration-200`}
            style={{ ...glassStyle }}
          >
            <div className="flex justify-end mb-2 shrink-0">
              <button
                type="button"
                onClick={() => setMobileOpen(false)}
                className="p-2 rounded-xl hover:bg-black/5 dark:hover:bg-white/10"
                aria-label={t("closeMenu")}
              >
                <X className="w-5 h-5" style={{ color: textColors.primary }} />
              </button>
            </div>
            <div className="overflow-y-auto flex-1 min-h-0">
              <SidebarContent
                groups={groups}
                pathname={pathname}
                onNavigate={() => setMobileOpen(false)}
                textColors={textColors}
                borderSubtle={borderSubtle}
                t={t}
              />
            </div>
          </div>
        </div>
      ) : null}

      <main className="flex-1 min-w-0 overflow-x-hidden p-4 lg:p-8">{children}</main>
    </div>
  );
}

"use client";

import { useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { useQuery, useMutation, useQueryClient, useQueries } from "@tanstack/react-query";
import { api } from "@/api/client";
import { useLanguage } from "@/context/LanguageContext";
import { formatWeekdayLongAndTime } from "@/utils/dateUtils";
import { useTheme } from "@/context/ThemeContext";
import { getGlassCardStyle, getTextColors, getInputStyle, getModalStyle } from "@/utils/themeStyles";
import { BlurFade } from "@/components/ui/blur-fade";
import { Plus, X, FileText, MoreVertical, Pencil, Trash2, Loader2, Edit2, AlertTriangle } from "lucide-react";
import { getCourseBannerUrl } from "@/lib/courseUtils";
import { useAuthStore } from "@/store/authStore";
import { DeleteConfirmButton } from "@/components/ui/DeleteConfirmButton";

type Group = {
  id: number;
  course_id: number;
  course_title: string;
  group_name: string;
  teacher_id: number;
  students_count: number;
  created_at: string | null;
};

type Assignment = {
  id: number;
  type: "assignment" | "material" | "question";
  group_id: number;
  title: string;
  deadline: string | null;
  is_closed: boolean;
};

function pickNearestDeadline(assignments: Assignment[]) {
  const now = Date.now();
  const candidates = assignments.filter((a) => a.type === "assignment" && a.deadline && !a.is_closed);
  if (candidates.length === 0) return null;
  const scored = candidates.map((a) => ({
    a,
    t: new Date(a.deadline!).getTime(),
  }));
  const upcoming = scored.filter((x) => x.t >= now).sort((x, y) => x.t - y.t);
  if (upcoming.length > 0) return upcoming[0].a;
  return scored.sort((x, y) => y.t - x.t)[0]?.a ?? null;
}

function yearFromCreated(s: string | null | undefined): string {
  if (!s) return "";
  try {
    return String(new Date(s).getFullYear());
  } catch {
    return "";
  }
}

export default function TeacherCoursesPage() {
  const router = useRouter();
  const { t, lang } = useLanguage();
  const { theme } = useTheme();
  const isDark = theme === "dark";
  const queryClient = useQueryClient();
  const glassStyle = getGlassCardStyle(theme);
  const textColors = getTextColors(theme);
  const inputStyle = getInputStyle(theme);
  const modalStyle = getModalStyle(theme);

  const [modalOpen, setModalOpen] = useState(false);
  const [newCourseName, setNewCourseName] = useState("");
  const [newSection, setNewSection] = useState("");
  const [learningClasses, setLearningClasses] = useState("");
  const [subject, setSubject] = useState("");
  const [auditorium, setAuditorium] = useState("");
  const [newCourseId, setNewCourseId] = useState<number | "">("");
  const [activeTab, setActiveTab] = useState<"active" | "archive">("active");
  const [renameModalOpen, setRenameModalOpen] = useState(false);
  const [renamingGroup, setRenamingGroup] = useState<Group | null>(null);
  const [renameTitle, setRenameTitle] = useState("");
  const [menuOpenGroupId, setMenuOpenGroupId] = useState<number | null>(null);
  const { user, isTeacher } = useAuthStore();

  const { data: groups = [], isLoading: groupsLoading } = useQuery({
    queryKey: ["teacher-groups"],
    queryFn: async () => {
      const { data } = await api.get<Group[]>("/teacher/groups");
      return data;
    },
  });

  const assignmentQueries = useQueries({
    queries: groups.map((g) => ({
      queryKey: ["teacher-assignments", g.id],
      queryFn: async () => {
        const { data } = await api.get<Assignment[]>(`/teacher/assignments?group_id=${g.id}`);
        return data;
      },
      enabled: groups.length > 0,
    })),
  });

  const groupIdToAssignments = useMemo(() => {
    const map = new Map<number, Assignment[]>();
    groups.forEach((g, i) => {
      map.set(g.id, assignmentQueries[i]?.data ?? []);
    });
    return map;
  }, [groups, assignmentQueries]);

  const { data: catalogCourses = [] } = useQuery({
    queryKey: ["courses-active"],
    queryFn: async () => {
      const { data } = await api.get<Array<{ id: number; title: string }>>("/courses?is_active=true");
      return data;
    },
    enabled: modalOpen,
  });

  const createGroupMutation = useMutation({
    mutationFn: async (body: { course_id: number; group_name: string }) => {
      await api.post("/teacher/groups", body);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["teacher-groups"] });
      setModalOpen(false);
      setNewCourseName("");
      setNewSection("");
      setLearningClasses("");
      setSubject("");
      setAuditorium("");
      setNewCourseId("");
    },
  });

  const handleCreate = () => {
    if (!newCourseName.trim() || !newCourseId) return;
    createGroupMutation.mutate({
      course_id: typeof newCourseId === "number" ? newCourseId : 1,
      group_name: newCourseName.trim()
    });
  };

  const deleteGroupMutation = useMutation({
    mutationFn: async (groupId: number) => {
      await api.delete(`/teacher/groups/${groupId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["teacher-groups"] });
    },
  });

  const renameGroupMutation = useMutation({
    mutationFn: async ({ id, group_name }: { id: number; group_name: string }) => {
      await api.patch(`/teacher/groups/${id}`, { group_name });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["teacher-groups"] });
      setRenameModalOpen(false);
      setRenamingGroup(null);
      setRenameTitle("");
    },
  });

  return (
    <div className="relative max-w-6xl mx-auto">
      <div className="flex items-start justify-between gap-4 mb-8">
        <div>
          <h1 className="text-2xl sm:text-3xl font-bold font-geologica" style={{ color: textColors.primary }}>
            {t("teacherCoursesTab")}
          </h1>
          <p className="text-sm mt-1" style={{ color: textColors.secondary }}>
            {t("teacherCoursesTabHint")}
          </p>
        </div>
        <button
          type="button"
          onClick={() => setModalOpen(true)}
          className="p-3 rounded-2xl text-white shrink-0 card-glow-hover transition-transform hover:scale-[1.02]"
          style={{ background: "linear-gradient(135deg, #3B82F6 0%, #8B5CF6 100%)" }}
          title={t("teacherCreateCourse")}
        >
          <Plus className="w-6 h-6" />
        </button>
      </div>

      {/* Tabs */}
      <div className="flex gap-4 mb-8 border-b" style={{ borderColor: theme === "dark" ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.08)" }}>
        <button
          type="button"
          onClick={() => setActiveTab("active")}
          className={`pb-3 px-1 text-sm font-medium border-b-2 transition-colors ${activeTab === "active"
            ? "border-blue-600 text-blue-600"
            : "border-transparent opacity-80 hover:opacity-100"
            }`}
        >
          {t("teacherActiveCourses")} ({groups.length})
        </button>
      </div>

      {/* Active Courses Tab */}
      <div className="space-y-6">
        {(groupsLoading) ? (
          <p className="text-sm" style={{ color: textColors.secondary }}>
            {t("loading")}
          </p>
        ) : groups.length === 0 ? (
          <BlurFade>
            <div className="rounded-2xl p-8 text-center" style={{ ...glassStyle }}>
              <p style={{ color: textColors.primary }}>{t("teacherNoCourses")}</p>
            </div>
          </BlurFade>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6">
            {groups.map((g, idx) => {
              const assignments = groupIdToAssignments.get(g.id) ?? [];
              const nearest = pickNearestDeadline(assignments);
              const y = yearFromCreated(g.created_at);
              const deadlineLine = nearest?.deadline
                ? t("teacherCourseCardDeadlineLine")
                  .replace("{when}", formatWeekdayLongAndTime(nearest.deadline, lang, t))
                  .replace("{title}", nearest.title)
                : null;

              return (
                <BlurFade key={g.id} delay={0.05 * idx}>
                  <div className="relative">
                    <div
                      className="w-full text-left rounded-2xl card-glow-hover transition-transform hover:scale-[1.01] flex flex-col relative"
                      style={{ ...glassStyle }}
                    >
                      <button
                        type="button"
                        onClick={() => router.push(`/app/teacher/courses/${g.id}`)}
                        className="w-full text-left flex flex-col rounded-t-2xl overflow-hidden"
                      >
                        <div
                          className="h-[160px] w-full px-4 flex flex-col justify-center shrink-0 relative overflow-hidden"
                        >
                          {/* Background Image Banner */}
                          <div
                            className="absolute inset-0 bg-cover bg-center transition-transform duration-500 group-hover:scale-110"
                            style={{ backgroundImage: `url(${getCourseBannerUrl({ title: g.course_title })})` }}
                          />
                          {/* Overlay for contrast */}
                          <div className="absolute inset-0 bg-black/40" />

                          <div className="relative z-10 font-geologica font-bold text-white text-lg leading-tight line-clamp-2">{g.group_name}</div>
                          {y ? <div className="relative z-10 text-white/90 text-sm font-semibold mt-1">{y}</div> : null}
                        </div>
                      </button>

                      {/* Three dots menu - Moved outside overflow-hidden header */}
                      <div className="absolute top-2 right-2 z-30">
                        <div className="relative">
                          <button
                            type="button"
                            onClick={(e) => {
                              e.stopPropagation();
                              setMenuOpenGroupId(menuOpenGroupId === g.id ? null : g.id);
                            }}
                            className="p-1.5 rounded-full bg-black/20 hover:bg-black/40 text-white transition-colors"
                          >
                            <MoreVertical className="w-5 h-5" />
                          </button>

                          {menuOpenGroupId === g.id && (
                            <div 
                              className="absolute right-0 mt-2 w-48 rounded-xl py-2 z-50 shadow-2xl animate-in fade-in zoom-in-95 duration-200"
                              style={{ 
                                ...modalStyle,
                                border: isDark ? "1px solid rgba(255,255,255,0.1)" : "1px solid rgba(0,0,0,0.1)" 
                              }}
                              onClick={(e) => e.stopPropagation()}
                            >
                              <button
                                type="button"
                                onClick={() => {
                                  setRenamingGroup(g);
                                  setRenameTitle(g.group_name);
                                  setRenameModalOpen(true);
                                  setMenuOpenGroupId(null);
                                }}
                                className="w-full flex items-center gap-3 px-4 py-2.5 text-left text-sm transition-colors hover:bg-black/[0.04] dark:hover:bg-white/[0.06]"
                                style={{ color: textColors.primary }}
                              >
                                <Pencil className="w-4 h-4" style={{ color: textColors.secondary }} />
                                {t("edit")}
                              </button>

                              {(user?.role === "admin" || g.teacher_id === user?.id) && (
                                <div className="px-1 pt-1 mt-1 border-t" style={{ borderColor: isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.06)" }}>
                                  <DeleteConfirmButton
                                    onDelete={() => deleteGroupMutation.mutate(g.id)}
                                    isLoading={deleteGroupMutation.isPending && deleteGroupMutation.variables === g.id}
                                    variant="ghost"
                                    size="sm"
                                    className="w-full justify-start text-red-500 hover:text-red-600 hover:bg-red-500/10 px-3 py-2.5 rounded-lg"
                                    text={t("delete")}
                                    title={`${t("teacherDeleteGroup")}: ${g.group_name}?`}
                                    description={t("confirmDelete")}
                                  />
                                </div>
                              )}
                            </div>
                          )}
                        </div>
                      </div>

                      {/* Click outside to close menu overlay */}
                      {menuOpenGroupId === g.id && (
                        <div 
                          className="fixed inset-0 z-10" 
                          onClick={() => setMenuOpenGroupId(null)}
                        />
                      )}
                      <div className="p-4 flex-1 flex flex-col gap-3 min-h-[100px]">
                        <button
                          type="button"
                          onClick={() => router.push(`/app/teacher/courses/${g.id}`)}
                          className="w-full text-left"
                        >
                          <p className="text-sm line-clamp-2 min-h-[2.5rem]" style={{ color: textColors.secondary }}>
                            {deadlineLine ?? t("teacherNoAssignments")}
                          </p>
                        </button>
                      </div>
                    </div>
                  </div>
                </BlurFade>
              );
            })}
          </div>
        )}
      </div>

      {modalOpen ? (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 animate-in fade-in duration-200">
          <button type="button" className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setModalOpen(false)} aria-label={t("close")} />
          <div
            className="relative w-full max-w-md rounded-2xl p-6 shadow-2xl animate-in zoom-in-95 duration-200"
            style={{ ...modalStyle }}
          >
            <div className="flex justify-between items-start gap-4 mb-4">
              <h2 className="text-lg font-semibold font-geologica" style={{ color: textColors.primary }}>
                {t("teacherCreateCourse")}
              </h2>
              <button
                type="button"
                onClick={() => setModalOpen(false)}
                className="p-2 rounded-xl hover:bg-black/5 dark:hover:bg-white/10"
              >
                <X className="w-5 h-5" style={{ color: textColors.secondary }} />
              </button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="block text-sm mb-1.5" style={{ color: textColors.secondary }}>
                  {t("teacherSelectCourse")}*
                </label>
                <select
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none"
                  style={{ ...inputStyle }}
                  value={newCourseId}
                  onChange={(e) => setNewCourseId(e.target.value ? Number(e.target.value) : "")}
                >
                  <option value="">{t("teacherSelectCoursePlaceholder")}</option>
                  {catalogCourses.map((c) => (
                    <option key={c.id} value={c.id}>
                      {c.title}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-sm mb-1.5" style={{ color: textColors.secondary }}>
                  {t("teacherCourseName")}*
                </label>
                <input
                  type="text"
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none"
                  style={{ ...inputStyle }}
                  placeholder={t("teacherCourseNamePlace")}
                  value={newCourseName}
                  onChange={(e) => setNewCourseName(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm mb-1.5" style={{ color: textColors.secondary }}>
                  {t("teacherCourseSection")}
                </label>
                <input
                  type="text"
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none"
                  style={{ ...inputStyle }}
                  value={newSection}
                  onChange={(e) => setNewSection(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm mb-1.5" style={{ color: textColors.secondary }}>
                  {t("teacherLearningClasses")}
                </label>
                <input
                  type="text"
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none"
                  style={{ ...inputStyle }}
                  value={learningClasses}
                  onChange={(e) => setLearningClasses(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm mb-1.5" style={{ color: textColors.secondary }}>
                  {t("teacherSubject")}
                </label>
                <input
                  type="text"
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none"
                  style={{ ...inputStyle }}
                  value={subject}
                  onChange={(e) => setSubject(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm mb-1.5" style={{ color: textColors.secondary }}>
                  {t("teacherAuditorium")}
                </label>
                <input
                  type="text"
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none"
                  style={{ ...inputStyle }}
                  value={auditorium}
                  onChange={(e) => setAuditorium(e.target.value)}
                />
              </div>
              <button
                type="button"
                disabled={createGroupMutation.isPending || !newCourseName.trim() || !newCourseId}
                onClick={handleCreate}
                className="w-full py-3 rounded-xl font-semibold text-white disabled:opacity-50 transition"
                style={{ background: "linear-gradient(135deg, #3B82F6 0%, #8B5CF6 100%)" }}
              >
                {t("teacherCreate")}
              </button>
            </div>
          </div>
        </div>
      ) : null}

      {renameModalOpen && renamingGroup && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 animate-in fade-in duration-200">
          <button type="button" className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setRenameModalOpen(false)} aria-label={t("close")} />
          <div
            className="relative w-full max-w-md rounded-2xl p-6 shadow-2xl animate-in zoom-in-95 duration-200"
            style={{ ...modalStyle }}
          >
            <div className="flex justify-between items-start gap-4 mb-4">
              <h2 className="text-lg font-semibold font-geologica" style={{ color: textColors.primary }}>
                {t("teacherRenameCourseTitle")}
              </h2>
              <button
                type="button"
                onClick={() => setRenameModalOpen(false)}
                className="p-2 rounded-xl hover:bg-black/5 dark:hover:bg-white/10"
              >
                <X className="w-5 h-5" style={{ color: textColors.secondary }} />
              </button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="block text-sm mb-1.5" style={{ color: textColors.secondary }}>
                  {t("teacherCourseName")}*
                </label>
                <input
                  type="text"
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none"
                  style={{ ...inputStyle }}
                  placeholder={t("teacherCourseNamePlace")}
                  value={renameTitle}
                  onChange={(e) => setRenameTitle(e.target.value)}
                />
              </div>
              <div className="flex gap-3">
                <button
                  type="button"
                  onClick={() => setRenameModalOpen(false)}
                  className="flex-1 py-2.5 rounded-xl text-sm font-medium transition-colors"
                  style={{
                    background: theme === "dark" ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.04)",
                    color: textColors.secondary,
                  }}
                >
                  {t("teacherCancel")}
                </button>
                <button
                  type="button"
                  disabled={renameGroupMutation.isPending || !renameTitle.trim() || renameTitle === renamingGroup.group_name}
                  onClick={() => renameGroupMutation.mutate({ id: renamingGroup.id, group_name: renameTitle.trim() })}
                  className="flex-1 py-2.5 rounded-xl text-white font-semibold text-sm disabled:opacity-50 transition-all hover:shadow-lg"
                  style={{ background: "linear-gradient(135deg, #3B82F6 0%, #8B5CF6 100%)" }}
                >
                  {renameGroupMutation.isPending ? t("teacherSaving") : t("teacherSave")}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { api } from "@/api/client";
import { useLanguage } from "@/context/LanguageContext";
import type { Lang } from "@/i18n/translations";
import { useTheme } from "@/context/ThemeContext";
import { getGlassCardStyle, getTextColors, getInputStyle } from "@/utils/themeStyles";
import { BlurFade } from "@/components/ui/blur-fade";
import { FileText, ChevronDown, ChevronRight, MoreVertical } from "lucide-react";
import { formatLocalizedDate } from "@/utils/dateUtils";


type InboxItem = {
  id: number;
  title: string;
  group_id: number;
  group_name: string;
  course_id: number;
  course_title: string;
  deadline: string | null;
  created_at: string | null;
  submitted_count: number;
  total_students: number;
  graded_count: number;
};

type Group = {
  id: number;
  group_name: string;
  course_id: number;
};

// formatDeadlineRow removed, using formatLocalizedDate directly


type TabKey = "pending" | "graded";

export default function TeacherCoursesReviewPage() {
  const router = useRouter();
  const { t, lang } = useLanguage();
  const queryClient = useQueryClient();
  const { theme } = useTheme();
  const glassStyle = getGlassCardStyle(theme);
  const textColors = getTextColors(theme);
  const inputStyle = getInputStyle(theme);

  const [tab, setTab] = useState<TabKey>("pending");
  const [groupFilter, setGroupFilter] = useState<number | "">("");
  const [openNoDue, setOpenNoDue] = useState(true);
  const [openDue, setOpenDue] = useState(true);
  const [activeMenu, setActiveMenu] = useState<number | null>(null);
  const [processingId, setProcessingId] = useState<number | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setActiveMenu(null);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const { data: groups = [] } = useQuery({
    queryKey: ["teacher-groups"],
    queryFn: async () => {
      const { data } = await api.get<Group[]>("/teacher/groups");
      return data;
    },
  });

  const status = tab === "pending" ? "pending" : "graded";

  const { data: inbox = [], isLoading, refetch } = useQuery({
    queryKey: ["teacher-submissions-inbox", status, groupFilter],
    queryFn: async () => {
      const params = new URLSearchParams();
      params.set("status", status);
      if (groupFilter !== "") params.set("group_id", String(groupFilter));
      const { data } = await api.get<InboxItem[]>(`/teacher/submissions/inbox?${params.toString()}`);
      return data;
    },
  });

  const markAsReviewed = async (assignmentId: number) => {
    try {
      setProcessingId(assignmentId);
      await api.post(`/teacher/assignments/${assignmentId}/mark-reviewed`);
      queryClient.setQueryData<InboxItem[]>(
        ["teacher-submissions-inbox", "pending", groupFilter],
        (prev = []) => prev.filter((x) => x.id !== assignmentId)
      );
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["teacher-submissions-inbox", "pending", groupFilter] }),
        queryClient.invalidateQueries({ queryKey: ["teacher-submissions-inbox", "graded", groupFilter] }),
      ]);
      await refetch();
    } catch (error) {
      console.error("Failed to mark as reviewed:", error);
    } finally {
      setProcessingId(null);
    }
  };

  const markAsUnreviewed = async (assignmentId: number) => {
    try {
      setProcessingId(assignmentId);
      await api.post(`/teacher/assignments/${assignmentId}/unmark-reviewed`);
      queryClient.setQueryData<InboxItem[]>(
        ["teacher-submissions-inbox", "graded", groupFilter],
        (prev = []) => prev.filter((x) => x.id !== assignmentId)
      );
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["teacher-submissions-inbox", "pending", groupFilter] }),
        queryClient.invalidateQueries({ queryKey: ["teacher-submissions-inbox", "graded", groupFilter] }),
      ]);
      await refetch();
    } catch (error) {
      console.error("Failed to mark as unreviewed:", error);
    } finally {
      setProcessingId(null);
    }
  };

  const noDeadlineItems = inbox.filter((x) => x.deadline === null);
  const withDeadlineItems = inbox.filter((x) => x.deadline !== null);

  const groupItemsByDate = (items: InboxItem[]) => {
    const groups: { [key: string]: InboxItem[] } = {};
    items.forEach((item) => {
      if (!item.deadline) return;
      const dateKey = formatLocalizedDate(item.deadline, lang, t);

      const key = `${t("teacherDueDateRowLabel")}: ${dateKey}`;
      if (!groups[key]) groups[key] = [];
      groups[key].push(item);
    });
    return groups;
  };

  const groupedWithDeadline = groupItemsByDate(withDeadlineItems);

  const renderSection = (title: string, items: InboxItem[], open: boolean, setOpen: (v: boolean) => void) => (
    <div className="rounded-2xl mb-4" style={{ ...glassStyle }}>
      <button
        type="button"
        onClick={() => setOpen(!open)}
        className="w-full flex items-center justify-between px-4 py-3 text-left hover:bg-black/[0.03] dark:hover:bg-white/[0.04] transition-colors rounded-t-2xl"
      >
        <div className="flex items-center gap-2">
          <span className="font-semibold font-geologica" style={{ color: textColors.primary }}>
            {title}
          </span>
          <span
            className="text-xs font-medium px-2 py-0.5 rounded-full"
            style={{
              background: theme === "dark" ? "rgba(59,130,246,0.2)" : "rgba(59,130,246,0.12)",
              color: theme === "dark" ? "#93C5FD" : "#1D4ED8",
            }}
          >
            {items.length}
          </span>
        </div>
        {open ? <ChevronDown className="w-5 h-5 opacity-70" /> : <ChevronRight className="w-5 h-5 opacity-70" />}
      </button>
      {open ? (
        <ul className="divide-y divide-black/5 dark:divide-white/10">
          {items.map((item) => (
            <li
              key={item.id}
              className={`relative group/row transition-all duration-300 ${
                processingId === item.id ? "opacity-50 pointer-events-none scale-[0.98]" : "opacity-100"
              }`}
            >
              <div
                role="button"
                tabIndex={0}
                onClick={() => router.push(`/app/teacher/courses/${item.group_id}/assignment/${item.id}`)}
                onKeyDown={(e) => {
                  if (e.key === "Enter" || e.key === " ") {
                    e.preventDefault();
                    router.push(`/app/teacher/courses/${item.group_id}/assignment/${item.id}`);
                  }
                }}
                className="flex flex-col sm:flex-row sm:items-center gap-3 px-4 py-3 cursor-pointer hover:bg-black/[0.03] dark:hover:bg-white/[0.04] transition-colors"
              >
                {(() => {
                  const rawSubmitted = Math.max(item.submitted_count || 0, 0);
                  const rawAssigned = Math.max(item.total_students || 0, 0);
                  const rawGraded = Math.max(item.graded_count || 0, 0);

                  // Show actionable counters:
                  // submitted = turned in but not yet graded
                  // assigned = not yet turned in
                  const submittedToReview = Math.max(rawSubmitted - rawGraded, 0);
                  const assignedNotSubmitted = Math.max(rawAssigned - rawSubmitted, 0);
                  const gradedDone = rawGraded;

                  return (
                    <>
                <div className="flex items-start gap-3 min-w-0 flex-1">
                  <FileText className="w-5 h-5 shrink-0 mt-0.5" style={{ color: textColors.secondary }} />
                  <div className="min-w-0">
                    <div className="font-semibold line-clamp-2" style={{ color: textColors.primary }}>
                      {item.title}
                    </div>
                    <div className="text-sm mt-0.5" style={{ color: textColors.secondary }}>
                      {item.group_name}
                      {item.deadline ? (
                        <>
                          {" "}
                          • {t("teacherDueDateRowLabel")}: {formatLocalizedDate(item.deadline, lang, t, { includeTime: true })}
                        </>
                      ) : null}
                    </div>
                  </div>
                </div>
                <div className="flex flex-col sm:flex-row sm:items-center gap-4 sm:gap-6 text-sm sm:justify-end w-full sm:w-auto">
                  <div className="grid grid-cols-3 gap-1 sm:flex sm:items-center sm:gap-6 w-full sm:w-auto flex-1 sm:flex-none min-w-0">
                    <div className="text-center min-w-0">
                      <div className="font-bold text-base sm:text-sm" style={{ color: textColors.primary }}>
                        {submittedToReview}
                      </div>
                      <div className="text-[9px] sm:text-[10px] uppercase tracking-wider opacity-70 break-words leading-tight" style={{ color: textColors.secondary }}>{t("submitted")}</div>
                    </div>
                    <div className="text-center min-w-0">
                      <div className="font-bold text-base sm:text-sm" style={{ color: textColors.primary }}>
                        {assignedNotSubmitted}
                      </div>
                      <div className="text-[9px] sm:text-[10px] uppercase tracking-wider opacity-70 break-words leading-tight" style={{ color: textColors.secondary }}>{t("assigned")}</div>
                    </div>
                    <div className="text-center min-w-0">
                      <div className="font-bold text-base sm:text-sm" style={{ color: textColors.primary }}>
                        {gradedDone}
                      </div>
                      <div className="text-[9px] sm:text-[10px] uppercase tracking-wider opacity-70 break-words leading-tight" style={{ color: textColors.secondary }}>{t("graded")}</div>
                    </div>
                  </div>
                  <div className="relative flex justify-end sm:block">
                    <button
                      type="button"
                      className="p-2 rounded-xl hover:bg-black/5 dark:hover:bg-white/10"
                      onClick={(e) => {
                        e.stopPropagation();
                        setActiveMenu(activeMenu === item.id ? null : item.id);
                      }}
                      aria-label={t("menu")}
                    >
                      <MoreVertical className="w-5 h-5" style={{ color: textColors.secondary }} />
                    </button>
                    {activeMenu === item.id && (
                      <div
                        ref={menuRef}
                        className="absolute right-0 top-1/2 -translate-y-1/2 mt-8 z-50 min-w-[200px] rounded-xl shadow-xl border border-black/5 dark:border-white/10 overflow-hidden"
                        style={{ ...glassStyle, background: theme === "dark" ? "#1E293B" : "#FFFFFF" }}
                      >
                        {tab === "pending" ? (
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              if (processingId === item.id) return;
                              markAsReviewed(item.id);
                              setActiveMenu(null);
                            }}
                            disabled={processingId === item.id}
                            className={`w-full text-left px-4 py-2.5 text-sm transition-colors ${
                              processingId === item.id ? "opacity-50 cursor-not-allowed" : "hover:bg-black/5 dark:hover:bg-white/10"
                            }`}
                            style={{ color: textColors.primary }}
                          >
                            {t("markAsReviewed")}
                          </button>
                        ) : (
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              if (processingId === item.id) return;
                              markAsUnreviewed(item.id);
                              setActiveMenu(null);
                            }}
                            disabled={processingId === item.id}
                            className={`w-full text-left px-4 py-2.5 text-sm transition-colors ${
                              processingId === item.id ? "opacity-50 cursor-not-allowed" : "hover:bg-black/5 dark:hover:bg-white/10"
                            }`}
                            style={{ color: textColors.primary }}
                          >
                            {t("markAsUnreviewed")}
                          </button>
                        )}
                      </div>
                    )}
                  </div>
                </div>
                    </>
                  );
                })()}
              </div>
            </li>
          ))}
        </ul>
      ) : null}
    </div>
  );

  const empty = !isLoading && inbox.length === 0;

  return (
    <div className="max-w-4xl mx-auto">
      <BlurFade>
        <h1 className="text-2xl sm:text-3xl font-bold font-geologica mb-6" style={{ color: textColors.primary }}>
          {tab === "pending" ? t("unreviewedAssignments") : t("reviewedAssignments")}
        </h1>
      </BlurFade>

      <div className="flex flex-col sm:flex-row sm:items-center gap-4 mb-8">
        <div
          className="flex w-full sm:w-auto rounded-xl p-1.5 gap-1.5"
          style={{
            ...glassStyle,
            background: theme === "dark" ? "rgba(26, 34, 56, 0.5)" : "rgba(255,255,255,0.9)",
          }}
        >
          <button
            type="button"
            onClick={() => setTab("pending")}
            className={`flex-1 sm:px-6 py-2.5 rounded-lg text-sm font-semibold transition-all duration-300 ${
              tab === "pending" ? "text-white shadow-lg scale-[1.02]" : "hover:bg-black/5 dark:hover:bg-white/5"
            }`}
            style={
              tab === "pending"
                ? { background: "linear-gradient(135deg, #3B82F6 0%, #8B5CF6 100%)" }
                : { color: textColors.secondary }
            }
          >
            {t("unreviewedAssignments")}
          </button>
          <button
            type="button"
            onClick={() => setTab("graded")}
            className={`flex-1 sm:px-6 py-2.5 rounded-lg text-sm font-semibold transition-all duration-300 ${
              tab === "graded" ? "text-white shadow-lg scale-[1.02]" : "hover:bg-black/5 dark:hover:bg-white/5"
            }`}
            style={
              tab === "graded"
                ? { background: "linear-gradient(135deg, #3B82F6 0%, #8B5CF6 100%)" }
                : { color: textColors.secondary }
            }
          >
            {t("reviewedAssignments")}
          </button>
        </div>

        <div className="w-full sm:w-auto sm:ml-auto">
          <select
            className="w-full sm:min-w-[220px] rounded-xl px-4 py-3 text-sm outline-none transition-all duration-300 focus:ring-2 focus:ring-blue-500/50"
            style={{ ...inputStyle }}
            value={groupFilter === "" ? "" : String(groupFilter)}
            onChange={(e) => setGroupFilter(e.target.value ? Number(e.target.value) : "")}
          >
            <option value="">{t("allCourses")}</option>
            {groups.map((g) => (
              <option key={g.id} value={g.id}>
                {g.group_name}
              </option>
            ))}
          </select>
        </div>
      </div>

      {isLoading ? (
        <p className="text-sm" style={{ color: textColors.secondary }}>
          {t("loading")}
        </p>
      ) : empty ? (
        <BlurFade>
          <div className="rounded-2xl p-6 sm:p-10 text-center flex flex-col items-center gap-4" style={{ ...glassStyle }}>
            <svg
              width="120"
              height="100"
              viewBox="0 0 120 100"
              className="opacity-40"
              style={{ color: textColors.secondary }}
              aria-hidden
            >
              <rect x="10" y="20" width="100" height="70" rx="8" fill="none" stroke="currentColor" strokeWidth="2" />
              <path d="M35 40h50M35 55h35M35 70h45" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
            </svg>
            <div>
              <p className="font-semibold text-lg font-geologica" style={{ color: textColors.primary }}>
                {tab === "pending" ? t("noUnreviewedWork") : t("noReviewedWork")}
              </p>
              <p className="text-sm mt-2 max-w-md mx-auto" style={{ color: textColors.secondary }}>
                {tab === "pending" ? t("noUnreviewedWorkHint") : t("noReviewedWorkHint")}
              </p>
            </div>
          </div>
        </BlurFade>
      ) : (
        <>
          {noDeadlineItems.length > 0 && renderSection(t("noDueDate"), noDeadlineItems, openNoDue, setOpenNoDue)}
          {tab === "pending" ? (
            withDeadlineItems.length > 0 &&
            renderSection(t("currentAssignments"), withDeadlineItems, openDue, setOpenDue)
          ) : (
            Object.entries(groupedWithDeadline).map(([dateLabel, items]) => (
              <div key={dateLabel}>
                {renderSection(dateLabel, items, true, () => {})}
              </div>
            ))
          )}
        </>
      )}
    </div>
  );
}

"use client";

