"use client";

import { useEffect, useState, useCallback } from "react";
import { useLanguage } from "@/context/LanguageContext";
import { formatLocalizedDate } from "@/utils/dateUtils";
import { useTheme } from "@/context/ThemeContext";
import { getLocalizedCourseTitle } from "@/lib/courseUtils";
import { api as apiClient } from "@/api/client";
import { Star, Check, X, MessageCircle, Sparkles, Trash2, Filter } from "lucide-react";
import { AnimatedNumber } from "./AnimatedNumber";
import { StaggeredAnimation } from "./StaggeredAnimation";
import { GlareEffect } from "./GlareEffect";
import { DeleteConfirmButton } from "@/components/ui/DeleteConfirmButton";

interface Review {
    id: number;
    user_id: number;
    user_name: string;
    user_email: string;
    course_id: number;
    course_title: string;
    rating: number;
    text: string | null;
    is_approved: boolean;
    is_featured: boolean;
    admin_reply: string | null;
    created_at: string | null;
}

interface ReviewStats {
    total: number;
    pending: number;
    approved: number;
    featured: number;
    avg_rating: number;
}

export default function ReviewManagement() {
    const { t, lang } = useLanguage();
    const { theme } = useTheme();
    const isDark = theme === "dark";
    const [reviews, setReviews] = useState<Review[]>([]);
    const [stats, setStats] = useState<ReviewStats | null>(null);
    const [filter, setFilter] = useState<string>("all");
    const [loading, setLoading] = useState(true);
    const [replyId, setReplyId] = useState<number | null>(null);
    const [replyText, setReplyText] = useState("");

    const fetchReviews = useCallback(async () => {
        try {
            const params: Record<string, string> = {};
            if (filter === "pending") params.status = "pending";
            if (filter === "approved") params.status = "approved";
            const { data } = await apiClient.get("/admin/reviews", { params });
            setReviews(data);
        } catch (e) {
            console.error(e);
        }
    }, [filter]);

    const fetchStats = async () => {
        try {
            const { data } = await apiClient.get("/reviews/stats");
            setStats(data);
        } catch (e) {
            console.error(e);
        }
    };

    useEffect(() => {
        setLoading(true);
        Promise.all([fetchReviews(), fetchStats()]).finally(() => setLoading(false));
    }, [fetchReviews]);

    const handleApprove = async (id: number) => {
        await apiClient.put(`/admin/reviews/${id}/approve`);
        fetchReviews();
        fetchStats();
    };

    const handleReject = async (id: number) => {
        await apiClient.put(`/admin/reviews/${id}/reject`);
        fetchReviews();
        fetchStats();
    };

    const handleFeature = async (id: number) => {
        await apiClient.put(`/admin/reviews/${id}/feature`);
        fetchReviews();
        fetchStats();
    };

    const handleDelete = async (id: number) => {
        await apiClient.delete(`/admin/reviews/${id}`);
        fetchReviews();
        fetchStats();
    };

    const handleReply = async (id: number) => {
        if (!replyText.trim()) return;
        await apiClient.put(`/admin/reviews/${id}/reply`, { admin_reply: replyText });
        setReplyId(null);
        setReplyText("");
        fetchReviews();
    };

    const renderStars = (rating: number) => (
        <div className="flex gap-0.5">
            {[1, 2, 3, 4, 5].map((s) => (
                <Star
                    key={s}
                    className={`w-4 h-4 ${s <= rating ? "fill-yellow-400 text-yellow-400" : "text-gray-300 dark:text-gray-600"}`}
                />
            ))}
        </div>
    );

    if (loading) {
        return (
            <div className="flex items-center justify-center py-20">
                <div className="animate-spin w-8 h-8 border-4 border-[var(--qit-primary)] border-t-transparent rounded-full" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Stats Cards */}
            {stats && (
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                    {[
                        { label: t("reviewStatsTotal"), value: stats.total, color: "from-blue-500 to-blue-600" },
                        { label: t("reviewStatsPending"), value: stats.pending, color: "from-amber-500 to-orange-500" },
                        { label: t("reviewStatsApproved"), value: stats.approved, color: "from-emerald-500 to-green-500" },
                        { label: t("reviewStatsFeatured"), value: stats.featured, color: "from-purple-500 to-pink-500" },
                        { label: t("reviewStatsAvgRating"), value: stats.avg_rating, color: "from-yellow-500 to-amber-500" },
                    ].map((s, i) => (
                        <StaggeredAnimation key={i} delay={i * 100}>
                            <GlareEffect>
                                <div
                                    className="relative overflow-hidden rounded-2xl border border-gray-200 dark:border-white/10 backdrop-blur-xl p-6 transition-all duration-300 bg-white/80 dark:bg-[rgba(30,41,59,0.6)] shadow-lg dark:shadow-xl"
                                    style={{ 
                                        boxShadow: isDark ? `0 8px 32px rgba(0, 0, 0, 0.3), 0 0 0 1px rgba(255, 255, 255, 0.05)` : `0 4px 16px rgba(0, 0, 0, 0.1), 0 0 0 1px rgba(0, 0, 0, 0.05)`
                                    }}
                                >
                                    <div className="relative">
                                        <p className="text-sm text-gray-600 dark:text-gray-400 mb-2">{s.label}</p>
                                        <p className="text-4xl font-bold text-gray-900 dark:text-white tracking-tight">
                                            <AnimatedNumber value={typeof s.value === 'number' ? s.value : parseFloat(String(s.value))} duration={1.5} decimals={typeof s.value === 'number' && s.value % 1 !== 0 ? 1 : 0} />
                                        </p>
                                    </div>
                                </div>
                            </GlareEffect>
                        </StaggeredAnimation>
                    ))}
                </div>
            )}

            {/* Filter Tabs */}
            <div className="flex gap-3 flex-wrap">
                {[
                    { key: "all", label: t("reviewFilterAll") },
                    { key: "pending", label: t("reviewFilterPending") },
                    { key: "approved", label: t("reviewFilterApproved") },
                ].map((f) => (
                    <button
                        key={f.key}
                        onClick={() => setFilter(f.key)}
                        className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 ${
                            filter === f.key
                                ? "bg-blue-600 text-white shadow-lg"
                                : "text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white border border-gray-300 dark:border-white/20 hover:bg-gray-100 dark:hover:bg-white/10"
                        }`}
                        style={filter === f.key ? { boxShadow: "0 4px 14px rgba(37, 99, 235, 0.4)" } : { background: isDark ? "rgba(255, 255, 255, 0.05)" : "rgba(255, 255, 255, 0.8)" }}
                    >
                        <Filter className="w-4 h-4" /> {f.label}
                    </button>
                ))}
            </div>

            {/* Reviews List */}
            {reviews.length === 0 ? (
                <div className="rounded-2xl border border-gray-200 dark:border-white/10 backdrop-blur-xl p-16 text-center bg-white/80 dark:bg-[rgba(30,41,59,0.6)] shadow-lg dark:shadow-xl" style={{ boxShadow: isDark ? "0 8px 32px rgba(0, 0, 0, 0.3), 0 0 0 1px rgba(255, 255, 255, 0.05)" : "0 4px 16px rgba(0, 0, 0, 0.1), 0 0 0 1px rgba(0, 0, 0, 0.05)" }}>
                    <div className="w-24 h-24 mx-auto mb-6 rounded-full flex items-center justify-center bg-purple-100 dark:bg-[rgba(139,92,246,0.2)]">
                        <Star className="w-12 h-12 text-purple-600 dark:text-purple-400" />
                    </div>
                    <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">{t("reviewNoReviews")}</h3>
                    <p className="text-gray-600 dark:text-gray-400 mb-6">{t("reviewNoReviewsSubtitle")}</p>
                </div>
            ) : (
                <div className="space-y-4">
                    {reviews.map((r, index) => (
                        <StaggeredAnimation key={r.id} delay={index * 50}>
                            <GlareEffect>
                                <div
                                    className={`relative overflow-hidden rounded-2xl border backdrop-blur-xl transition-all duration-300 bg-white/80 dark:bg-[rgba(30,41,59,0.6)] shadow-lg dark:shadow-xl ${
                                        r.is_featured
                                            ? "border-yellow-500/50 dark:border-yellow-500/50"
                                            : r.is_approved
                                                ? "border-emerald-500/30 dark:border-emerald-500/30"
                                                : "border-amber-500/30 dark:border-amber-500/30"
                                    } hover:border-gray-300 dark:hover:border-white/30`}
                                    style={{ 
                                        boxShadow: r.is_featured 
                                            ? (isDark ? "0 8px 32px rgba(251, 191, 36, 0.3), 0 0 0 1px rgba(255, 255, 255, 0.05)" : "0 4px 16px rgba(251, 191, 36, 0.2), 0 0 0 1px rgba(0, 0, 0, 0.05)")
                                            : (isDark ? "0 8px 32px rgba(0, 0, 0, 0.3), 0 0 0 1px rgba(255, 255, 255, 0.05)" : "0 4px 16px rgba(0, 0, 0, 0.1), 0 0 0 1px rgba(0, 0, 0, 0.05)")
                                    }}
                                >
                            {r.is_featured && (
                                <div className="absolute top-0 right-0 bg-gradient-to-bl from-yellow-400 to-amber-500 text-white text-xs px-4 py-1.5 rounded-bl-xl font-medium shadow-lg">
                                    ⭐ {t("reviewFeatured")}
                                </div>
                            )}
                            <div className="p-6">
                                <div className="flex items-start justify-between gap-4">
                                    <div className="flex-1">
                                        <div className="flex items-center gap-3 mb-3">
                                            <div className="w-10 h-10 rounded-full flex items-center justify-center text-white text-sm font-bold shrink-0" style={{ background: "linear-gradient(135deg, #14b8a6 0%, #3b82f6 100%)" }}>
                                                {r.user_name?.[0]?.toUpperCase() || "?"}
                                            </div>
                                            <div>
                                                <p className="font-medium text-sm text-gray-900 dark:text-white">{r.user_name}</p>
                                                <p className="text-xs text-gray-600 dark:text-gray-400">{r.user_email}</p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-2 mb-3">
                                            {renderStars(r.rating)}
                                            <span className="text-xs text-gray-600 dark:text-gray-400 ml-1">
                                                {getLocalizedCourseTitle({ title: r.course_title } as any, t)}
                                            </span>
                                        </div>
                                        {r.text && (
                                            <p className="text-sm text-gray-700 dark:text-gray-300 leading-relaxed">
                                                {r.text}
                                            </p>
                                        )}
                                        {r.admin_reply && (
                                            <div className="mt-3 pl-4 border-l-2 border-blue-500">
                                                <p className="text-xs text-gray-600 dark:text-gray-400 mb-1">{t("reviewAdminReply")}</p>
                                                <p className="text-sm text-gray-700 dark:text-gray-300">{r.admin_reply}</p>
                                            </div>
                                        )}
                                        <p className="text-xs text-gray-600 dark:text-gray-400 mt-3">
                                            {r.created_at ? formatLocalizedDate(r.created_at, lang as any, t) : ""}
                                        </p>
                                    </div>
                                    <div className="flex flex-col gap-2">
                                        {!r.is_approved && (
                                            <button
                                                onClick={() => handleApprove(r.id)}
                                                className="p-2.5 rounded-xl bg-emerald-100 dark:bg-emerald-600/20 text-emerald-700 dark:text-emerald-400 hover:bg-emerald-200 dark:hover:bg-emerald-600/30 border border-emerald-300 dark:border-emerald-500/30 transition-colors"
                                                title={t("reviewApprove")}
                                            >
                                                <Check className="w-4 h-4" />
                                            </button>
                                        )}
                                        {r.is_approved && (
                                            <button
                                                onClick={() => handleReject(r.id)}
                                                className="p-2.5 rounded-xl bg-amber-100 dark:bg-amber-600/20 text-amber-700 dark:text-amber-400 hover:bg-amber-200 dark:hover:bg-amber-600/30 border border-amber-300 dark:border-amber-500/30 transition-colors"
                                                title={t("reviewReject")}
                                            >
                                                <X className="w-4 h-4" />
                                            </button>
                                        )}
                                        <button
                                            onClick={() => handleFeature(r.id)}
                                            className={`p-2.5 rounded-xl transition-colors border ${
                                                r.is_featured
                                                    ? "bg-yellow-100 dark:bg-yellow-600/20 text-yellow-700 dark:text-yellow-400 border-yellow-300 dark:border-yellow-500/30"
                                                    : "bg-gray-100 dark:bg-white/5 text-gray-600 dark:text-gray-400 hover:bg-yellow-100 dark:hover:bg-yellow-600/20 border-gray-300 dark:border-white/10 hover:border-yellow-500/30"
                                            }`}
                                            title={t("reviewFeature")}
                                        >
                                            <Sparkles className="w-4 h-4" />
                                        </button>
                                        <button
                                            onClick={() => { setReplyId(r.id === replyId ? null : r.id); setReplyText(r.admin_reply || ""); }}
                                            className="p-2.5 rounded-xl bg-blue-100 dark:bg-blue-600/20 text-blue-700 dark:text-blue-400 hover:bg-blue-200 dark:hover:bg-blue-600/30 border border-blue-300 dark:border-blue-500/30 transition-colors"
                                            title={t("reviewReply")}
                                        >
                                            <MessageCircle className="w-4 h-4" />
                                        </button>
                                        <DeleteConfirmButton
                                            onDelete={() => handleDelete(r.id)}
                                            hideText={true}
                                            title={t("reviewDeleteConfirm")}
                                            description={t("confirmDelete")}
                                            variant="ghost"
                                            size="sm"
                                            className="p-0 border-0 shadow-none bg-red-100 dark:bg-red-600/20 rounded-xl"
                                        />
                                    </div>
                                </div>
                                {replyId === r.id && (
                                    <div className="mt-4 flex gap-2">
                                        <input
                                            value={replyText}
                                            onChange={(e) => setReplyText(e.target.value)}
                                            placeholder={t("reviewReplyPlaceholder")}
                                            className="flex-1 px-4 py-2 rounded-xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 text-sm focus:outline-none focus:ring-2 focus:ring-[var(--qit-primary)]"
                                        />
                                        <button
                                            onClick={() => handleReply(r.id)}
                                            className="px-4 py-2 rounded-xl bg-[var(--qit-primary)] text-white text-sm font-medium hover:opacity-90 transition-opacity"
                                        >
                                            {t("reviewSendReply")}
                                        </button>
                                    </div>
                                )}
                            </div>
                                </div>
                            </GlareEffect>
                        </StaggeredAnimation>
                    ))}
                </div>
            )}
        </div>
    );
}

"use client";

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useState } from "react";
import Image from "next/image";
import { api } from "@/api/client";
import { getLocalizedProductTitle } from "@/lib/shopUtils";
import { useLanguage } from "@/context/LanguageContext";
import { useTheme } from "@/context/ThemeContext";
import { getGlassCardStyle, getTextColors, getModalStyle, getInputStyle } from "@/utils/themeStyles";
import { Package, Truck, CheckCircle, Clock, Search, Filter, UserPlus, X } from "lucide-react";
import { CourierListView } from "./CourierListView";
import { cn } from "@/lib/utils";
import { formatLocalizedDate } from "@/utils/dateUtils";


type Purchase = {
  id: number;
  user_id: number;
  user_name: string;
  user_email: string;
  shop_item_id: number;
  item_title: string;
  item_price_coins: number;
  purchased_at: string | null;
  delivery_status: string;
  estimated_delivery_date: string | null;
  delivered_at: string | null;
  courier_id?: number | null;
  courier_name?: string | null;
};

type Courier = {
  id: number;
  full_name: string;
  email: string;
  phone?: string | null;
  deliveries_count: number;
  pending_deliveries: number;
  delivered_count: number;
};

type PurchaseStats = {
  total_purchases: number;
  pending: number;
  processing: number;
  shipped: number;
  delivered: number;
};

const DELIVERY_STATUSES = [
  { value: "pending", color: "#64748B" },
  { value: "processing", color: "#F59E0B" },
  { value: "shipped", color: "#3B82F6" },
  { value: "delivered", color: "#10B981" },
  { value: "cancelled", color: "#EF4444" },
];

export function ShopPurchaseManagement() {
  const { t, lang } = useLanguage();
  const { theme } = useTheme();
  const queryClient = useQueryClient();
  const textColors = getTextColors(theme);
  const cardStyle = getGlassCardStyle(theme);
  const modalStyle = getModalStyle(theme);
  const isDark = theme === "dark";

  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("");
  const [userIdFilter, setUserIdFilter] = useState<number | null>(null);
  const [courierFilter, setCourierFilter] = useState<number | null>(null);
  const [editingPurchase, setEditingPurchase] = useState<Purchase | null>(null);
  const [newStatus, setNewStatus] = useState<string>("");
  const [assigningCourier, setAssigningCourier] = useState<Purchase | null>(null);
  const [selectedCourierId, setSelectedCourierId] = useState<number | null>(null);
  const [activeTab, setActiveTab] = useState<"purchases" | "couriers">("purchases");
  const [initialCourierId, setInitialCourierId] = useState<number | null>(null);

  const { data: purchases = [] } = useQuery({
    queryKey: ["admin-shop-purchases", statusFilter, userIdFilter, courierFilter],
    queryFn: async () => {
      const params = new URLSearchParams();
      if (statusFilter) params.append("delivery_status", statusFilter);
      if (userIdFilter) params.append("user_id", userIdFilter.toString());
      const { data } = await api.get<Purchase[]>(`/admin/shop/purchases?${params.toString()}`);
      return data;
    },
  });

  const { data: couriers = [] } = useQuery({
    queryKey: ["admin-shop-couriers"],
    queryFn: async () => {
      const { data } = await api.get<Courier[]>("/admin/shop/purchases/couriers");
      return data;
    },
  });

  const { data: availableCouriers = [] } = useQuery({
    queryKey: ["admin-shop-available-couriers"],
    queryFn: async () => {
      const { data } = await api.get<Courier[]>("/admin/shop/purchases/available-couriers");
      return data;
    },
  });

  const assignCourierMutation = useMutation({
    mutationFn: async ({ purchaseId, courierId }: { purchaseId: number; courierId: number }) => {
      await api.patch(`/admin/shop/purchases/${purchaseId}/assign-courier`, {
        courier_id: courierId,
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-shop-purchases"] });
      queryClient.invalidateQueries({ queryKey: ["admin-shop-couriers"] });
      queryClient.invalidateQueries({ queryKey: ["admin-shop-available-couriers"] });
      setAssigningCourier(null);
      setSelectedCourierId(null);
    },
  });

  const { data: stats } = useQuery({
    queryKey: ["admin-shop-stats"],
    queryFn: async () => {
      const { data } = await api.get<PurchaseStats>("/admin/shop/purchases/stats");
      return data;
    },
  });

  const updateStatusMutation = useMutation({
    mutationFn: async ({ purchaseId, status }: { purchaseId: number; status: string }) => {
      await api.patch(`/admin/shop/purchases/${purchaseId}/delivery-status`, {
        delivery_status: status,
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-shop-purchases"] });
      queryClient.invalidateQueries({ queryKey: ["admin-shop-stats"] });
      setEditingPurchase(null);
      setNewStatus("");
    },
  });

  const filteredPurchases = purchases.filter((p) => {
    if (search) {
      const searchLower = search.toLowerCase();
      if (
        !p.user_name.toLowerCase().includes(searchLower) &&
        !p.user_email.toLowerCase().includes(searchLower) &&
        !p.item_title.toLowerCase().includes(searchLower) &&
        !(p.courier_name && p.courier_name.toLowerCase().includes(searchLower))
      ) {
        return false;
      }
    }
    if (courierFilter && p.courier_id !== courierFilter) {
      return false;
    }
    return true;
  });

  const getStatusColor = (status: string) => {
    return DELIVERY_STATUSES.find((s) => s.value === status)?.color || "#64748B";
  };

  const getStatusLabel = (status: string) => {
    const statusMap: Record<string, string> = {
      pending: t("adminShopStatusPending"),
      processing: t("adminShopStatusProcessing"),
      shipped: t("adminShopStatusShipped"),
      delivered: t("adminShopStatusDelivered"),
      cancelled: t("adminShopStatusCancelled"),
    };
    return statusMap[status] || status;
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "delivered":
        return <CheckCircle className="w-4 h-4" />;
      case "shipped":
        return <Truck className="w-4 h-4" />;
      case "processing":
        return <Package className="w-4 h-4" />;
      case "cancelled":
        return <X className="w-4 h-4" />;
      default:
        return <Clock className="w-4 h-4" />;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
        <h1 className="text-3xl font-bold flex items-center gap-3" style={{ color: textColors.primary }}>
          <Package className="w-8 h-8" style={{ color: "#FF4181" }} />
          {t("adminShopPurchases")}
        </h1>
      </div>

      {/* Вкладки */}
      <div className="border-b overflow-x-auto" style={{ borderColor: isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)" }}>
        <div className="flex gap-2 min-w-max pr-1">
        <button
          onClick={() => setActiveTab("purchases")}
          className={cn(
            "px-4 sm:px-6 py-3 font-medium transition-all relative whitespace-nowrap text-sm sm:text-base",
            activeTab === "purchases" && "text-white"
          )}
          style={
            activeTab === "purchases"
              ? {
                  background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)",
                }
              : { color: textColors.secondary }
          }
        >
          {t("adminShopPurchasesList")}
          {activeTab === "purchases" && (
            <div
              className="absolute bottom-0 left-0 right-0 h-0.5"
              style={{ background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)" }}
            />
          )}
        </button>
        <button
          onClick={() => setActiveTab("couriers")}
          className={cn(
            "px-4 sm:px-6 py-3 font-medium transition-all relative whitespace-nowrap text-sm sm:text-base",
            activeTab === "couriers" && "text-white"
          )}
          style={
            activeTab === "couriers"
              ? {
                  background: "linear-gradient(135deg, #06B6D4 0%, #3B82F6 100%)",
                }
              : { color: textColors.secondary }
          }
        >
          {t("adminShopCouriers")}
          {activeTab === "couriers" && (
            <div
              className="absolute bottom-0 left-0 right-0 h-0.5"
              style={{ background: "linear-gradient(135deg, #06B6D4 0%, #3B82F6 100%)" }}
            />
          )}
        </button>
        </div>
      </div>

      {activeTab === "couriers" ? (
        <CourierListView initialCourierId={initialCourierId} />
      ) : (
        <div>

      {stats && (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-5">
          <div className="rounded-xl p-4" style={cardStyle}>
            <div className="text-sm mb-1" style={{ color: textColors.secondary }}>
              {t("adminShopTotalPurchases")}
            </div>
            <div className="text-2xl font-bold" style={{ color: textColors.primary }}>
              {stats.total_purchases}
            </div>
          </div>
          <div className="rounded-xl p-4" style={cardStyle}>
            <div className="text-sm mb-1" style={{ color: textColors.secondary }}>
              {t("adminShopAwaiting")}
            </div>
            <div className="text-2xl font-bold" style={{ color: "#64748B" }}>
              {stats.pending}
            </div>
          </div>
          <div className="rounded-xl p-4" style={cardStyle}>
            <div className="text-sm mb-1" style={{ color: textColors.secondary }}>
              {t("adminShopProcessing")}
            </div>
            <div className="text-2xl font-bold" style={{ color: "#F59E0B" }}>
              {stats.processing}
            </div>
          </div>
          <div className="rounded-xl p-4" style={cardStyle}>
            <div className="text-sm mb-1" style={{ color: textColors.secondary }}>
              {t("adminShopShipped")}
            </div>
            <div className="text-2xl font-bold" style={{ color: "#3B82F6" }}>
              {stats.shipped}
            </div>
          </div>
          <div className="rounded-xl p-4" style={cardStyle}>
            <div className="text-sm mb-1" style={{ color: textColors.secondary }}>
              {t("adminShopDelivered")}
            </div>
            <div className="text-2xl font-bold" style={{ color: "#10B981" }}>
              {stats.delivered}
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col sm:flex-row gap-4">
        <div className="flex-1 relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: textColors.secondary }} />
          <input
            type="text"
            placeholder={t("adminShopSearchPlaceholder")}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2 rounded-lg"
            style={getInputStyle(theme)}
          />
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-2 w-full sm:w-auto">
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="w-full sm:w-auto px-4 py-2 rounded-lg"
            style={getInputStyle(theme)}
          >
            <option value="">{t("adminShopAllStatuses")}</option>
            {DELIVERY_STATUSES.map((status) => (
              <option key={status.value} value={status.value}>
                {getStatusLabel(status.value)}
              </option>
            ))}
          </select>
          <select
            value={courierFilter || ""}
            onChange={(e) => setCourierFilter(e.target.value ? parseInt(e.target.value) : null)}
            className="w-full sm:w-auto px-4 py-2 rounded-lg"
            style={getInputStyle(theme)}
          >
            <option value="">{t("adminShopAllCouriers")}</option>
            {couriers.map((courier) => (
              <option key={courier.id} value={courier.id}>
                {courier.full_name}
              </option>
            ))}
          </select>
          <input
            type="number"
            placeholder={t("adminShopUserIdPlaceholder")}
            value={userIdFilter || ""}
            onChange={(e) => setUserIdFilter(e.target.value ? parseInt(e.target.value) : null)}
            className="w-full sm:w-32 px-4 py-2 rounded-lg"
            style={getInputStyle(theme)}
          />
        </div>
      </div>

      <div className="rounded-xl overflow-hidden w-full" style={cardStyle}>
        <div className="overflow-x-auto">
          <table className="w-full min-w-[1000px]">
            <thead>
              <tr style={{ borderBottom: isDark ? "1px solid rgba(255,255,255,0.1)" : "1px solid rgba(0,0,0,0.1)" }}>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  ID
                </th>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  {t("adminShopStudent")}
                </th>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  {t("adminShopProduct")}
                </th>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  {t("adminShopPrice")}
                </th>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  {t("adminShopPurchaseDate")}
                </th>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  {t("adminShopStatus")}
                </th>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  {t("adminShopDeliveryDate")}
                </th>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  {t("adminShopCourier")}
                </th>
                <th className="px-4 py-3 text-left text-sm font-semibold" style={{ color: textColors.primary }}>
                  {t("adminShopActions")}
                </th>
              </tr>
            </thead>
            <tbody>
              {filteredPurchases.map((purchase) => (
                <tr
                  key={purchase.id}
                  className="hover:bg-opacity-50 transition-colors"
                  style={{ borderBottom: isDark ? "1px solid rgba(255,255,255,0.05)" : "1px solid rgba(0,0,0,0.05)" }}
                >
                  <td className="px-4 py-3 text-sm" style={{ color: textColors.secondary }}>
                    #{purchase.id}
                  </td>
                  <td className="px-4 py-3">
                    <div>
                      <div className="font-medium text-sm" style={{ color: textColors.primary }}>
                        {purchase.user_name}
                      </div>
                      <div className="text-xs" style={{ color: textColors.secondary }}>
                        {purchase.user_email}
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-3 text-sm" style={{ color: textColors.primary }}>
                    {getLocalizedProductTitle(purchase.item_title, t)}
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-1">
                      <Image src="/icons/coin.png" alt="" width={14} height={14} />
                      <span className="text-sm font-medium" style={{ color: "#FBBF24" }}>
                        {purchase.item_price_coins}
                      </span>
                    </div>
                  </td>
                  <td className="px-4 py-3 text-sm" style={{ color: textColors.secondary }}>
                    {purchase.purchased_at
                      ? formatLocalizedDate(purchase.purchased_at, lang as any, t)
                      : "-"}

                  </td>
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-2">
                      <div
                        className="flex items-center gap-1.5 px-2 py-1 rounded-lg text-xs font-medium"
                        style={{
                          background: `${getStatusColor(purchase.delivery_status)}20`,
                          color: getStatusColor(purchase.delivery_status),
                        }}
                      >
                        {getStatusIcon(purchase.delivery_status)}
                        {getStatusLabel(purchase.delivery_status)}
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-3">
                    {purchase.delivery_status === "delivered" && purchase.delivered_at ? (
                      <div className="flex items-center gap-1.5">
                        <CheckCircle className="w-3.5 h-3.5" style={{ color: "#10B981" }} />
                        <span className="text-sm" style={{ color: "#10B981" }}>
                          {formatLocalizedDate(purchase.delivered_at, lang as any, t)}
                        </span>

                      </div>
                    ) : purchase.estimated_delivery_date ? (
                      <div className="flex items-center gap-1.5">
                        <Clock className="w-3.5 h-3.5" style={{ color: textColors.secondary }} />
                        <span className="text-sm" style={{ color: textColors.secondary }}>
                          {t("adminShopExpected")} {formatLocalizedDate(purchase.estimated_delivery_date, lang as any, t)}
                        </span>

                      </div>
                    ) : (
                      <span className="text-xs" style={{ color: textColors.secondary }}>
                        -
                      </span>
                    )}
                  </td>
                  <td className="px-4 py-3">
                    {purchase.courier_name ? (
                      <div className="space-y-1">
                        <button
                          onClick={() => {
                            if (purchase.courier_id) {
                              setInitialCourierId(purchase.courier_id);
                              setActiveTab("couriers");
                            }
                          }}
                          className="flex items-center gap-1.5 hover:opacity-80 transition-opacity text-left"
                          title={t("adminShopViewCourierDeliveries")}
                        >
                          <div className="text-sm font-medium" style={{ color: "#06B6D4" }}>
                            {purchase.courier_name}
                          </div>
                          {purchase.delivery_status === "delivered" && purchase.delivered_at && (
                            <CheckCircle className="w-3.5 h-3.5" style={{ color: "#10B981" }} aria-label={t("adminShopDeliveredByCourier")} />
                          )}
                        </button>
                        {purchase.delivery_status === "delivered" && purchase.delivered_at && (
                          <div className="text-xs" style={{ color: textColors.secondary }}>
                            {t("adminShopDeliveredOn")} {formatLocalizedDate(purchase.delivered_at, lang as any, t)}
                          </div>

                        )}
                      </div>
                    ) : (
                      <span className="text-xs" style={{ color: textColors.secondary }}>
                        {t("adminShopNotAssigned")}
                      </span>
                    )}
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex gap-2">
                      <button
                        onClick={() => {
                          setAssigningCourier(purchase);
                          setSelectedCourierId(purchase.courier_id || null);
                        }}
                        className="px-3 py-1.5 rounded-lg text-xs font-medium transition-all hover:opacity-90"
                        style={{
                          background: "linear-gradient(135deg, #06B6D4 0%, #3B82F6 100%)",
                          color: "#FFFFFF",
                        }}
                        title={t("adminShopAssignCourier")}
                      >
                        <UserPlus className="w-4 h-4 inline" />
                      </button>
                      <button
                        onClick={() => {
                          setEditingPurchase(purchase);
                          setNewStatus(purchase.delivery_status);
                        }}
                        className="px-3 py-1.5 rounded-lg text-xs font-medium transition-all hover:opacity-90"
                        style={{
                          background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)",
                          color: "#FFFFFF",
                        }}
                      >
                        {t("adminShopUpdateStatus")}
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredPurchases.length === 0 && (
            <div className="text-center py-12">
              <Package className="w-16 h-16 mx-auto mb-4 opacity-20" style={{ color: textColors.secondary }} />
              <p className="text-lg font-medium" style={{ color: textColors.primary }}>
                {t("adminShopNoPurchasesFound")}
              </p>
            </div>
          )}
        </div>
      </div>

      {editingPurchase && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4"
          style={{ background: isDark ? "rgba(0,0,0,0.7)" : "rgba(0,0,0,0.5)" }}
          onClick={() => setEditingPurchase(null)}
        >
          <div
            className="rounded-2xl shadow-xl max-w-md w-full p-6"
            style={modalStyle}
            onClick={(e) => e.stopPropagation()}
          >
            <h2 className="text-xl font-bold mb-4" style={{ color: textColors.primary }}>
              {t("adminShopUpdateDeliveryStatus")}
            </h2>
            <div className="mb-4">
              <p className="text-sm mb-2" style={{ color: textColors.secondary }}>
                {t("adminShopProductLabel")} {getLocalizedProductTitle(editingPurchase.item_title, t)}
              </p>
              <p className="text-sm" style={{ color: textColors.secondary }}>
                {t("adminShopStudentLabel")} {editingPurchase.user_name}
              </p>
            </div>
            <div className="mb-6">
              <label className="block text-sm font-medium mb-2" style={{ color: textColors.primary }}>
                {t("adminShopNewStatus")}
              </label>
              <select
                value={newStatus}
                onChange={(e) => setNewStatus(e.target.value)}
                className="w-full px-4 py-2 rounded-lg"
                style={getInputStyle(theme)}
              >
                {DELIVERY_STATUSES.map((status) => (
                  <option key={status.value} value={status.value}>
                    {getStatusLabel(status.value)}
                  </option>
                ))}
              </select>
            </div>
            <div className="flex gap-3">
              <button
                onClick={() => setEditingPurchase(null)}
                className="flex-1 py-2.5 rounded-lg font-medium transition-colors"
                style={{
                  color: textColors.primary,
                  background: isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.05)",
                  border: isDark ? "1px solid rgba(255,255,255,0.1)" : "1px solid rgba(0,0,0,0.1)",
                }}
              >
                {t("adminShopCancel")}
              </button>
              <button
                onClick={() => {
                  updateStatusMutation.mutate({
                    purchaseId: editingPurchase.id,
                    status: newStatus,
                  });
                }}
                disabled={updateStatusMutation.isPending}
                className="flex-1 py-2.5 rounded-lg font-medium text-white transition-all hover:opacity-90 disabled:opacity-50"
                style={{ background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)" }}
              >
                {updateStatusMutation.isPending ? t("adminShopSaving") : t("adminShopSave")}
              </button>
            </div>
          </div>
        </div>
      )}

      {assigningCourier && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4"
          style={{ background: isDark ? "rgba(0,0,0,0.7)" : "rgba(0,0,0,0.5)" }}
          onClick={() => setAssigningCourier(null)}
        >
          <div
            className="rounded-2xl shadow-xl max-w-md w-full p-6"
            style={modalStyle}
            onClick={(e) => e.stopPropagation()}
          >
            <h2 className="text-xl font-bold mb-4" style={{ color: textColors.primary }}>
              {t("adminShopAssignCourier")}
            </h2>
            <div className="mb-4">
              <p className="text-sm mb-2" style={{ color: textColors.secondary }}>
                {t("adminShopProductLabel")} {getLocalizedProductTitle(assigningCourier.item_title, t)}
              </p>
              <p className="text-sm" style={{ color: textColors.secondary }}>
                {t("adminShopStudentLabel")} {assigningCourier.user_name}
              </p>
            </div>
            <div className="mb-6">
              <label className="block text-sm font-medium mb-2" style={{ color: textColors.primary }}>
                {t("adminShopSelectCourier")}
              </label>
              <select
                value={selectedCourierId || ""}
                onChange={(e) => setSelectedCourierId(e.target.value ? parseInt(e.target.value) : null)}
                className="w-full px-4 py-2 rounded-lg"
                style={getInputStyle(theme)}
              >
                <option value="">{t("adminShopNotAssigned")}</option>
                {availableCouriers.map((courier) => (
                  <option key={courier.id} value={courier.id}>
                    {courier.full_name} {courier.deliveries_count > 0 ? `(${courier.deliveries_count} ${t("adminShopTotalDeliveries").toLowerCase()})` : `(${t("adminShopCourierRole").toLowerCase()})`}
                  </option>
                ))}
              </select>
              {availableCouriers.length === 0 && (
                <p className="text-xs mt-2" style={{ color: textColors.secondary }}>
                  {t("adminShopNoCouriersAvailable")}
                </p>
              )}
            </div>
            <div className="flex gap-3">
              <button
                onClick={() => setAssigningCourier(null)}
                className="flex-1 py-2.5 rounded-lg font-medium transition-colors"
                style={{
                  color: textColors.primary,
                  background: isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.05)",
                  border: isDark ? "1px solid rgba(255,255,255,0.1)" : "1px solid rgba(0,0,0,0.1)",
                }}
              >
                {t("adminShopCancel")}
              </button>
              <button
                onClick={() => {
                  if (selectedCourierId) {
                    assignCourierMutation.mutate({
                      purchaseId: assigningCourier.id,
                      courierId: selectedCourierId,
                    });
                  } else {
                    // Можно добавить endpoint для удаления курьера, но пока просто закрываем
                    setAssigningCourier(null);
                  }
                }}
                disabled={assignCourierMutation.isPending || !selectedCourierId}
                className="flex-1 py-2.5 rounded-lg font-medium text-white transition-all hover:opacity-90 disabled:opacity-50"
                style={{ background: "linear-gradient(135deg, #06B6D4 0%, #3B82F6 100%)" }}
              >
                {assignCourierMutation.isPending ? t("adminShopSaving") : t("adminShopAssign")}
              </button>
            </div>
          </div>
        </div>
      )}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";

interface StaggeredAnimationProps {
  children: React.ReactNode;
  delay?: number;
  className?: string;
}

export function StaggeredAnimation({ 
  children, 
  delay = 0,
  className = "" 
}: StaggeredAnimationProps) {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setTimeout(() => {
              setIsVisible(true);
            }, delay);
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.1 }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => {
      if (ref.current) {
        observer.unobserve(ref.current);
      }
    };
  }, [delay]);

  return (
    <div
      ref={ref}
      className={`transition-all duration-700 ease-out ${
        isVisible
          ? "opacity-100 translate-y-0"
          : "opacity-0 translate-y-8"
      } ${className}`}
    >
      {children}
    </div>
  );
}

"use client";

import { useQuery, useMutation, useQueryClient, type UseMutationResult } from "@tanstack/react-query";
import { api } from "@/api/client";
import { useState } from "react";
import type { Test, TestQuestion } from "@/types";
import { Pencil, Trash2, Plus, ChevronDown, ChevronUp } from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";
import { useTheme } from "@/context/ThemeContext";
import { getTextColors } from "@/utils/themeStyles";

interface CourseStructure {
  course_id: number;
  modules: Array<{
    id: number;
    title: string;
    order_number: number;
    topics: Array<{ id: number; title: string; order_number: number }>;
  }>;
}

interface TestManagementProps {
  courseId: number;
  courseTitle: string;
}

export function TestManagement({ courseId, courseTitle }: TestManagementProps) {
  const { t } = useLanguage();
  const { theme } = useTheme();
  const textColors = getTextColors(theme);
  const [editingTest, setEditingTest] = useState<Test | null>(null);
  const [deleteTestConfirm, setDeleteTestConfirm] = useState<number | null>(null);
  const [expandedTest, setExpandedTest] = useState<number | null>(null);
  const [showCreateTest, setShowCreateTest] = useState(false);
  const [editingQuestion, setEditingQuestion] = useState<TestQuestion | null>(null);
  const [addingQuestion, setAddingQuestion] = useState<number | null>(null);
  const [deleteQuestionConfirm, setDeleteQuestionConfirm] = useState<{ testId: number; questionId: number } | null>(null);
  const queryClient = useQueryClient();

  const { data: tests = [] } = useQuery({
    queryKey: ["admin-tests", courseId],
    queryFn: async () => {
      const { data } = await api.get<Test[]>(`/admin/courses/${courseId}/tests`);
      return data;
    },
  });

  const { data: structure } = useQuery({
    queryKey: ["course-structure", courseId],
    queryFn: async () => {
      const { data } = await api.get<CourseStructure>(`/courses/${courseId}/structure`);
      return data;
    },
  });

  const topics = structure?.modules?.flatMap((m) => m.topics) ?? [];

  const createTestMutation = useMutation({
    mutationFn: async (body: { title: string; passing_score: number; question_count: number; topic_id?: number; is_final?: boolean }) => {
      const { data } = await api.post<Test>(`/admin/courses/${courseId}/tests`, {
        course_id: courseId,
        title: body.title,
        passing_score: body.passing_score,
        question_count: body.question_count,
        topic_id: body.topic_id ?? null,
        is_final: body.is_final ?? false,
        time_limit_seconds: null,
      });
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-tests", courseId] });
      queryClient.invalidateQueries({ queryKey: ["admin-tests-by-course"] });
      setShowCreateTest(false);
    },
  });

  const updateTestMutation = useMutation({
    mutationFn: async ({ id, body }: { id: number; body: Partial<{ title: string; passing_score: number; question_count: number }> }) => {
      const { data } = await api.patch<Test>(`/admin/tests/${id}`, body);
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-tests", courseId] });
      queryClient.invalidateQueries({ queryKey: ["admin-tests-by-course"] });
      setEditingTest(null);
    },
  });

  const deleteTestMutation = useMutation({
    mutationFn: async (id: number) => {
      await api.delete(`/admin/tests/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-tests", courseId] });
      queryClient.invalidateQueries({ queryKey: ["admin-tests-by-course"] });
      setDeleteTestConfirm(null);
    },
  });

  const addQuestionMutation = useMutation({
    mutationFn: async ({ testId, body }: { testId: number; body: { question_text: string; correct_answer: string; option_a: string; option_b: string; option_c: string; option_d: string; order_number?: number } }) => {
      const { data } = await api.post<TestQuestion>(`/admin/tests/${testId}/questions`, { ...body, test_id: testId });
      return data;
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["admin-questions", vars.testId] });
      setAddingQuestion(null);
    },
  });

  const updateQuestionMutation = useMutation({
    mutationFn: async ({ testId, questionId, body }: { testId: number; questionId: number; body: Partial<TestQuestion> }) => {
      const { data } = await api.patch<TestQuestion>(`/admin/tests/${testId}/questions/${questionId}`, body);
      return data;
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["admin-questions", vars.testId] });
      setEditingQuestion(null);
    },
  });

  const deleteQuestionMutation = useMutation({
    mutationFn: async ({ testId, questionId }: { testId: number; questionId: number }) => {
      await api.delete(`/admin/tests/${testId}/questions/${questionId}`);
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["admin-questions", vars.testId] });
      setDeleteQuestionConfirm(null);
    },
  });

  return (
    <div>
      <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between mb-4 min-w-0">
        <div className="min-w-0">
          <h1 className="text-lg sm:text-2xl font-bold break-words" style={{ color: textColors.primary }}>{t("adminTestTitle")}: {courseTitle}</h1>
          <p className="mt-1 text-sm sm:text-base" style={{ color: textColors.secondary }}>{t("adminTestSubtitle")}</p>
        </div>
        <button
          type="button"
          onClick={() => setShowCreateTest(true)}
          className="flex items-center justify-center gap-2 py-2.5 px-4 rounded-lg bg-qit-primary text-white hover:opacity-90 w-full sm:w-auto shrink-0 text-sm font-medium"
        >
          <Plus className="w-4 h-4 shrink-0" /> {t("adminTestCreate")}
        </button>
      </div>

      <div className="space-y-4">
        {tests.map((test) => (
          <TestCard
            key={test.id}
            test={test}
            courseId={courseId}
            isExpanded={expandedTest === test.id}
            onToggleExpand={() => setExpandedTest((v) => (v === test.id ? null : test.id))}
            onEdit={() => setEditingTest(test)}
            onDelete={() => setDeleteTestConfirm(test.id)}
            onAddQuestion={() => setAddingQuestion(test.id)}
            onCloseAddQuestion={() => setAddingQuestion(null)}
            editingQuestion={editingQuestion}
            onEditQuestion={setEditingQuestion}
            addingQuestion={addingQuestion}
            onDeleteQuestion={(qId) => setDeleteQuestionConfirm({ testId: test.id, questionId: qId })}
            addQuestionMutation={addQuestionMutation as UseMutationResult<unknown, Error, unknown, unknown>}
            updateQuestionMutation={updateQuestionMutation as UseMutationResult<unknown, Error, unknown, unknown>}
            deleteQuestionMutation={deleteQuestionMutation as UseMutationResult<unknown, Error, unknown, unknown>}
          />
        ))}
      </div>

      {showCreateTest && (
        <CreateTestModal
          courseId={courseId}
          topics={topics}
          onClose={() => setShowCreateTest(false)}
          onSubmit={(body) => createTestMutation.mutate(body)}
          isPending={createTestMutation.isPending}
        />
      )}

      {editingTest && (
        <EditTestModal
          test={editingTest}
          onClose={() => setEditingTest(null)}
          onSave={(body) => updateTestMutation.mutate({ id: editingTest.id, body })}
          isPending={updateTestMutation.isPending}
        />
      )}

      {deleteTestConfirm && (
        <ConfirmModal
          title={t("adminTestDeleteConfirm")}
          message={t("adminTestDeleteMessage")}
          onClose={() => setDeleteTestConfirm(null)}
          onConfirm={() => deleteTestMutation.mutate(deleteTestConfirm)}
          isPending={deleteTestMutation.isPending}
        />
      )}

      {deleteQuestionConfirm && (
        <ConfirmModal
          title={t("adminTestQuestionDelete")}
          message={t("adminTestQuestionDeleteMessage")}
          onClose={() => setDeleteQuestionConfirm(null)}
          onConfirm={() =>
            deleteQuestionMutation.mutate({
              testId: deleteQuestionConfirm.testId,
              questionId: deleteQuestionConfirm.questionId,
            })
          }
          isPending={deleteQuestionMutation.isPending}
        />
      )}
    </div>
  );
}

function TestCard({
  test,
  courseId,
  isExpanded,
  onToggleExpand,
  onEdit,
  onDelete,
  onAddQuestion,
  onCloseAddQuestion,
  editingQuestion,
  onEditQuestion,
  addingQuestion,
  onDeleteQuestion,
  addQuestionMutation,
  updateQuestionMutation,
  deleteQuestionMutation,
}: {
  test: Test;
  courseId: number;
  isExpanded: boolean;
  onToggleExpand: () => void;
  onEdit: () => void;
  onDelete: () => void;
  onAddQuestion: () => void;
  onCloseAddQuestion: () => void;
  editingQuestion: TestQuestion | null;
  onEditQuestion: (q: TestQuestion | null) => void;
  addingQuestion: number | null;
  onDeleteQuestion: (questionId: number) => void;
  addQuestionMutation: UseMutationResult<unknown, Error, unknown, unknown>;
  updateQuestionMutation: UseMutationResult<unknown, Error, unknown, unknown>;
  deleteQuestionMutation: UseMutationResult<unknown, Error, unknown, unknown>;
}) {
  const { t } = useLanguage();
  const { theme } = useTheme();
  const textColors = getTextColors(theme);
  const { data: questions = [] } = useQuery({
    queryKey: ["admin-questions", test.id],
    queryFn: async () => {
      const { data } = await api.get<TestQuestion[]>(`/admin/tests/${test.id}/questions`);
      return data;
    },
    enabled: isExpanded,
  });

  return (
    <div className="bg-white dark:bg-gray-800 rounded-xl shadow border border-gray-100 dark:border-gray-700 overflow-hidden">
      <div className="flex items-center justify-between p-4">
        <button type="button" onClick={onToggleExpand} className="flex items-center gap-2 flex-1 text-left">
          {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
          <div>
            <h3 className="font-semibold text-gray-800 dark:text-white">{test.title}</h3>
            <p className="text-sm" style={{ color: textColors.secondary }}>
              {t("adminTestPassingScoreLabel").replace("{score}", test.passing_score.toString()).replace("{count}", test.question_count.toString()).replace("{dbCount}", questions.length.toString())}
            </p>
          </div>
        </button>
        <div className="flex items-center gap-1">
          <button type="button" onClick={onEdit} className="p-2 text-qit-primary hover:bg-qit-primary/10 rounded-lg" title={t("adminTestEdit")}>
            <Pencil className="w-4 h-4" />
          </button>
          <button type="button" onClick={onDelete} className="p-2 text-red-600 hover:bg-red-50 rounded-lg" title={t("adminTestDelete")}>
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      </div>
      {isExpanded && (
        <div className="border-t border-gray-100 dark:border-gray-700 p-4 bg-gray-50/50 dark:bg-gray-800/50">
          <div className="flex justify-between items-center mb-3">
            <h4 className="font-medium" style={{ color: textColors.primary }}>{t("adminTestQuestions")}</h4>
            <button
              type="button"
              onClick={onAddQuestion}
              className="flex items-center gap-1 text-sm py-1.5 px-3 rounded-lg border border-qit-primary text-qit-primary hover:bg-qit-primary/10"
            >
              <Plus className="w-4 h-4" /> {t("adminTestAddQuestion")}
            </button>
          </div>
          <ul className="space-y-2">
            {questions.map((q) => (
              <li key={q.id} className="flex items-center justify-between p-3 bg-white dark:bg-gray-800 rounded-lg border dark:border-gray-700">
                <div className="flex-1 min-w-0">
                  <p className="text-sm text-gray-800 dark:text-white truncate">{q.question_text}</p>
                  <p className="text-xs mt-0.5" style={{ color: textColors.secondary }}>{t("adminTestCorrectAnswerLabel").replace("{answer}", (q.correct_answer ?? "—").toUpperCase())}</p>
                </div>
                <div className="flex items-center gap-1 ml-2">
                  <button type="button" onClick={() => onEditQuestion(q)} className="p-1.5 text-qit-primary hover:bg-qit-primary/10 rounded">
                    <Pencil className="w-4 h-4" />
                  </button>
                  <button type="button" onClick={() => onDeleteQuestion(q.id)} className="p-1.5 text-red-600 hover:bg-red-50 rounded">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </li>
            ))}
          </ul>
          {addingQuestion === test.id && (
            <AddQuestionForm
              testId={test.id}
              onClose={() => { onCloseAddQuestion(); addQuestionMutation.reset(); }}
              onSubmit={(body) => addQuestionMutation.mutate({ testId: test.id, body })}
              isPending={addQuestionMutation.isPending}
            />
          )}
          {editingQuestion && editingQuestion.test_id === test.id && (
            <EditQuestionModal
              question={editingQuestion}
              onClose={() => onEditQuestion(null)}
              onSave={(body) => updateQuestionMutation.mutate({ testId: test.id, questionId: editingQuestion.id, body })}
              isPending={updateQuestionMutation.isPending}
            />
          )}
        </div>
      )}
    </div>
  );
}

function CreateTestModal({
