  const { data, isLoading } = useQuery({
    queryKey: ["student-study-plan"],
    queryFn: async () => {
      const { data } = await api.get<StudyPlanData>("/analytics/student-insights/study-plan");
      return data;
    },
  });

  if (isLoading) {
    return (
      <div className="rounded-xl p-8 text-center" style={glassStyle}>
        <div className="animate-spin w-8 h-8 border-2 border-purple-500 border-t-transparent rounded-full mx-auto" />
        <p className="mt-3 text-sm" style={{ color: textColors.secondary }}>{t("loading")}</p>
      </div>
    );
  }

  if (!data || data.recommendations.length === 0) {
    return (
      <div className="rounded-xl p-8 text-center" style={glassStyle}>
        <ListChecks className="w-10 h-10 mx-auto mb-3 text-gray-400" />
        <p className="text-sm" style={{ color: textColors.secondary }}>{t("studyPlanEmpty")}</p>
      </div>
    );
  }

  const getReason = (rec: Recommendation) => {
    if (lang === "kk") return rec.reason_kk;
    if (lang === "en") return rec.reason_en;
    return rec.reason;
  };

  const priorityConfig = {
    high: { color: "#EF4444", bg: "rgba(239, 68, 68, 0.1)", border: "rgba(239, 68, 68, 0.2)" },
    medium: { color: "#6366F1", bg: "rgba(99, 102, 241, 0.1)", border: "rgba(99, 102, 241, 0.2)" },
    low: { color: "#10B981", bg: "rgba(16, 185, 129, 0.1)", border: "rgba(16, 185, 129, 0.2)" },
  };

  return (
    <div className="space-y-4">
      {/* Header with daily goal */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
        <div
          className="rounded-xl p-5 relative overflow-hidden"
          style={{
            background: isDark
              ? "linear-gradient(135deg, rgba(20, 184, 166, 0.15) 0%, rgba(99, 102, 241, 0.1) 100%)"
              : "linear-gradient(135deg, rgba(20, 184, 166, 0.08) 0%, rgba(99, 102, 241, 0.05) 100%)",
            border: isDark
              ? "1px solid rgba(20, 184, 166, 0.25)"
              : "1px solid rgba(20, 184, 166, 0.15)",
          }}
        >
          <div className="flex items-center gap-2 mb-2">
            <Target className="w-4 h-4 text-teal-500" />
            <span className="text-xs font-semibold" style={{ color: textColors.secondary }}>
              {t("studyPlanGoal")}
            </span>
          </div>
          <p className="text-3xl font-black" style={{ color: "#14B8A6" }}>
            {data.daily_goal_topics}
          </p>
          <p className="text-xs mt-1" style={{ color: textColors.secondary }}>
            {t("studyPlanTopicsPerDay")}
          </p>
        </div>

        <div
          className="rounded-xl p-5 relative overflow-hidden"
          style={glassStyle}
        >
          <div className="flex items-center gap-2 mb-2">
            <RefreshCw className="w-4 h-4" style={{ color: textColors.secondary }} />
            <span className="text-xs font-semibold" style={{ color: textColors.secondary }}>
              {t("studyPlanCurrentPace")}
            </span>
          </div>
          <p className="text-3xl font-black" style={{ color: textColors.primary }}>
            {data.current_pace_per_day}
          </p>
          <p className="text-xs mt-1" style={{ color: textColors.secondary }}>
            {t("studyPlanTopicsPerDay")}
          </p>
        </div>
      </div>

      {/* Title */}
      <div className="rounded-xl p-4" style={glassStyle}>
        <div className="flex items-center gap-3">
          <ListChecks className="w-5 h-5 text-indigo-500" />
          <h3 className="font-bold" style={{ color: textColors.primary }}>{t("studyPlanTitle")}</h3>
        </div>
      </div>

      {/* Recommendations list */}
      <div className="space-y-2">
        {data.recommendations.map((rec, idx) => {
          const pConf = priorityConfig[rec.priority] || priorityConfig.medium;
          const isReview = rec.type === "review";

          return (
            <div
              key={`${rec.type}-${rec.topic_id}-${idx}`}
              className="rounded-xl p-4 sm:p-5 transition-all duration-200 hover:-translate-y-0.5 hover:shadow-lg"
              style={glassStyle}
            >
              <div className="flex items-start gap-3">
                {/* Priority indicator */}
                <div
                  className="w-10 h-10 rounded-xl flex items-center justify-center shrink-0"
                  style={{ background: pConf.bg, border: `1px solid ${pConf.border}` }}
                >
                  {isReview ? (
                    <RefreshCw className="w-4.5 h-4.5" style={{ color: pConf.color }} />
                  ) : (
                    <BookOpen className="w-4.5 h-4.5" style={{ color: pConf.color }} />
                  )}
                </div>

                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-0.5">
                    <span
                      className="text-[10px] font-bold uppercase px-1.5 py-0.5 rounded"
                      style={{ color: pConf.color, background: pConf.bg }}
                    >
                      {isReview ? t("studyPlanReview") : t("studyPlanContinue")}
                    </span>
                  </div>
                  <h4 className="font-semibold text-sm truncate" style={{ color: textColors.primary }}>
                    {getLocalizedTopicTitle(rec.topic_title, t)}
                  </h4>
                  <p className="text-xs truncate mt-0.5" style={{ color: textColors.secondary }}>
                    {getLocalizedCourseTitle({ title: rec.course_title } as any, t)}
                  </p>
                  <p className="text-xs mt-1.5" style={{ color: textColors.secondary }}>
                    {getReason(rec)}
                  </p>
                </div>

                <Link
                  href={`/app/courses/${rec.course_id}/topic/${rec.topic_id}`}
                  className="shrink-0 flex items-center gap-1 px-3 py-2 rounded-lg text-xs font-semibold text-white transition-opacity hover:opacity-90"
                  style={{ background: `linear-gradient(135deg, ${pConf.color}, ${pConf.color}cc)` }}
                >
                  {isReview ? t("weakTopicsRetry") : t("studyPlanContinue")}
                  <ChevronRight className="w-3.5 h-3.5" />
                </Link>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import Link from "next/link";
import { AlertTriangle, ChevronRight, RefreshCw, CheckCircle2 } from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";
import { useTheme } from "@/context/ThemeContext";
import { getGlassCardStyle, getTextColors } from "@/utils/themeStyles";
import { useQuery } from "@tanstack/react-query";
import { api } from "@/api/client";
import { getLocalizedCourseTitle, getLocalizedTopicTitle } from "@/lib/courseUtils";

interface WeakTopic {
  topic_id: number;
  topic_title: string;
  course_id: number;
  course_title: string;
  test_score: number;
  attempts_count: number;
}

export function WeakTopicsTab() {
  const { t } = useLanguage();
  const { theme } = useTheme();
  const glassStyle = getGlassCardStyle(theme);
  const textColors = getTextColors(theme);
  const isDark = theme === "dark";

  const { data: topics = [], isLoading } = useQuery({
    queryKey: ["student-weak-topics"],
    queryFn: async () => {
      const { data } = await api.get<WeakTopic[]>("/analytics/student-insights/weak-topics");
      return data;
    },
  });

  if (isLoading) {
    return (
      <div className="rounded-xl p-8 text-center" style={glassStyle}>
        <div className="animate-spin w-8 h-8 border-2 border-purple-500 border-t-transparent rounded-full mx-auto" />
        <p className="mt-3 text-sm" style={{ color: textColors.secondary }}>{t("loading")}</p>
      </div>
    );
  }

  if (topics.length === 0) {
    return (
      <div className="rounded-xl p-8 text-center" style={glassStyle}>
        <div className="w-16 h-16 mx-auto mb-4 rounded-2xl bg-green-500/10 flex items-center justify-center">
          <CheckCircle2 className="w-8 h-8 text-green-500" />
        </div>
        <h3 className="text-lg font-bold mb-2" style={{ color: textColors.primary }}>
          🎉 {t("weakTopicsEmpty")}
        </h3>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <div className="rounded-xl p-4" style={glassStyle}>
        <div className="flex items-center gap-3 mb-1">
          <AlertTriangle className="w-5 h-5 text-orange-500" />
          <h3 className="font-bold" style={{ color: textColors.primary }}>{t("weakTopicsTitle")}</h3>
        </div>
        <p className="text-sm ml-8" style={{ color: textColors.secondary }}>{t("weakTopicsHint")}</p>
      </div>

      {topics.map((topic) => {
        const scoreColor =
          topic.test_score < 30
            ? "#EF4444"
            : topic.test_score < 50
            ? "#F59E0B"
            : "#F97316";

        return (
          <div
            key={topic.topic_id}
            className="rounded-xl p-4 sm:p-5 transition-all duration-200 hover:-translate-y-0.5 hover:shadow-lg"
            style={glassStyle}
          >
            <div className="flex items-start justify-between gap-3">
              <div className="flex-1 min-w-0">
                <h4 className="font-semibold text-sm sm:text-base truncate" style={{ color: textColors.primary }}>
                  {getLocalizedTopicTitle(topic.topic_title, t)}
                </h4>
                <p className="text-xs mt-0.5 truncate" style={{ color: textColors.secondary }}>
                  {getLocalizedCourseTitle({ title: topic.course_title } as any, t)}
                </p>
                <div className="flex items-center gap-4 mt-3">
                  <div className="flex items-center gap-1.5">
                    <span className="text-xs font-medium" style={{ color: textColors.secondary }}>
                      {t("weakTopicsScore")}:
                    </span>
                    <span
                      className="text-sm font-bold px-2 py-0.5 rounded-md"
                      style={{ color: scoreColor, background: `${scoreColor}15` }}
                    >
                      {topic.test_score.toFixed(0)}%
                    </span>
                  </div>
                  <div className="flex items-center gap-1.5">
                    <RefreshCw className="w-3.5 h-3.5" style={{ color: textColors.secondary }} />
                    <span className="text-xs" style={{ color: textColors.secondary }}>
                      {topic.attempts_count} {t("weakTopicsAttempts").toLowerCase()}
                    </span>
                  </div>
                </div>
                {/* Score bar */}
                <div className="mt-3 h-1.5 rounded-full overflow-hidden" style={{ background: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.06)" }}>
                  <div
                    className="h-full rounded-full transition-all duration-700"
                    style={{ width: `${topic.test_score}%`, background: scoreColor }}
                  />
                </div>
              </div>
              <Link
                href={`/app/courses/${topic.course_id}/topic/${topic.topic_id}`}
                className="shrink-0 flex items-center gap-1.5 px-3 py-2 rounded-lg text-xs font-semibold text-white transition-opacity hover:opacity-90"
                style={{ background: "linear-gradient(135deg, #6366F1 0%, #8B5CF6 100%)" }}
              >
                {t("weakTopicsRetry")}
                <ChevronRight className="w-3.5 h-3.5" />
              </Link>
            </div>
          </div>
        );
      })}
    </div>
  );
}

"use client";

import Link from "next/link";
import { Check, Lock } from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";
import type { TranslationKey } from "@/i18n/translations";
import { getLocalizedModuleTitle, getLocalizedTopicTitle } from "@/lib/courseUtils";

export type PathNode = "completed" | "current" | "locked";

export interface FlattenedTopic {
  module_id: number;
  module_title: string;
  module_order: number;
  topic_id: number;
  topic_title: string;
  topic_order: number;
  nodeType: PathNode;
}

interface LearningPathProps {
  courseId: number;
  items: FlattenedTopic[];
}

function TopicBlock({
  item,
  courseId,
  t,
}: {
  item: FlattenedTopic;
  courseId: number;
  t: (k: TranslationKey) => string;
}) {
  const base = "rounded-lg px-3 sm:px-4 py-2.5 sm:py-3 font-medium transition-colors min-w-[140px] max-w-full text-center";
  const completed =
    "bg-green-500 dark:bg-green-600 text-white hover:bg-green-600 dark:hover:bg-green-700";
  const current =
    "bg-orange-500 dark:bg-orange-600 text-white hover:bg-orange-600 dark:hover:bg-orange-700";
  const locked =
    "bg-gray-300 dark:bg-gray-600 text-gray-500 dark:text-gray-400 cursor-not-allowed";

  const style =
    item.nodeType === "completed"
      ? completed
      : item.nodeType === "current"
        ? current
        : locked;

  const content = (
      <span className="flex items-center justify-center gap-2 min-w-0">
      {item.nodeType === "completed" && <Check className="h-4 w-4 shrink-0" strokeWidth={2.5} />}
      {item.nodeType === "locked" && <Lock className="h-4 w-4 shrink-0" />}
      <span className="line-clamp-2 sm:line-clamp-1 mobile-safe-text">{item.topic_title}</span>
    </span>
  );

  if (item.nodeType === "locked") {
    return (
      <div title={item.topic_title} className={`${base} ${style}`}>
        {content}
      </div>
    );
  }

  return (
    <Link
      href={`/app/courses/${courseId}/topic/${item.topic_id}`}
      title={item.topic_title}
      className={`block ${base} ${style}`}
    >
      {content}
    </Link>
  );
}

export function LearningPath({ courseId, items }: LearningPathProps) {
  const { t } = useLanguage();

  if (items.length === 0) return null;

  const byModule = items.reduce<FlattenedTopic[][]>((acc, item) => {
    const last = acc[acc.length - 1];
    if (last && last[0]?.module_id === item.module_id) {
      last.push(item);
    } else {
      acc.push([item]);
    }
    return acc;
  }, []);

  return (
    <div className="space-y-6">
      {byModule.map((moduleItems) => (
        <div key={moduleItems[0].module_id}>
          <h3 className="mb-3 text-sm font-semibold text-gray-600 dark:text-gray-400">
            {t("courseUnit")} {moduleItems[0].module_order}:{" "}
            {getLocalizedModuleTitle(moduleItems[0].module_title, t as any)}
          </h3>
          <div className="flex flex-wrap gap-2">
            {moduleItems.map((item) => (
              <TopicBlock
                key={item.topic_id}
                item={{ ...item, topic_title: getLocalizedTopicTitle(item.topic_title, t as any) }}
                courseId={courseId}
                t={t}
              />
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

"use client";

import { useMemo, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { api } from "@/api/client";
import { useLanguage } from "@/context/LanguageContext";
import { 
  Users, 
  Send, 
  Loader2, 
  MessageSquare
} from "lucide-react";
import { cn } from "@/lib/utils";
import { formatRelativeDate } from "@/utils/dateUtils";

type TargetType = "assignment" | "material";

type PrivateComment = {
  id: number | null;
  target_type?: TargetType;
  target_id?: number;
  author_role: string | null;
  author_id: number | null;
  author_name: string | null;
  text: string;
  created_at: string | null;
};

const AVATAR_COLORS = [
  "bg-purple-600",
  "bg-blue-600",
  "bg-amber-500",
  "bg-emerald-600",
  "bg-pink-600",
  "bg-indigo-600",
];

function getAvatarColor(name: string) {
  if (!name) return AVATAR_COLORS[0];
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

function getInitials(name: string) {
  if (!name) return "?";
  return name
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);
}


export function PrivateCommentsSection({
  targetType,
  targetId,
  canPost = true,
  placeholder = "Add private comment...",
  title = "Private comments",
}: {
  targetType: TargetType;
  targetId: number;
  canPost?: boolean;
  placeholder?: string;
  title?: string;
}) {
  const { t, lang } = useLanguage();
  const queryClient = useQueryClient();
  const [draft, setDraft] = useState("");

  const queryKey = useMemo(() => ["private-comments", targetType, targetId] as const, [targetType, targetId]);

  const { data: comments = [], isPending, isError } = useQuery({
    queryKey,
    queryFn: async () => {
      const { data } = await api.get<PrivateComment[]>(
        `/private-comments?target_type=${encodeURIComponent(targetType)}&target_id=${encodeURIComponent(String(targetId))}`
      );
      return data;
    },
    enabled: Number.isFinite(targetId),
  });

  const postMutation = useMutation({
    mutationFn: async (text: string) => {
      await api.post(`/private-comments`, {
        target_type: targetType,
        target_id: targetId,
        text,
      });
    },
    onSuccess: () => {
      setDraft("");
      queryClient.invalidateQueries({ queryKey });
    },
  });

  const displayComments = useMemo(() => {
    return [...comments].sort((a, b) => {
      const ta = a.created_at ? new Date(a.created_at).getTime() : 0;
      const tb = b.created_at ? new Date(b.created_at).getTime() : 0;
      return ta - tb;
    });
  }, [comments]);

  const handleSend = () => {
    if (!draft.trim() || postMutation.isPending) return;
    postMutation.mutate(draft.trim());
  };

  return (
    <div className="flex flex-col gap-4">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Users className="h-5 w-5 text-gray-500 dark:text-gray-400" />
        <h3 className="text-sm font-bold text-gray-900 dark:text-white">
          {displayComments.length} {t("personalComments").toLowerCase()}
        </h3>
      </div>

      {/* Comments List */}
      <div className="space-y-4">
        {isPending ? (
          <div className="flex justify-center py-4">
            <Loader2 className="h-5 w-5 animate-spin text-blue-600" />
          </div>
        ) : isError ? (
          <p className="text-xs text-red-500">{t("privateCommentsLoadError")}</p>
        ) : displayComments.length === 0 ? (
          <p className="text-xs text-gray-400 pl-8 italic">{t("privateCommentsEmpty")}</p>
        ) : (
          displayComments.map((c, idx) => {
            const isStaff = ["teacher", "curator", "admin", "director"].includes(c.author_role || "");
            const authorName = c.author_name || (isStaff ? t("studentTeacher") : t("you"));
            const initials = getInitials(authorName);
            const bgColor = getAvatarColor(authorName);

            return (
              <div key={c.id ?? idx} className="flex gap-3 group animate-in fade-in slide-in-from-bottom-2 duration-300">
                <div className={cn("mt-0.5 flex h-9 w-9 shrink-0 items-center justify-center rounded-full text-[10px] font-bold text-white shadow-sm", bgColor)}>
                  {initials}
                </div>
                <div className="min-w-0 flex-1">
                  <div className="flex items-baseline gap-2">
                    <span className="text-xs font-bold text-gray-900 dark:text-white">
                      {authorName}
                    </span>
                    <span className="text-[10px] text-gray-400 font-medium">
                      • {formatRelativeDate(c.created_at || "", lang, t)}
                    </span>
                  </div>
                  <div className="mt-1 text-sm leading-relaxed text-gray-700 dark:text-gray-300 whitespace-pre-wrap">
                    {c.text}
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* Input Area */}
      <div className="space-y-3">
        <div className={cn(
          "relative overflow-hidden rounded-2xl border bg-white transition-all focus-within:border-blue-500 focus-within:ring-2 focus-within:ring-blue-500/20 dark:bg-gray-950",
          "border-gray-200 dark:border-gray-800"
        )}>
          <textarea
            className="w-full resize-none border-0 bg-transparent px-4 py-3 text-sm text-gray-900 outline-none placeholder:text-gray-400 dark:text-white dark:placeholder:text-gray-600"
            placeholder={placeholder}
            rows={2}
            value={draft}
            disabled={!canPost || postMutation.isPending}
            onChange={(e) => setDraft(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
          />

          <div className="flex items-center justify-end border-t border-gray-100 px-3 py-1.5 dark:border-gray-900">
            <button
              type="button"
              onClick={handleSend}
              disabled={postMutation.isPending || !draft.trim() || !canPost}
              className={cn(
                "ml-auto flex h-8 w-8 shrink-0 items-center justify-center rounded-full transition-all active:scale-95",
                draft.trim() && canPost
                  ? "bg-blue-600 text-white shadow-md shadow-blue-500/20 hover:bg-blue-700" 
                  : "bg-gray-100 text-gray-300 dark:bg-gray-800 dark:text-gray-600"
              )}
            >
              {postMutation.isPending ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Send className="h-4 w-4" />
              )}
            </button>
          </div>
        </div>

        <p className="flex items-center gap-1.5 px-1 text-[11px] font-medium text-gray-400">
          <MessageSquare className="h-3 w-3" />
          {t("privateCommentsAssignmentHint")}
        </p>
      </div>
    </div>
  );
}

