"use client";

import { useRef, useState, useEffect, useCallback } from "react";
import dynamic from "next/dynamic";
import { Gauge, SkipForward, Loader2, AlertCircle } from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";

/** Matches progressInterval (ms) below */
const PROGRESS_INTERVAL_SEC = 1;
const MAX_STEP_COEFF = 2;
const MAX_STEP_SLACK = 3;

function maxAllowedForwardStep(playbackRate: number) {
  return playbackRate * PROGRESS_INTERVAL_SEC * MAX_STEP_COEFF + MAX_STEP_SLACK;
}

const ReactPlayer = dynamic(() => import("react-player"), { 
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center bg-black/90 aspect-video rounded-lg">
      <Loader2 className="w-8 h-8 text-purple-500 animate-spin" />
    </div>
  )
});

interface VideoPlayerProps {
  src?: string;
  duration: number;
  initialWatched: number;
  onProgress: (seconds: number) => void;
  onDurationLoaded?: (seconds: number) => void;
  disabled?: boolean;
  isPremium?: boolean;
}

export function VideoPlayer({
  src,
  duration,
  initialWatched,
  onProgress,
  onDurationLoaded,
  disabled = false,
  isPremium = false,
}: VideoPlayerProps) {
  const { t } = useLanguage();
  const playerRef = useRef<any>(null);
  const [mounted, setMounted] = useState(false);
  const [isReady, setIsReady] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [watched, setWatched] = useState(initialWatched);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [showSpeedMenu, setShowSpeedMenu] = useState(false);
  const [showSkipWarning, setShowSkipWarning] = useState(false);
  const lastSent = useRef(0);
  /** Furthest honestly reached time (seconds); drives API / UI */
  const legitimateMaxRef = useRef(initialWatched);
  /** Last raw playedSeconds sample (for jump detection) */
  const lastAcceptedSecondsRef = useRef(initialWatched);
  const skipFlagRef = useRef(false);
  const effectiveRate = isPremium ? playbackRate : 1.0;

  useEffect(() => {
    setMounted(true);
  }, []);

  const videoSrc = src?.startsWith("http") ? src : src ? (src.startsWith("/") ? src : `/uploads/${src}`) : undefined;

  const Player = ReactPlayer as any;

  const [hasSetInitialProgress, setHasSetInitialProgress] = useState(false);

  const syncRefsFromInitial = useCallback((w: number) => {
    legitimateMaxRef.current = w;
    lastAcceptedSecondsRef.current = w;
    lastSent.current = w;
    setWatched(w);
  }, []);

  useEffect(() => {
    syncRefsFromInitial(initialWatched);
    setHasSetInitialProgress(false);
    setIsReady(false);
    setError(null);
    // eslint-disable-next-line react-hooks/exhaustive-deps -- only reset player bookkeeping when the media URL changes
  }, [src]);

  const showSkipWarningBriefly = useCallback(() => {
    setShowSkipWarning(true);
    setTimeout(() => setShowSkipWarning(false), 2500);
  }, []);

  const clampSeekToLegitimate = useCallback(() => {
    const cap = legitimateMaxRef.current;
    skipFlagRef.current = true;
    if (playerRef.current) {
      playerRef.current.seekTo(cap, "seconds");
    }
    lastAcceptedSecondsRef.current = cap;
    showSkipWarningBriefly();
    setTimeout(() => {
      skipFlagRef.current = false;
    }, 500);
  }, [showSkipWarningBriefly]);

  useEffect(() => {
    if (initialWatched > 0 && !hasSetInitialProgress && playerRef.current) {
      playerRef.current.seekTo(initialWatched, "seconds");
      syncRefsFromInitial(initialWatched);
      setHasSetInitialProgress(true);
    }
  }, [initialWatched, hasSetInitialProgress, mounted, syncRefsFromInitial]);

  const handleProgress = useCallback(
    (state: { playedSeconds: number }) => {
      if (disabled || skipFlagRef.current) return;

      const playedSeconds = state.playedSeconds;
      const maxStep = maxAllowedForwardStep(effectiveRate);
      const lastAcc = lastAcceptedSecondsRef.current;
      const legit = legitimateMaxRef.current;
      const delta = playedSeconds - lastAcc;

      const forwardJumpBeyondLegit =
        delta > maxStep && playedSeconds > legit + 0.01;

      if (forwardJumpBeyondLegit) {
        clampSeekToLegitimate();
        return;
      }

      lastAcceptedSecondsRef.current = playedSeconds;

      const floored = Math.floor(playedSeconds);
      if (floored > legit) {
        legitimateMaxRef.current = floored;
      }

      if (floored > lastSent.current) {
        lastSent.current = floored;
        setWatched(floored);
        onProgress(floored);
      }
    },
    [disabled, onProgress, effectiveRate, clampSeekToLegitimate],
  );

  const handleSeek = useCallback(
    (seconds: number) => {
      if (disabled) return;

      const legit = legitimateMaxRef.current;
      const maxStep = maxAllowedForwardStep(effectiveRate);
      if (seconds > legit + maxStep) {
        clampSeekToLegitimate();
      }
    },
    [disabled, effectiveRate, clampSeekToLegitimate],
  );

  const handleEnded = useCallback(() => {
    if (disabled) return;

    let playerDur = 0;
    try {
      playerDur = Math.floor(playerRef.current?.getDuration?.() ?? 0);
    } catch {
      playerDur = 0;
    }
    const known = Math.max(0, Math.floor(duration));
    const target =
      playerDur > 0 && known > 0 ? Math.min(playerDur, known) : Math.max(playerDur, known);

    if (target <= 0) return;

    legitimateMaxRef.current = target;
    lastAcceptedSecondsRef.current = target;

    if (target > lastSent.current) {
      lastSent.current = target;
      setWatched(target);
      onProgress(target);
    }
  }, [disabled, duration, onProgress]);

  const handleSpeedChange = (rate: number) => {
    setPlaybackRate(rate);
    setShowSpeedMenu(false);
  };

  const speedOptions = [1.0, 1.25, 1.5, 2.0];
  const speedMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (speedMenuRef.current && !speedMenuRef.current.contains(event.target as Node)) {
        setShowSpeedMenu(false);
      }
    };
    if (showSpeedMenu) {
      document.addEventListener("mousedown", handleClickOutside);
      return () => document.removeEventListener("mousedown", handleClickOutside);
    }
  }, [showSpeedMenu]);

  if (!mounted) {
    return (
      <div className="relative bg-black rounded-lg overflow-hidden aspect-video flex items-center justify-center">
        <Loader2 className="w-8 h-8 text-purple-500 animate-spin" />
      </div>
    );
  }

  return (
    <div className="relative w-full bg-black rounded-lg overflow-hidden aspect-video">
      {videoSrc ? (
        <>
          {showSkipWarning && (
            <div className="absolute top-4 left-1/2 -translate-x-1/2 z-30 flex items-center gap-2 bg-black/80 text-white px-4 py-2 rounded-lg text-sm font-medium backdrop-blur-sm border border-white/20 animate-in fade-in slide-in-from-top-2">
              <SkipForward className="w-4 h-4 text-amber-400" />
              <span>{t("videoNoSkipWarning")}</span>
            </div>
          )}

          {!isReady && !error && (
            <div className="absolute inset-0 z-[25] flex items-center justify-center bg-black/60 pointer-events-none">
              <div className="flex flex-col items-center gap-2">
                <Loader2 className="w-10 h-10 text-purple-500 animate-spin" />
                <span className="text-white text-sm font-medium">{t("loading")}...</span>
              </div>
            </div>
          )}

          {error && (
            <div className="absolute inset-0 z-30 flex items-center justify-center bg-black/80 p-6">
              <div className="text-center text-white">
                <AlertCircle className="w-12 h-12 text-red-500 mx-auto mb-3" />
                <p className="font-semibold mb-2">{t("videoLoadError") || "Error loading video"}</p>
                <button 
                  onClick={() => { setError(null); setIsReady(false); }}
                  className="px-4 py-2 bg-purple-600 rounded-lg text-sm hover:bg-purple-700 transition-colors"
                >
                  {t("retry") || "Retry"}
                </button>
              </div>
            </div>
          )}

          <div className="absolute inset-0 z-0 min-h-0 overflow-hidden [&>div]:!h-full [&>div]:!w-full [&>div]:!min-h-0">
            <Player
              ref={playerRef}
              url={videoSrc}
              controls={!disabled}
              width="100%"
              height="100%"
              playsinline
              progressInterval={1000}
              playing={false} // Force manual play to avoid autoplay issues
              playbackRate={isPremium ? playbackRate : 1.0}
              onProgress={handleProgress}
              onSeek={handleSeek}
              onEnded={handleEnded}
              onError={(e: any) => {
                console.error("Video error:", e);
                setError("Failed to load video");
              }}
              onDuration={(dur: number) => {
                if (onDurationLoaded) onDurationLoaded(Math.floor(dur));
              }}
              onReady={() => {
                setIsReady(true);
                if (initialWatched > 0 && playerRef.current && !hasSetInitialProgress) {
                  playerRef.current.seekTo(initialWatched, "seconds");
                  syncRefsFromInitial(initialWatched);
                  setHasSetInitialProgress(true);
                }
              }}
              config={{
                youtube: {
                  playerVars: {
                    showinfo: 0,
                    rel: 0,
                    modestbranding: 1,
                    cc_load_policy: 1,
                    cc_lang_pref: "kk",
                    hl: "kk",
                    origin: typeof window !== "undefined" ? window.location.origin : undefined,
                  },
                },
                file: {
                  attributes: {
                    controlsList: "nodownload",
                    preload: "auto",
                  },
                },
              }}
            />
          </div>

          {isPremium && !disabled && (
            <div className="absolute top-4 right-4 z-30 pointer-events-auto">
              <div className="relative" ref={speedMenuRef}>
                <button
                  type="button"
                  onClick={() => setShowSpeedMenu(!showSpeedMenu)}
                  className="bg-black/70 hover:bg-black/90 text-white px-3 py-2 rounded-lg flex items-center gap-2 text-sm font-medium transition-colors backdrop-blur-sm"
                  title={t("playbackSpeed")}
                >
                  <Gauge className="w-4 h-4" />
                  <span>{playbackRate}x</span>
                </button>
                {showSpeedMenu && (
                  <div className="absolute top-full right-0 mt-2 bg-black/90 backdrop-blur-sm rounded-lg overflow-hidden shadow-xl border border-white/10">
                    {speedOptions.map((rate) => (
                      <button
                        key={rate}
                        type="button"
                        onClick={() => handleSpeedChange(rate)}
                        className={`w-full px-4 py-2 text-left text-sm text-white hover:bg-white/10 transition-colors ${
                          playbackRate === rate ? "bg-purple-600/50 font-semibold" : ""
                        }`}
                      >
                        {rate}x
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}
        </>
      ) : (
        <div className="w-full h-full flex items-center justify-center text-gray-400 bg-gray-900">
          <p>{t("noVideoFiles")}</p>
        </div>
      )}
    </div>
  );
}

"use client";

import Link from "next/link";
import { Clock, BookOpen, UserPlus, CheckCircle2, ChevronRight } from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";
import { useQuery } from "@tanstack/react-query";
import { api } from "@/api/client";
import { useTheme } from "@/context/ThemeContext";
import { getGlassCardStyle, getTextColors } from "@/utils/themeStyles";
import { useAuthStore } from "@/store/authStore";
import { motion, AnimatePresence } from "framer-motion";

const formatTimeAgo = (dateStr: string, t: any) => {
  const date = new Date(dateStr);
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMs / 3600000);
  const diffDays = Math.floor(diffMs / 86400000);

  if (diffMins < 1) return t("timeJustNow");
  if (diffMins < 60) return t("timeMinAgo").replace("{n}", diffMins.toString());
  if (diffHours < 24) return t("timeHourAgo").replace("{n}", diffHours.toString());
  return t("timeDayAgo").replace("{n}", diffDays.toString());
};

export function ActivityFeedWidget() {
  const { t, lang } = useLanguage();
  const { theme } = useTheme();
  const glassStyle = getGlassCardStyle(theme);
  const textColors = getTextColors(theme);
  const { isTeacher } = useAuthStore();
  const teacherMode = isTeacher();

  const { data: activities = [], isLoading } = useQuery({
    queryKey: [teacherMode ? "teacher-recent-submissions" : "student-activity-feed", lang],
    queryFn: async () => {
      const withTimeout = async <T,>(promise: Promise<T>, ms: number): Promise<T> => {
        return await Promise.race([
          promise,
          new Promise<T>((_, reject) => setTimeout(() => reject(new Error("timeout")), ms)),
        ]);
      };
      try {
        if (teacherMode) {
          const { data } = await withTimeout(api.get<Array<{
            id: number;
            student_id: number;
            student_name: string;
            assignment_id: number;
            assignment_title: string;
            group_name: string;
            submitted_at: string;
            grade: number | null;
          }>>("/teacher/recent-submissions"), 7000);
          return data.map(s => ({
            id: s.id,
            type: "submission",
            message: s.student_name,
            subtext: `${t("activitySubtext_submitted")} ${s.assignment_title}`,
            group: s.group_name,
            time: s.submitted_at,
            link: `/app/teacher/view-answers/${s.assignment_id}?tab=submissions&studentId=${s.student_id}`,
          }));
        } else {
          const { data } = await withTimeout(api.get<Array<any>>("/dashboard/events"), 7000);
          return data.slice(0, 10).map((e: any) => {
            let type = "other";
            const notes = (e.notes || "").toLowerCase();
            if (notes.includes("сда") || notes.includes("work") || notes.includes("submission")) type = "submission";
            else if (notes.includes("зада") || notes.includes("assign")) type = "assignment";
            else if (notes.includes("студ") || notes.includes("stud")) type = "student";

            return {
              id: e.id,
              type: type,
              message: e.notes || e.topic_title || t("leaderboardActivity"),
              subtext: e.course_title || "",
              time: e.scheduled_date,
              link: "/app",
              group: null
            };
          });
        }
      } catch {
        return [];
      }
    },
    staleTime: 60_000,
    refetchOnWindowFocus: false,
  });

  const getActivityIcon = (type: string) => {
    switch (type) {
      case "submission": return <CheckCircle2 className="w-4 h-4" />;
      case "assignment": return <BookOpen className="w-4 h-4" />;
      case "student": return <UserPlus className="w-4 h-4" />;
      default: return <Clock className="w-4 h-4" />;
    }
  };

  const getActivityColor = (type: string) => {
    switch (type) {
      case "submission": return "#10b981";
      case "assignment": return "#8B5CF6";
      case "student": return "#3B82F6";
      default: return "#64748B";
    }
  };

  const isDark = theme === "dark";
  const teacherReviewHref = "/app/teacher/courses/review";

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="rounded-unified-lg overflow-hidden backdrop-blur-xl border border-white/10 shadow-2xl"
      style={{
        ...glassStyle,
        background: isDark 
          ? "linear-gradient(135deg, rgba(30, 41, 59, 0.7) 0%, rgba(15, 23, 42, 0.8) 100%)" 
          : "linear-gradient(135deg, rgba(255, 255, 255, 0.9) 0%, rgba(243, 244, 246, 0.8) 100%)",
      }}
    >
      {teacherMode ? (
        <Link
          href={teacherReviewHref}
          className="p-5 text-white flex items-center justify-between relative overflow-hidden group"
          style={{ background: "linear-gradient(135deg, #3B82F6 0%, #8B5CF6 100%)" }}
        >
          <div className="absolute inset-0 bg-black/10 mix-blend-overlay" />
          <div className="absolute top-0 right-0 w-32 h-32 rounded-full opacity-30 blur-2xl bg-white" />
          <div className="flex items-center gap-2 relative z-10 min-w-0">
            <Clock className="w-5 h-5 shrink-0" />
            <h3 className="font-bold text-base tracking-tight">{t("recentActivity")}</h3>
          </div>
          <div className="relative z-10 flex items-center gap-2 shrink-0">
            {isLoading && (
              <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1 }} className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full" />
            )}
            <ChevronRight className="w-5 h-5 opacity-80 group-hover:translate-x-0.5 transition-transform" />
          </div>
        </Link>
      ) : (
        <div
          className="p-5 text-white flex items-center justify-between relative overflow-hidden"
          style={{ background: "linear-gradient(135deg, #3B82F6 0%, #8B5CF6 100%)" }}
        >
          <div className="absolute inset-0 bg-black/10 mix-blend-overlay" />
          <div className="absolute top-0 right-0 w-32 h-32 rounded-full opacity-30 blur-2xl bg-white" />
          <div className="flex items-center gap-2 relative z-10">
            <Clock className="w-5 h-5" />
            <h3 className="font-bold text-base tracking-tight">{t("recentActivity")}</h3>
          </div>
          {isLoading && <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1 }} className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full relative z-10" />}
        </div>
      )}

      <div className="p-4">
        <AnimatePresence mode="popLayout">
          {activities.length === 0 && !isLoading ? (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="flex flex-col items-center justify-center py-10 text-center"
            >
              <div className="w-16 h-16 rounded-full bg-gray-500/10 flex items-center justify-center mb-3">
                <Clock className="w-8 h-8 opacity-20" />
              </div>
              <p className="text-sm font-medium" style={{ color: textColors.secondary }}>
                {t("noActivity")}
              </p>
            </motion.div>
          ) : (
            <div className="space-y-3">
              {activities.map((activity, idx) => {
                const color = getActivityColor(activity.type);
                const timeAgo = formatTimeAgo(activity.time, t);

                const href = typeof activity.link === "string" && activity.link.trim() ? activity.link : null;
                return (
                  <div key={activity.id + "-" + idx}>
                  {href ? (
                  <Link href={href}>
                    <motion.div
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: idx * 0.05 }}
                      whileHover={{ scale: 1.02, x: 5 }}
                      className="flex items-start gap-3 p-3.5 rounded-2xl transition-all cursor-pointer group mb-3"
                      style={{
                        background: isDark ? "rgba(255, 255, 255, 0.03)" : "rgba(0, 0, 0, 0.02)",
                        border: `1px solid ${isDark ? "rgba(255, 255, 255, 0.05)" : "rgba(0, 0, 0, 0.05)"}`,
                      }}
                    >
                      <div
                        className="w-10 h-10 rounded-xl flex items-center justify-center shrink-0 text-white shadow-lg shadow-blue-500/10"
                        style={{ background: `linear-gradient(135deg, ${color}, ${color}dd)` }}
                      >
                        {getActivityIcon(activity.type)}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-baseline justify-between gap-2">
                          <p className="text-sm font-bold truncate leading-tight mb-0.5" style={{ color: textColors.primary }}>
                            {activity.message}
                          </p>
                          <span className="text-[10px] font-medium whitespace-nowrap opacity-60" style={{ color: textColors.secondary }}>
                            {timeAgo}
                          </span>
                        </div>
                        <p className="text-xs opacity-70 truncate line-clamp-1 mb-0.5" style={{ color: textColors.secondary }}>
                          {activity.subtext}
                        </p>
                        {activity.group && (
                          <span className="text-[10px] px-1.5 py-0.5 rounded-md bg-white/5 border border-white/10" style={{ color: textColors.secondary }}>
                            {activity.group}
                          </span>
                        )}
                      </div>
                      <ChevronRight className="w-4 h-4 opacity-0 group-hover:opacity-40 transition-opacity self-center" />
                    </motion.div>
                  </Link>
                  ) : (
                    <motion.div
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: idx * 0.05 }}
                      className="flex items-start gap-3 p-3.5 rounded-2xl transition-all mb-3"
                      style={{
                        background: isDark ? "rgba(255, 255, 255, 0.03)" : "rgba(0, 0, 0, 0.02)",
                        border: `1px solid ${isDark ? "rgba(255, 255, 255, 0.05)" : "rgba(0, 0, 0, 0.05)"}`,
                      }}
                    >
                      <div
                        className="w-10 h-10 rounded-xl flex items-center justify-center shrink-0 text-white shadow-lg shadow-blue-500/10"
                        style={{ background: `linear-gradient(135deg, ${color}, ${color}dd)` }}
                      >
                        {getActivityIcon(activity.type)}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-baseline justify-between gap-2">
                          <p className="text-sm font-bold truncate leading-tight mb-0.5" style={{ color: textColors.primary }}>
                            {activity.message}
                          </p>
                          <span className="text-[10px] font-medium whitespace-nowrap opacity-60" style={{ color: textColors.secondary }}>
                            {timeAgo}
                          </span>
                        </div>
                        <p className="text-xs opacity-70 truncate line-clamp-1 mb-0.5" style={{ color: textColors.secondary }}>
                          {activity.subtext}
                        </p>
                        {activity.group && (
                          <span className="text-[10px] px-1.5 py-0.5 rounded-md bg-white/5 border border-white/10" style={{ color: textColors.secondary }}>
                            {activity.group}
                          </span>
                        )}
                      </div>
                    </motion.div>
                  )}
                  </div>
                );
              })}
            </div>
          )}
        </AnimatePresence>

        <Link
          href={teacherMode ? teacherReviewHref : "/app"}
          className="mt-4 flex items-center justify-center w-full py-3 rounded-2xl font-bold text-sm transition-all bg-blue-500/10 hover:bg-blue-500/20 text-blue-500 group"
        >
          {t("viewAll")}
          <ChevronRight className="w-4 h-4 ml-1 group-hover:translate-x-1 transition-transform" />
        </Link>
      </div>
    </motion.div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { Bot, Send, X } from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";
import { api } from "@/api/client";
import { useAuthStore } from "@/store/authStore";

export function AiAssistantWidget() {
  const { t, lang } = useLanguage();
  const userId = useAuthStore((s) => s.user?.id);
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState<Array<{ role: "user" | "bot"; text: string }>>([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const scrollRefDesktop = useRef<HTMLDivElement>(null);
  const scrollRefMobile = useRef<HTMLDivElement>(null);

  const STORAGE_KEY = "ai-chat-history";

  // Load history
  useEffect(() => {
    if (typeof window !== "undefined") {
      const key = userId ? `${STORAGE_KEY}-${userId}` : `${STORAGE_KEY}-guest`;
      const saved = localStorage.getItem(key);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          if (Array.isArray(parsed) && parsed.length > 0) {
            setMessages(parsed);
          }
        } catch (e) {}
      }
    }
  }, [userId]);

  // Save history
  useEffect(() => {
    if (typeof window !== "undefined" && messages.length > 0) {
      const key = userId ? `${STORAGE_KEY}-${userId}` : `${STORAGE_KEY}-guest`;
      localStorage.setItem(key, JSON.stringify(messages.slice(-50)));
    }
  }, [messages, userId]);

  useEffect(() => {
    scrollRefDesktop.current?.scrollTo(0, scrollRefDesktop.current.scrollHeight);
    scrollRefMobile.current?.scrollTo(0, scrollRefMobile.current.scrollHeight);
  }, [messages]);

  const send = async () => {
    const text = input.trim();
    if (!text || loading) return;
    setInput("");
    setMessages((m) => [...m, { role: "user", text }]);
    setLoading(true);
    try {
      const { data } = await api.post<{ response: string }>("/ai/chat", { message: text }, { params: { lang } });
      setMessages((m) => [...m, { role: "bot", text: data.response }]);
    } catch {
      setMessages((m) => [...m, { role: "bot", text: t("aiError") }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="lg:w-80 shrink-0">
      <div
        className="rounded-[20px] overflow-hidden shadow-lg border border-gray-200/80 dark:border-gray-700"
        style={{
          background: "linear-gradient(135deg, rgba(26,35,126,0.08) 0%, rgba(255,64,129,0.08) 100%)",
        }}
      >
        <div
          className="p-4 text-white flex items-center justify-between"
          style={{ background: "var(--qit-gradient-banner)" }}
        >
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 rounded-xl flex items-center justify-center bg-white/20">
              <Bot className="w-5 h-5" />
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h3 className="font-bold text-sm">{t("aiAssistant")}</h3>
                <span className="text-[9px] bg-white/20 px-1 py-0.5 rounded uppercase tracking-wider font-bold">
                  AI
                </span>
              </div>
              <span className="text-xs text-white/80">{t("askAiHomework")}</span>
            </div>
          </div>
          <button
            type="button"
            onClick={() => setOpen(!open)}
            className="p-1.5 hover:bg-white/20 rounded-lg transition-colors lg:hidden"
            aria-label={open ? t("aiClose") : t("aiOpen")}
          >
            {open ? <X className="w-5 h-5" /> : <span className="text-xs bg-white/20 px-2 py-0.5 rounded">{t("aiOpen")}</span>}
          </button>
        </div>

        {/* Desktop: always show full widget */}
        <div className="hidden lg:block">
          <div ref={scrollRefDesktop} className="h-48 overflow-auto p-4 space-y-3 bg-white/50 dark:bg-gray-800/30">
              {messages.length === 0 && (
                <p className="text-gray-600 dark:text-gray-400 text-sm">
                  {t("aiWelcomeLong")}
                </p>
              )}
              {messages.map((msg, i) => (
                <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
                  <div
                    className={`max-w-[90%] rounded-xl px-3 py-2 text-sm ${
                      msg.role === "user"
                        ? "text-white"
                        : "bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-200"
                    }`}
                    style={msg.role === "user" ? { background: "var(--qit-gradient-3)" } : undefined}
                  >
                    {msg.text}
                  </div>
                </div>
              ))}
              {loading && (
                <div className="flex justify-start">
                  <div className="bg-gray-100 dark:bg-gray-700 rounded-xl px-3 py-2 text-sm text-gray-500">
                    {t("aiAnswerLoading")}
                  </div>
                </div>
              )}
            </div>
            <div className="p-3 border-t border-gray-200/80 dark:border-gray-700 flex gap-2">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && send()}
                placeholder={t("aiQuestionPlaceholder")}
                className="flex-1 border border-gray-200 dark:border-gray-600 rounded-xl px-3 py-2 text-sm bg-white dark:bg-gray-800 focus:ring-2 focus:ring-[#ff4081]/30 focus:border-[#ff4081]"
              />
              <button
                type="button"
                onClick={send}
                disabled={loading || !input.trim()}
                className="p-2 rounded-xl text-white disabled:opacity-50 transition-opacity"
                style={{ background: "var(--qit-gradient-3)" }}
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>

        {/* Mobile: collapsed by default, expand on click */}
        <div className="lg:hidden">
            {open && (
            <>
              <div ref={scrollRefMobile} className="h-40 overflow-auto p-4 space-y-3 bg-white/50 dark:bg-gray-800/30">
                {messages.length === 0 && (
                  <p className="text-gray-600 dark:text-gray-400 text-sm">{t("aiWelcomeShort")}</p>
                )}
                {messages.map((msg, i) => (
                  <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
                    <div
                      className={`max-w-[90%] rounded-xl px-3 py-2 text-sm ${
                        msg.role === "user" ? "text-white" : "bg-gray-100 dark:bg-gray-700"
                      }`}
                      style={msg.role === "user" ? { background: "var(--qit-gradient-3)" } : undefined}
                    >
                      {msg.text}
                    </div>
                  </div>
                ))}
                {loading && (
                  <div className="flex justify-start">
                    <div className="bg-gray-100 dark:bg-gray-700 rounded-xl px-3 py-2 text-sm text-gray-500">
                      {t("aiAnswerLoading")}
                    </div>
                  </div>
                )}
              </div>
              <div className="p-3 border-t border-gray-200/80 flex gap-2">
                <input
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && send()}
                  placeholder={t("aiQuestionPlaceholder")}
                  className="flex-1 border border-gray-200 rounded-xl px-3 py-2 text-sm"
                />
                <button
                  type="button"
                  onClick={send}
                  disabled={loading || !input.trim()}
                  className="p-2 rounded-xl text-white disabled:opacity-50"
                  style={{ background: "var(--qit-gradient-3)" }}
                >
                  <Send className="w-4 h-4" />
                </button>
              </div>
            </>
          )}
          {!open && (
            <button
              type="button"
              onClick={() => setOpen(true)}
              className="w-full p-4 flex items-center justify-center gap-2 text-gray-600 dark:text-gray-400 hover:bg-white/30 dark:hover:bg-gray-700/30 transition-colors"
            >
              <Bot className="w-5 h-5" style={{ color: "var(--qit-accent)" }} />
              <span className="text-sm font-medium">{t("askAiHomework")}</span>
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

