"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import {
  LayoutDashboard,
  BookOpen,
  Library,
  Calendar,
  Settings,
  Menu,
  ChevronDown,
  Bell,
  User,
  LogOut,
  Trophy,
  ShoppingBag,
  Users,
  MessageCircle,
  Globe,
  Sun,
  Moon,
  PanelLeftClose,
  Sparkles,
  FileText,
  Activity,
  BarChart3,
  Star,
  Grid3x3,
  FileQuestion,
  ShieldCheck,
  ArrowRight,
  Zap,
  X,
  LifeBuoy,
} from "lucide-react";
import { useAuthStore } from "@/store/authStore";
import { useTheme } from "@/context/ThemeContext";
import { useSidebar } from "@/context/SidebarContext";
import { useNotifications } from "@/hooks/useNotifications";
import { useLanguage } from "@/context/LanguageContext";
import { useState, useEffect, useRef } from "react";
import { api } from "@/api/client";
import { getLocalizedNotificationText } from "@/lib/notificationText";
import { useQuery, useQueryClient } from "@tanstack/react-query";

export function AppDashboardSidebar() {
  const { user, logout, isAdmin, isTeacher, canManageUsers } = useAuthStore();
  const queryClient = useQueryClient();
  const router = useRouter();
  const pathname = usePathname();
  const { t, lang, setLang } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const { collapsed, toggle, width, mobileOpen, setMobileOpen } = useSidebar();
  const { data: notifications = [], refetch } = useNotifications();
  const [notifOpen, setNotifOpen] = useState(false);
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const [langOpen, setLangOpen] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);
  const langRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!notifOpen) return;
    const close = (e: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(e.target as Node))
        setNotifOpen(false);
    };
    document.addEventListener("click", close);
    return () => document.removeEventListener("click", close);
  }, [notifOpen]);

  useEffect(() => {
    if (!userMenuOpen) return;
    const close = (e: MouseEvent) => {
      if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node))
        setUserMenuOpen(false);
    };
    document.addEventListener("click", close);
    return () => document.removeEventListener("click", close);
  }, [userMenuOpen]);

  useEffect(() => {
    if (!langOpen) return;
    const close = (e: MouseEvent) => {
      if (langRef.current && !langRef.current.contains(e.target as Node))
        setLangOpen(false);
    };
    document.addEventListener("click", close);
    return () => document.removeEventListener("click", close);
  }, [langOpen]);

  useEffect(() => {
    if (!mobileOpen) return;
    const prevOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    const onEsc = (e: KeyboardEvent) => {
      if (e.key === "Escape") setMobileOpen(false);
    };
    document.addEventListener("keydown", onEsc);
    return () => {
      document.body.style.overflow = prevOverflow;
      document.removeEventListener("keydown", onEsc);
    };
  }, [mobileOpen, setMobileOpen]);

  const unread = notifications.filter((n) => !n.is_read);

  const markRead = (notificationId: number, link?: string) => {
    api.put(`/notifications/${notificationId}/read`).then(() => {
      refetch();
      setNotifOpen(false);
      if (link) router.push(link);
    });
  };

  const markAllRead = () => {
    api.post("/notifications/read-all").then(() => {
      refetch();
    });
  };

  const navLinkClass = (href: string) => {
    const isActive =
      href === "/app"
        ? pathname === "/app" || pathname === "/app/"
        : href === "/app/teacher"
          ? pathname === "/app/teacher" || pathname === "/app/teacher/"
          : pathname === href || (href !== "/app" && pathname.startsWith(href + "/"));
    if (isActive) {
      return "flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 text-white font-medium";
    }
    return `flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 ${
      theme === "dark" 
        ? "text-white/70 hover:text-white hover:bg-white/10" 
        : "text-gray-700 hover:text-gray-900 hover:bg-gray-100"
    }`;
  };

  const navLinkStyle = (href: string, isPremiumLink?: boolean) => {
    const isActive =
      href === "/app"
        ? pathname === "/app" || pathname === "/app/"
        : href === "/app/teacher"
          ? pathname === "/app/teacher" || pathname === "/app/teacher/"
          : pathname === href || (href !== "/app" && pathname.startsWith(href + "/"));
    if (!isActive) return undefined;
    if (isPremiumLink) {
      return { background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)", boxShadow: "0 0 12px rgba(255, 65, 129, 0.4)" };
    }
    return { background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)", boxShadow: "0 0 12px rgba(255, 65, 129, 0.3)" };
  };

  const isApproved = user?.is_approved !== false;
  const isParent = user?.role === "parent";
  const isStudentWithoutGroup = user?.role === "student" && !user?.has_group_access;

  const mainLinks = isApproved
    ? isParent
      ? [
          { href: "/app", icon: LayoutDashboard, label: t("dashboard") },
          { href: "/app/parent-rating", icon: Trophy, label: t("rating") },
        ]
      : isStudentWithoutGroup
        ? [
          { href: "/app", icon: LayoutDashboard, label: t("dashboard") },
          { href: "/app/support", icon: LifeBuoy, label: t("studentSupportTitle") },
        ]
        : [
          { href: "/app", icon: LayoutDashboard, label: t("dashboard") },
          ...(isTeacher() ? [] : [
            ...(user?.role === "student" ? [] : [{ href: "/app/courses", icon: Library, label: t("courseCatalog") }]),
            { href: "/app/analytics", icon: BarChart3, label: t("studentAnalytics") },
          ]),
          { href: "/app/ai-challenge/1", icon: Zap, label: t("aiVsStudent") },
          { href: "/app/shop", icon: ShoppingBag, label: t("shop") },
          { href: "/app/leaderboard", icon: Trophy, label: t("rating") },
          { href: "/app/community", icon: MessageCircle, label: t("communitySidebarLink") },
          ...(user?.role === "student" ? [{ href: "/app/support", icon: LifeBuoy, label: t("studentSupportTitle") }] : []),
        ]
    : [{ href: "/app", icon: LayoutDashboard, label: t("dashboard") }];

  const extraLinksBeforeManager = isApproved
    ? isStudentWithoutGroup
      ? [
        { href: "/app/premium", icon: Sparkles, label: t("premiumTab"), isPremium: true },
        { href: "/app/profile", icon: Settings, label: t("settings") },
      ]
      : [
        // Premium показывается только для студентов (не для учителей, директора, админа, куратора, родителя)
        ...(user?.role === "student" ? [{ href: "/app/premium", icon: Sparkles, label: t("premiumTab"), isPremium: true }] : []),
        ...(isTeacher() ? [{ href: "/app/teacher", icon: Users, label: t("teacherDashboardSidebar") }] : []),
        ...(isAdmin() || isTeacher() || user?.role === "curator" ? [{ href: "/app/people", icon: Users, label: t("peopleList") }] : []),
        { href: "/app/profile", icon: Settings, label: t("settings") },
        ...(user?.role === "curator" ? [
          { href: "/app/admin/courses", icon: BookOpen, label: t("adminNavCourses") },
          { href: "/app/admin/analytics", icon: BarChart3, label: t("adminNavAnalytics") },
          { href: "/app/admin/support", icon: LifeBuoy, label: t("adminNavSupport") },
        ] : []),
      ]
    : [];

  // Curator links are now merged into extraLinksBeforeManager
  const curatorLinks: any[] = [];

  // Меню для администраторов и директоров (полный доступ)
  const managerLinks = canManageUsers() ? [
    { href: "/app/admin/users", icon: Users, label: t("adminNavUsers") },
    { href: "/app/admin/courses", icon: BookOpen, label: t("adminNavCourses") },
    { href: "/app/admin/overview", icon: Activity, label: t("adminNavProcesses") },
    { href: "/app/admin/analytics", icon: BarChart3, label: t("adminNavAnalytics") },
    { href: "/app/admin/reviews", icon: Star, label: t("adminNavReviews") },
    { href: "/app/admin/shop", icon: ShoppingBag, label: t("adminShopPurchases") },
    { href: "/app/admin/support", icon: LifeBuoy, label: t("adminNavSupport") },
  ] : [];

  const NavContent = ({ compact = false }: { compact?: boolean }) => {
    const isManagerSectionActive = pathname.startsWith("/app/admin");


    const { data: teacherGroups = [] } = useQuery({
      queryKey: ["teacher-groups-sidebar"],
      queryFn: async () => {
        const res = await api.get("/teacher/groups");
        return res.data as { id: number; group_name: string }[];
      },
      enabled: isTeacher() && !compact,
    });

    return (
      <>
        <nav className="flex-1 overflow-y-auto py-4 px-2 space-y-1 min-h-0 custom-scrollbar">
          {/* User Profile Section for Mobile Drawer removed per request */}

          {mainLinks.map(({ href, icon: Icon, label }) => (
            <Link
              key={href}
              href={href}
              onClick={() => setMobileOpen(false)}
              className={`${navLinkClass(href)} ${compact ? "justify-center px-2" : "px-4"}`}
              style={navLinkStyle(href)}
              title={compact ? label : undefined}
            >
              <Icon className="w-5 h-5 shrink-0" />
              {!compact && <span className="text-sm font-semibold">{label}</span>}
            </Link>
          ))}

          {/* Teacher Courses Section */}
          {!compact && isTeacher() && (
            <div className={`pt-4 mt-4 border-t ${theme === "dark" ? "border-white/10" : "border-gray-100"}`}>
              <Link
                href="/app/teacher/courses"
                onClick={() => setMobileOpen(false)}
                className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all duration-200 ${
                  pathname === "/app/teacher/courses"
                    ? "bg-gradient-to-r from-[#FF4181] to-[#B938EB] text-white font-semibold shadow-lg shadow-[#FF4181]/30"
                    : theme === "dark"
                      ? "text-white/70 hover:text-white hover:bg-white/10"
                      : "text-gray-700 hover:text-gray-900 hover:bg-gray-100"
                }`}
              >
                <span className="text-sm font-semibold">{t("teacherCoursesTabHint")}</span>
                <BookOpen className="w-4 h-4 shrink-0" />
              </Link>
            </div>
          )}

          {/* Student: courses I take (same style as teacher) */}
          {!compact && user?.role === "student" && user?.has_group_access && (
            <div className={`pt-4 mt-4 border-t ${theme === "dark" ? "border-white/10" : "border-gray-100"}`}>
              <Link
                href="/app/courses"
                onClick={() => setMobileOpen(false)}
                className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all duration-200 ${
                  pathname === "/app/courses" || pathname.startsWith("/app/courses/")
                    ? "bg-gradient-to-r from-[#FF4181] to-[#B938EB] text-white font-semibold shadow-lg shadow-[#FF4181]/30"
                    : theme === "dark"
                      ? "text-white/70 hover:text-white hover:bg-white/10"
                      : "text-gray-700 hover:text-gray-900 hover:bg-gray-100"
                }`}
              >
                <span className="text-sm font-semibold">{t("studentCoursesTabHint")}</span>
                <BookOpen className="w-4 h-4 shrink-0" />
              </Link>
            </div>
          )}

          {extraLinksBeforeManager.length > 0 && (
            <div className={`pt-4 mt-4 border-t ${theme === "dark" ? "border-white/10" : "border-gray-100"}`}>
               {!compact && <p className="px-4 text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-2">{t("more")}</p>}
              {extraLinksBeforeManager.map(({ href, icon: Icon, label, isPremium }) => (
                <Link
                  key={href}
                  href={href}
                  onClick={() => setMobileOpen(false)}
                  className={`${navLinkClass(href)} ${compact ? "justify-center px-2" : "px-4"}`}
                  style={navLinkStyle(href, isPremium)}
                  title={compact ? label : undefined}
                >
                  <Icon className="w-5 h-5 shrink-0" />
                  {!compact && <span className="text-sm font-semibold">{label}</span>}
                </Link>
              ))}
            </div>
          )}
          {curatorLinks.length > 0 && (
            <>
              <div className={`pt-4 mt-4 border-t ${theme === "dark" ? "border-white/20" : "border-gray-200"}`}></div>
              <div className="pt-4 px-3">
                <div className="flex items-center gap-3 mb-2">
                  <Grid3x3 className={`w-5 h-5 shrink-0 ${theme === "dark" ? "text-white" : "text-gray-700"}`} />
                  {!compact && <span className={`font-medium text-sm ${theme === "dark" ? "text-white" : "text-gray-700"}`}>{t("admin")}</span>}
                </div>
                <div className="space-y-1 mt-2">
                  {curatorLinks.map(({ href, icon: Icon, label }) => {
                    const isActive = pathname === href || pathname.startsWith(href + "/");
                    return (
                      <Link
                        key={href}
                        href={href}
                        onClick={() => setMobileOpen(false)}
                        className={`flex items-center gap-3 px-3 py-2.5 rounded-lg transition-all duration-200 ${
                          isActive
                            ? "text-white font-medium"
                            : theme === "dark"
                              ? "text-white/70 hover:text-white hover:bg-white/10"
                              : "text-gray-700 hover:text-gray-900 hover:bg-gray-100"
                        } ${compact ? "justify-center px-2" : ""}`}
                        style={isActive ? { background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)", boxShadow: "0 0 12px rgba(255, 65, 129, 0.3)" } : undefined}
                        title={compact ? label : undefined}
                      >
                        <Icon className="w-5 h-5 shrink-0" />
                        {!compact && <span>{label}</span>}
                      </Link>
                    );
                  })}
                </div>
              </div>
            </>
          )}
          {managerLinks.length > 0 && (
            <>
              <div className={`pt-4 mt-4 border-t ${theme === "dark" ? "border-white/20" : "border-gray-200"}`}></div>
              <div className="pt-4 px-3">
                <div className="flex items-center gap-3 mb-2">
                  <Grid3x3 className={`w-5 h-5 shrink-0 ${theme === "dark" ? "text-white" : "text-gray-700"}`} />
                  {!compact && <span className={`font-medium text-sm ${theme === "dark" ? "text-white" : "text-gray-700"}`}>{t("admin")}</span>}
                </div>
                <div className="space-y-1 mt-2">
                  {managerLinks.map(({ href, icon: Icon, label }) => {
                    const isActive = pathname === href || pathname.startsWith(href + "/");
                    return (
                      <Link
                        key={href}
                        href={href}
                        onClick={() => setMobileOpen(false)}
                        className={`flex items-center gap-3 px-3 py-2.5 rounded-lg transition-all duration-200 ${
                          isActive
                            ? "text-white font-medium"
                            : theme === "dark"
                              ? "text-white/70 hover:text-white hover:bg-white/10"
                              : "text-gray-700 hover:text-gray-900 hover:bg-gray-100"
                        } ${compact ? "justify-center px-2" : ""}`}
                        style={isActive ? { background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)", boxShadow: "0 0 12px rgba(255, 65, 129, 0.3)" } : undefined}
                        title={compact ? label : undefined}
                      >
                        <Icon className="w-5 h-5 shrink-0" />
                        {!compact && <span>{label}</span>}
                      </Link>
                    );
                  })}
                </div>
              </div>
            </>
          )}
        </nav>

        {/* Mobile Utility Sections */}
        {(!compact || mobileOpen) && (
          <div className="lg:hidden px-3 pb-6 space-y-4">
            <div className={`pt-4 border-t ${theme === "dark" ? "border-white/10" : "border-gray-100"}`}>
               <p className="px-4 text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-2">
                 {t("language")}
               </p>
               <div className="grid grid-cols-3 gap-1 px-2">
                 {(["ru", "kk", "en"] as const).map((l) => (
                   <button
                     key={l}
                     type="button"
                     onClick={() => setLang(l)}
                     className={`py-2 rounded-lg text-xs font-bold transition-all ${
                       lang === l
                         ? "bg-[var(--qit-primary)] text-white shadow-md shadow-[var(--qit-primary)]/20"
                         : "bg-gray-50 dark:bg-gray-800/50 text-gray-600 dark:text-gray-400"
                     }`}
                   >
                     {l.toUpperCase()}
                   </button>
                 ))}
               </div>
            </div>

            <div className="px-2">
              <button
                type="button"
                onClick={toggleTheme}
                className="w-full flex items-center justify-between px-4 py-3 rounded-xl bg-gray-50 dark:bg-gray-800/50 text-gray-700 dark:text-gray-200 transition-all font-medium active-tap"
              >
                <div className="flex items-center gap-3">
                  {theme === "light" ? <Moon className="w-5 h-5" /> : <Sun className="w-5 h-5" />}
                  <span className="text-sm">{theme === "light" ? t("darkTheme") : t("lightTheme")}</span>
                </div>
                <div className={`w-8 h-4 rounded-full relative transition-colors ${theme === "dark" ? "bg-[var(--qit-secondary)]" : "bg-gray-300"}`}>
                  <div className={`absolute top-1 w-2 h-2 rounded-full bg-white transition-all ${theme === "dark" ? "right-1" : "left-1"}`} />
                </div>
              </button>
            </div>

            <div className="px-2">
              <button
                type="button"
                onClick={() => {
                  queryClient.clear();
                  logout();
                  router.push("/");
                }}
                className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/10 font-bold text-sm active-tap"
              >
                <LogOut className="w-5 h-5" />
                <span>{t("logout")}</span>
              </button>
            </div>
          </div>
        )}
      </>
    );
  };

  return (
    <>
      {/* Desktop sidebar */}
      <aside
        className="hidden lg:flex fixed left-0 top-0 z-40 h-screen flex-col shrink-0 transition-all duration-300 ease-in-out overflow-hidden shadow-lg"
        style={{ 
          background: theme === "dark" ? "#0B0F19" : "#FFFFFF", 
          width: width,
          borderRight: theme === "dark" ? "1px solid rgba(255, 255, 255, 0.08)" : "1px solid rgba(0, 0, 0, 0.08)"
        }}
      >
        <div className={`flex items-center justify-between h-16 px-3 shrink-0 border-b min-w-0 ${theme === "dark" ? "border-white/10" : "border-gray-200"}`}>
          <button
            type="button"
            onClick={toggle}
            className={`flex items-center gap-2 font-semibold text-lg hover:opacity-90 transition-opacity w-full min-w-0 ${theme === "dark" ? "text-white" : "text-gray-900"}`}
            title={collapsed ? t("openMenu") : t("closeMenu")}
          >
            <div
              className="w-9 h-9 rounded-xl flex items-center justify-center text-white font-bold text-sm shrink-0 animate-[spin_3s_linear_infinite]"
              style={{ background: "var(--qit-gradient-3)" }}
            >
              Q
            </div>
            {!collapsed && <span className="whitespace-nowrap">{t("platformName")}</span>}
          </button>
          {!collapsed && (
            <button
              type="button"
              onClick={toggle}
              className={`p-2 rounded-lg shrink-0 ${
                theme === "dark"
                  ? "text-white/70 hover:text-white hover:bg-white/10"
                  : "text-gray-600 hover:text-gray-900 hover:bg-gray-100"
              }`}
              title={t("closeMenu")}
              aria-label={t("closeMenu")}
            >
              <PanelLeftClose className="w-5 h-5" />
            </button>
          )}
        </div>
        <div className="flex-1 flex flex-col min-h-0">
          <NavContent compact={collapsed} />
        </div>
      </aside>

      {/* Mobile header - Simplified */}
      <header className="lg:hidden fixed top-0 left-0 right-0 z-50 h-16 flex items-center justify-between px-4 glass-nav">
        <button
          type="button"
          onClick={() => setMobileOpen(!mobileOpen)}
          className="p-2 -ml-2 rounded-xl active-tap text-gray-700 dark:text-white bg-white/50 dark:bg-white/10"
          aria-label={t("openMenu")}
          aria-expanded={mobileOpen}
          aria-controls="mobile-main-menu"
        >
          <Menu className="w-6 h-6" />
        </button>

        <Link href="/app" className="flex items-center gap-2 group">
          <div
            className="w-9 h-9 rounded-xl flex items-center justify-center text-white font-bold text-sm shadow-lg group-active:scale-95 transition-transform"
            style={{ background: "var(--qit-gradient-3)" }}
          >
            Q
          </div>
          <span className="max-w-[42vw] truncate font-bold text-gray-900 dark:text-white tracking-tight">
            {t("platformName")}
          </span>
        </Link>

        <div className="flex items-center">
          <div className="relative" ref={notifRef}>
            <button
              type="button"
              onClick={() => setNotifOpen(!notifOpen)}
              className="p-2 -mr-2 rounded-xl active-tap text-gray-700 dark:text-white"
            >
              <div className="relative">
                <Bell className="w-6 h-6" />
                {unread.length > 0 && (
                  <span className="absolute -top-1 -right-1 min-w-[18px] h-[18px] px-1 text-[10px] bg-red-500 text-white rounded-full flex items-center justify-center border-2 border-white dark:border-gray-900">
                    {unread.length > 9 ? "9+" : unread.length}
                  </span>
                )}
              </div>
            </button>
            {notifOpen && (
              <div className="absolute right-0 top-full mt-2 w-[min(20rem,calc(100vw-1.5rem))] max-w-[calc(100vw-2rem)] rounded-2xl shadow-2xl z-50 max-h-96 overflow-auto bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700">
                <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between sm:gap-3 sticky top-0 bg-inherit z-10">
                  <div className="flex items-center gap-2 min-w-0">
                    <h3 className="font-bold text-sm shrink-0">{t("notifications")}</h3>
                    {unread.length > 0 && (
                      <span className="text-[10px] px-2 py-0.5 rounded-full bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 font-bold uppercase shrink-0">
                        {t("newBadge")}
                      </span>
                    )}
                  </div>
                  {unread.length > 0 && (
                    <button
                      type="button"
                      onClick={(e) => {
                        e.stopPropagation();
                        markAllRead();
                      }}
                      className="text-[10px] sm:text-xs font-semibold text-[var(--qit-primary)] dark:text-[var(--qit-secondary)] hover:underline text-left sm:text-right leading-snug whitespace-normal w-full sm:w-auto sm:max-w-[12.5rem]"
                    >
                      {t("markAllAsRead")}
                    </button>
                  )}
                </div>
                {notifications.length === 0 ? (
                  <div className="p-8 text-center">
                    <Bell className="w-8 h-8 text-gray-300 mx-auto mb-2" />
                    <p className="text-xs text-gray-500 dark:text-gray-400">
                      {t("noNotifications")}
                    </p>
                  </div>
                ) : (
                  notifications.slice(0, 15).map((n) => {
                    const { title, message } = getLocalizedNotificationText(n, t);
                    return (
                      <button
                        key={n.id}
                        type="button"
                        onClick={() => markRead(n.id, n.link)}
                        className={`w-full text-left px-4 py-3 border-b border-gray-100 dark:border-gray-700 last:border-0 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors ${!n.is_read ? "bg-[var(--qit-primary)]/5 dark:bg-[var(--qit-primary)]/10" : ""}`}
                      >
                        <p className="font-bold text-xs text-gray-900 dark:text-gray-200 mb-0.5">{title}</p>
                        <p className="text-[11px] text-gray-600 dark:text-gray-400 line-clamp-2 leading-relaxed">
                          {message}
                        </p>
                      </button>
                    );
                  })
                )}
              </div>
            )}
          </div>
        </div>
      </header>

      {/* Mobile overlay menu */}
      {mobileOpen && (
        <div
          className="lg:hidden fixed inset-0 z-40 bg-black/50"
          onClick={() => setMobileOpen(false)}
          aria-hidden
        />
      )}
      <aside
        id="mobile-main-menu"
        className={`lg:hidden fixed top-0 left-0 z-50 h-full w-[min(18rem,85vw)] flex flex-col transition-transform duration-300 shadow-xl ${mobileOpen ? "translate-x-0" : "-translate-x-full"
          }`}
        style={{ 
          background: theme === "dark" ? "#0B0F19" : "#FFFFFF",
          borderRight: theme === "dark" ? "1px solid rgba(255, 255, 255, 0.08)" : "1px solid rgba(0, 0, 0, 0.08)"
        }}
      >
        <div className="flex items-center justify-between h-16 px-5 border-b border-gray-100 dark:border-gray-800 min-w-0">
           <div className="flex items-center gap-2 min-w-0">
              <div className="w-8 h-8 shrink-0 rounded-lg flex items-center justify-center text-white font-bold text-xs" style={{ background: "var(--qit-gradient-3)" }}>Q</div>
              <span className="font-bold text-sm truncate">{t("platformName")}</span>
           </div>
          <button type="button" onClick={() => setMobileOpen(false)} className="p-2.5 -mr-2 rounded-xl active-tap text-gray-400 bg-gray-50 dark:bg-white/5 border border-gray-100 dark:border-white/10 shadow-sm">
            <X className="w-5 h-5" />
          </button>
        </div>
        <NavContent compact={false} />
      </aside>
    </>
  );
}

"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import {
  BookOpen,
  User,
  Trophy,
  Bell,
  LogOut,
  LayoutDashboard,
  Calendar,
  Users,
  Baby,
  Zap,
  Menu,
  ChevronDown,
  ShoppingBag,
} from "lucide-react";
import { useAuthStore } from "@/store/authStore";
import { useQueryClient } from "@tanstack/react-query";
import { useNotifications } from "@/hooks/useNotifications";
import { useLanguage } from "@/context/LanguageContext";
import { AppHeader } from "@/components/common/AppHeader";
import { useState, useEffect, useRef } from "react";
import { api } from "@/api/client";
import { getLocalizedNotificationText } from "@/lib/notificationText";
import { cn } from "@/lib/utils";
import { formatLocalizedDate } from "@/utils/dateUtils";

export function AppTopNav() {
  const { user, logout, isAdmin, isTeacher } = useAuthStore();
  const queryClient = useQueryClient();
  const router = useRouter();
  const pathname = usePathname();
  const { t, lang } = useLanguage();
  const { data: notifications = [], refetch } = useNotifications();
  const [notifOpen, setNotifOpen] = useState(false);
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!notifOpen) return;
    const close = (e: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(e.target as Node))
        setNotifOpen(false);
    };
    document.addEventListener("click", close);
    return () => document.removeEventListener("click", close);
  }, [notifOpen]);

  useEffect(() => {
    if (!userMenuOpen) return;
    const close = (e: MouseEvent) => {
      if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node))
        setUserMenuOpen(false);
    };
    document.addEventListener("click", close);
    return () => document.removeEventListener("click", close);
  }, [userMenuOpen]);

  const unread = notifications.filter((n) => !n.is_read);

  const markRead = (notificationId: number, link?: string) => {
    api.put(`/notifications/${notificationId}/read`).then(() => {
      refetch();
      setNotifOpen(false);
      if (link) router.push(link);
    });
  };

  const markAllRead = () => {
    api.post("/notifications/read-all").then(() => {
      refetch();
    });
  };

  const navLinkClass = (href: string) => {
    const isActive =
      href === "/app"
        ? pathname === "/app" || pathname === "/app/"
        : pathname === href || pathname.startsWith(href + "/");
    return `flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
      isActive
        ? "bg-[var(--qit-primary)]/10 text-[var(--qit-primary)] dark:text-[var(--qit-secondary)]"
        : "text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 hover:text-gray-900 dark:hover:text-white"
    }`;
  };

  return (
    <header className="sticky top-0 z-40 bg-white/95 dark:bg-gray-900/95 backdrop-blur-md border-b border-gray-200 dark:border-gray-700 shadow-sm">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <Link
            href="/app"
            className="flex items-center gap-2 text-[var(--qit-primary)] dark:text-[var(--qit-secondary)] hover:opacity-90 transition-opacity shrink-0"
          >
            <div
              className="w-9 h-9 rounded-xl flex items-center justify-center text-white font-bold text-sm shrink-0 aspect-square"
              style={{ background: "var(--qit-gradient-1)" }}
            >
              Q
            </div>
            <span className="font-semibold text-lg hidden sm:inline">
              {t("platformName")}
            </span>
          </Link>

          <nav className="hidden md:flex items-center gap-1">
            <Link href="/app/courses" className={navLinkClass("/app/courses")}>
              <BookOpen className="w-4 h-4 shrink-0" />
              {t("courses")}
            </Link>
            <Link href="/app/leaderboard" className={navLinkClass("/app/leaderboard")}>
              <Trophy className="w-4 h-4 shrink-0" />
              {t("rating")}
            </Link>
            <Link href="/app/tasks-calendar" className={navLinkClass("/app/tasks-calendar")}>
              <Calendar className="w-4 h-4 shrink-0" />
              {t("tasksCalendar")}
            </Link>
            <Link href="/app#ai-challenge" className={navLinkClass("/app")}>
              <Zap className="w-4 h-4 shrink-0" />
              {t("aiVsStudent")}
            </Link>
            <Link href="/app/shop" className={navLinkClass("/app/shop")}>
              <ShoppingBag className="w-4 h-4 shrink-0" />
              {t("shop")}
            </Link>
            {isTeacher() && (
              <Link href="/app/teacher" className={navLinkClass("/app/teacher")}>
                <Users className="w-4 h-4 shrink-0" />
                {t("teacherDashboardSidebar")}
              </Link>
            )}
            {user?.role === "parent" && (
              <Link
                href="/app/parent-dashboard"
                className={navLinkClass("/app/parent-dashboard")}
              >
                <Baby className="w-4 h-4 shrink-0" />
                {t("parent")}
              </Link>
            )}
            {isAdmin() && (
              <Link href="/app/admin" className={navLinkClass("/app/admin")}>
                <LayoutDashboard className="w-4 h-4 shrink-0" />
                {t("admin")}
              </Link>
            )}
          </nav>

          <div className="flex items-center gap-2">
            <div className="relative" ref={notifRef}>
              <button
                type="button"
                onClick={() => setNotifOpen(!notifOpen)}
                className="p-2 rounded-lg text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                title={t("notifications")}
              >
                <div className="relative">
                  <Bell className="w-5 h-5" />
                  {unread.length > 0 && (
                    <span className="absolute -top-1 -right-1 min-w-[18px] h-[18px] px-1 text-xs bg-red-500 text-white rounded-full flex items-center justify-center">
                      {unread.length > 9 ? "9+" : unread.length}
                    </span>
                  )}
                </div>
              </button>
              {notifOpen && (
                <div className="absolute right-0 top-full mt-1 w-[min(20rem,calc(100vw-1.5rem))] max-w-[calc(100vw-2rem)] bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded-xl shadow-xl z-50 max-h-[32rem] flex flex-col">
                  <div className="p-3 border-b dark:border-gray-600 flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between bg-gray-50/50 dark:bg-gray-800/50">
                    <span className="text-xs font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 shrink-0">{t("notifications")}</span>
                    {unread.length > 0 && (
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          markAllRead();
                        }}
                        className="text-xs font-semibold text-[var(--qit-primary)] dark:text-[var(--qit-secondary)] hover:underline text-left sm:text-right leading-snug whitespace-normal"
                      >
                        {t("markAllAsRead")}
                      </button>
                    )}
                  </div>
                  <div className="overflow-y-auto flex-1">
                    {notifications.length === 0 ? (
                      <p className="p-4 text-gray-500 dark:text-gray-400 text-sm text-center">
                        {t("noNotifications")}
                      </p>
                    ) : (
                      notifications.slice(0, 50).map((n) => {
                        const { title, message } = getLocalizedNotificationText(n, t);
                        return (
                          <button
                            key={n.id}
                            type="button"
                            onClick={() => markRead(n.id, n.link)}
                            className={`w-full text-left px-4 py-3 border-b dark:border-gray-600 last:border-0 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors ${
                              !n.is_read ? "bg-[var(--qit-primary)]/5 border-l-2 border-l-[var(--qit-primary)]" : ""
                            }`}
                          >
                            <p className={cn("text-sm", !n.is_read ? "font-bold" : "font-medium text-gray-700 dark:text-gray-200")}>{title}</p>
                            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5 line-clamp-2 break-words">{message}</p>
                            <p className="text-[10px] text-gray-400 mt-1 whitespace-nowrap">
                              {formatLocalizedDate(n.created_at, lang, t, { includeTime: true, shortMonth: true })}
                            </p>
                          </button>
                        );
                      })
                    )}
                  </div>
                </div>
              )}
            </div>

            <AppHeader />

            {/* Mobile nav - hamburger on small screens */}
            <div className="md:hidden">
              <MobileNavMenu
                pathname={pathname}
                navLinkClass={navLinkClass}
                isTeacher={isTeacher}
                isAdmin={isAdmin}
                userRole={user?.role}
                t={t as (key: string) => string}
              />
            </div>

            <div className="relative" ref={userMenuRef}>
              <button
                type="button"
                onClick={() => setUserMenuOpen(!userMenuOpen)}
                className="flex items-center gap-2 px-2 md:px-3 py-2 rounded-lg text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
              >
                <div className="w-8 h-8 rounded-full bg-[var(--qit-primary)]/20 dark:bg-[var(--qit-secondary)]/20 flex items-center justify-center text-[var(--qit-primary)] dark:text-[var(--qit-secondary)] font-semibold text-sm">
                  {(user?.full_name || "U")[0].toUpperCase()}
                </div>
                <span className="hidden lg:inline text-sm font-medium">
                  {user?.full_name || t("profile")}
                </span>
                <ChevronDown className={`hidden md:block w-4 h-4 transition-transform ${userMenuOpen ? "rotate-180" : ""}`} />
              </button>
              {userMenuOpen && (
                <div className="absolute right-0 top-full mt-1 py-1 w-48 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded-xl shadow-xl z-50">
                  <Link
                    href="/app/profile"
                    onClick={() => setUserMenuOpen(false)}
                    className="flex items-center gap-2 px-4 py-2.5 text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                  >
                    <User className="w-4 h-4" />
                    {t("profile")}
                  </Link>
                  <button
                    type="button"
                    onClick={() => {
                      queryClient.clear();
                      logout();
                      router.push("/");
                      setUserMenuOpen(false);
                    }}
                    className="w-full flex items-center gap-2 px-4 py-2.5 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                  >
                    <LogOut className="w-4 h-4" />
                    {t("logout")}
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </header>
  );
}

function MobileNavMenu({
  pathname,
  navLinkClass,
  isTeacher,
  isAdmin,
  userRole,
  t,
}: {
  pathname: string;
  navLinkClass: (href: string) => string;
  isTeacher: () => boolean;
  isAdmin: () => boolean;
  userRole?: string;
  t: (key: string) => string;
}) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    const close = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener("click", close);
    return () => document.removeEventListener("click", close);
  }, [open]);

  const links: { href: string; icon: typeof BookOpen; label: string }[] = [
    ...(isTeacher() ? [] : [{ href: "/app/courses", icon: BookOpen, label: t("courses") }]),
    { href: "/app/leaderboard", icon: Trophy, label: t("rating") },
    { href: "/app/tasks-calendar", icon: Calendar, label: t("tasksCalendar") },
    { href: "/app", icon: Zap, label: t("aiVsStudent") },
    { href: "/app/shop", icon: ShoppingBag, label: t("shop") },
    ...(isTeacher() ? [{ href: "/app/teacher", icon: Users, label: t("teacherDashboardSidebar") }] : []),
    ...(userRole === "parent" ? [{ href: "/app/parent-dashboard", icon: Baby, label: t("parent") }] : []),
    ...(isAdmin() ? [{ href: "/app/admin", icon: LayoutDashboard, label: t("admin") }] : []),
  ];

  return (
    <div ref={ref}>
      <button
        type="button"
        onClick={() => setOpen(!open)}
        className="p-2 rounded-lg text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700"
        aria-label={t("openMenu")}
      >
        <Menu className="w-6 h-6" />
      </button>
      {open && (
        <div className="absolute right-0 top-full mt-1 py-2 w-56 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded-xl shadow-xl z-50 flex flex-col gap-0.5">
          {links.map(({ href, icon: Icon, label }) => (
            <Link
              key={href}
              href={href}
              onClick={() => setOpen(false)}
              className={`${navLinkClass(href)} w-full justify-start mx-2`}
            >
              <Icon className="w-4 h-4 shrink-0" />
              {label}
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { api } from "@/api/client";
import { useLanguage } from "@/context/LanguageContext";
import { toast } from "@/store/notificationStore";
import { useTheme } from "@/context/ThemeContext";
import { CreditCard, Smartphone, Loader2 } from "lucide-react";
import { getModalStyle, getTextColors } from "@/utils/themeStyles";
import { getLocalizedCourseTitle } from "@/lib/courseUtils";

type PaymentStep = "method" | "card" | "loading" | "done";
type LoadingPhase = "connect" | "process" | "confirm";

interface PendingPayment {
  id: number;
  course_id: number;
  course_title: string | null;
  amount: number;
}

export function ApprovedApplicationPaymentModal({
  payment,
  onClose,
  onSuccess,
}: {
  payment: PendingPayment;
  onClose: () => void;
  onSuccess: () => void;
}) {
  const { t, lang } = useLanguage();
  const { theme } = useTheme();
  const modalStyle = getModalStyle(theme);
  const textColors = getTextColors(theme);
  const isDark = theme === "dark";
  const queryClient = useQueryClient();
  const [step, setStep] = useState<PaymentStep>("method");
  const [loadingPhase, setLoadingPhase] = useState<LoadingPhase>("connect");
  const [cardNumber, setCardNumber] = useState("");
  const [cardExpiry, setCardExpiry] = useState("");
  const [cardCvv, setCardCvv] = useState("");
  const [paying, setPaying] = useState(false);
  const [transactionId, setTransactionId] = useState<string | null>(null);

  const handlePay = async () => {
    if (!cardNumber || !cardExpiry || !cardCvv) {
      toast.error(t("paymentFillAllFields"));
      return;
    }
    setPaying(true);
    setStep("loading");
    setLoadingPhase("connect");
    setTransactionId(null);
    try {
      await new Promise((r) => setTimeout(r, 1200));
      setLoadingPhase("process");
      await new Promise((r) => setTimeout(r, 1200));
      setLoadingPhase("confirm");
      const { data } = await api.post<{ transaction_id?: string }>(`/payments/${payment.id}/confirm`);
      setTransactionId(data.transaction_id ?? `TXN-${payment.id.toString().padStart(8, "0")}`);
      setStep("done");
      queryClient.invalidateQueries({ queryKey: ["my-enrollments"] });
      queryClient.invalidateQueries({ queryKey: ["payments-pending"] });
      // Keep "done" state longer for user to read the message
    } catch (e) {
      setStep("card");
      setPaying(false);
      const err = e as { response?: { data?: { detail?: string } } };
      toast.error(err.response?.data?.detail ?? t("error"));
    }
  };

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
      role="dialog"
      aria-modal="true"
    >
      <div className="rounded-3xl shadow-2xl p-8 max-w-md w-full max-h-[90vh] flex flex-col border-0 overflow-hidden relative backdrop-blur-xl" style={modalStyle}>
        {step !== "done" && (
          <button
            onClick={onClose}
            className="absolute top-4 right-4 p-2 rounded-full hover:opacity-80 z-10"
            style={{ color: textColors.secondary }}
          >
            ×
          </button>
        )}

        <h2 className="text-2xl font-bold mb-6 text-center flex-shrink-0" style={{ color: textColors.primary }}>
          {step === "method" && t("paymentSelectMethod")}
          {step === "card" && t("paymentEnterCardData")}
          {step === "loading" && t("paymentProcessing")}
          {step === "done" && t("paymentAccepted")}
        </h2>

        <div className="min-h-0 max-h-[85vh] overflow-y-auto">
        {step === "method" && (
          <>
            <div className="bg-blue-50 dark:bg-blue-900/20 rounded-2xl p-4 mb-6 border border-blue-100 dark:border-blue-800">
              <div className="flex justify-between items-center mb-1">
                <span className="text-sm text-blue-600 dark:text-blue-400 font-medium">{t("goToPayment")}</span>
                <span className="text-xl font-bold text-blue-700 dark:text-blue-300">{payment.amount.toLocaleString(lang === "kk" ? "kk-KZ" : lang === "ru" ? "ru-RU" : "en-US")} ₸</span>
              </div>
              <p className="text-xs text-blue-500/80 truncate">{payment.course_title ? getLocalizedCourseTitle({ title: payment.course_title } as any, t) : ""}</p>
            </div>

            <div className="grid grid-cols-1 gap-3 mb-8">
              <button
                type="button"
                onClick={() => setStep("card")}
                className="group relative flex items-center gap-4 p-4 rounded-2xl border-2 border-gray-100 dark:border-gray-700 hover:border-blue-500 hover:bg-blue-50/30 dark:hover:bg-blue-500/5 transition-all duration-300 text-left"
              >
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                  <CreditCard className="w-6 h-6" />
                </div>
                <div>
                  <p className="font-semibold text-gray-800 dark:text-white">{t("paymentBankCard")}</p>
                  <p className="text-xs text-gray-500">{t("paymentCardsSupported")}</p>
                </div>
              </button>

              <button
                type="button"
                onClick={() => setStep("card")}
                className="group relative flex items-center gap-4 p-4 rounded-2xl border-2 border-gray-100 dark:border-gray-700 hover:border-red-500 hover:bg-red-50/30 dark:hover:bg-red-500/5 transition-all duration-300 text-left"
              >
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-red-500 to-red-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform font-bold italic">
                  K
                </div>
                <div>
                  <p className="font-semibold text-gray-800 dark:text-white">Kaspi.kz</p>
                  <p className="text-xs text-gray-500">{t("paymentViaApp")}</p>
                </div>
              </button>

              <button
                type="button"
                onClick={() => setStep("card")}
                className="group relative flex items-center gap-4 p-4 rounded-2xl border-2 border-gray-100 dark:border-gray-700 hover:border-green-500 hover:bg-green-50/30 dark:hover:bg-green-500/5 transition-all duration-300 text-left"
              >
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                  <Smartphone className="w-6 h-6" />
                </div>
                <div>
                  <p className="font-semibold text-gray-800 dark:text-white">Halyk Bank</p>
                  <p className="text-xs text-gray-500">Halyk Pay / QR</p>
                </div>
              </button>

              <button
                type="button"
                onClick={() => setStep("card")}
                className="group relative flex items-center gap-4 p-4 rounded-2xl border-2 border-gray-100 dark:border-gray-700 hover:border-purple-500 hover:bg-purple-50/30 dark:hover:bg-purple-500/5 transition-all duration-300 text-left"
              >
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-purple-500 to-purple-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                  <Smartphone className="w-6 h-6" />
                </div>
                <div>
                  <p className="font-semibold text-gray-800 dark:text-white">{t("eurasianBank")}</p>
                  <p className="text-xs text-gray-500">{t("paymentBankCard")}</p>
                </div>
              </button>

              <button
                type="button"
                onClick={() => setStep("card")}
                className="group relative flex items-center gap-4 p-4 rounded-2xl border-2 border-gray-100 dark:border-gray-700 hover:border-yellow-500 hover:bg-yellow-50/30 dark:hover:bg-yellow-500/5 transition-all duration-300 text-left"
              >
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-yellow-500 to-yellow-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                  <Smartphone className="w-6 h-6" />
                </div>
                <div>
                  <p className="font-semibold text-gray-800 dark:text-white">{t("tinkoff")}</p>
                  <p className="text-xs text-gray-500">{t("paymentBankCard")}</p>
                </div>
              </button>

              <button
                type="button"
                onClick={() => setStep("card")}
                className="group relative flex items-center gap-4 p-4 rounded-2xl border-2 border-gray-100 dark:border-gray-700 hover:border-blue-500 hover:bg-blue-50/30 dark:hover:bg-blue-500/5 transition-all duration-300 text-left"
              >
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                  <Smartphone className="w-6 h-6" />
                </div>
                <div>
                  <p className="font-semibold text-gray-800 dark:text-white">{t("jusan")}</p>
                  <p className="text-xs text-gray-500">{t("paymentBankCard")}</p>
                </div>
              </button>

              <button
                type="button"
                onClick={() => setStep("card")}
                className="group relative flex items-center gap-4 p-4 rounded-2xl border-2 border-gray-100 dark:border-gray-700 hover:border-indigo-500 hover:bg-indigo-50/30 dark:hover:bg-indigo-500/5 transition-all duration-300 text-left"
              >
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-indigo-500 to-indigo-600 flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
                  <Smartphone className="w-6 h-6" />
                </div>
                <div>
                  <p className="font-semibold text-gray-800 dark:text-white">{t("forte")}</p>
                  <p className="text-xs text-gray-500">{t("paymentBankCard")}</p>
                </div>
              </button>
            </div>
          </>
        )}

        {step === "card" && (
          <>
            <div className="bg-gray-100 dark:bg-gray-700/50 rounded-2xl p-6 mb-6 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 rounded-full -mr-16 -mt-16" />
              <div className="relative z-10">
                <div className="flex justify-between items-start mb-8">
                  <div className="w-10 h-7 bg-yellow-400/80 rounded-md" />
                  <CreditCard className="w-8 h-8 text-gray-400" />
                </div>
                <div className="space-y-4">
                  <input
                    type="text"
                    value={cardNumber}
                    onChange={(e) => setCardNumber(e.target.value)}
                    className="w-full bg-transparent border-b-2 border-gray-300 dark:border-gray-600 focus:border-blue-500 outline-none px-0 py-1 text-lg font-mono tracking-widest placeholder-gray-400"
                    placeholder={t("cardNumberPlaceholder")}
                    maxLength={19}
                  />
                  <div className="flex gap-6">
                    <div className="flex-1">
                      <input
                        type="text"
                        value={cardExpiry}
                        onChange={(e) => setCardExpiry(e.target.value)}
                        className="w-full bg-transparent border-b-2 border-gray-300 dark:border-gray-600 focus:border-blue-500 outline-none px-0 py-1 text-sm font-mono placeholder-gray-400"
                        placeholder={t("paymentExpiryPlaceholder")}
                        maxLength={5}
                      />
                    </div>
                    <div className="w-20">
                      <input
                        type="password"
                        value={cardCvv}
                        onChange={(e) => setCardCvv(e.target.value)}
                        className="w-full bg-transparent border-b-2 border-gray-300 dark:border-gray-600 focus:border-blue-500 outline-none px-0 py-1 text-sm font-mono placeholder-gray-400"
                        placeholder={t("cardCvvPlaceholder")}
                        maxLength={3}
                      />
                    </div>
                  </div>
                </div>
              </div>
            </div>
            <div className="flex gap-3">
              <button
                type="button"
                onClick={() => setStep("method")}
                className="py-3 px-6 rounded-2xl border border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
              >
                {t("back")}
              </button>
              <button
                type="button"
                onClick={handlePay}
                disabled={paying}
                className="flex-1 py-3 px-6 rounded-2xl text-white font-bold shadow-lg shadow-blue-500/30 disabled:opacity-50 transition-all active:scale-95 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700"
              >
                {paying ? (
                  <div className="flex items-center justify-center gap-2">
                    <Loader2 className="w-4 h-4 animate-spin" /> {t("paymentPay")}...
                  </div>
                ) : (
                  t("paymentPayAmount").replace("{amount}", payment.amount.toLocaleString(lang === "kk" ? "kk-KZ" : lang === "ru" ? "ru-RU" : "en-US"))
                )}
              </button>
            </div>
          </>
        )}

        {step === "loading" && (
          <div className="flex flex-col items-center py-12">
            <div className="relative mb-8">
              <div className="w-20 h-20 rounded-full border-4 border-gray-100 dark:border-gray-700" />
              <Loader2 className="absolute top-0 left-0 w-20 h-20 animate-spin text-blue-500" style={{ borderWidth: '4px' }} />
            </div>
            <p className="text-xl font-semibold text-gray-800 dark:text-white mb-2 text-center">
              {loadingPhase === "connect" && t("paymentConnecting")}
              {loadingPhase === "process" && t("paymentProcessingData")}
              {loadingPhase === "confirm" && t("paymentConfirming")}
            </p>
            <p className="text-gray-500 text-center text-sm px-4">{t("paymentDoNotClose")}</p>
          </div>
        )}

        {step === "done" && (
          <div className="flex flex-col items-center py-6 text-center">
            <div className="w-24 h-24 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mb-6 animate-[bounce_1s_ease-in-out]">
              <div className="w-16 h-16 bg-green-500 rounded-full flex items-center justify-center text-white shadow-lg shadow-green-500/40">
                <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
              </div>
            </div>
            <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">{t("paymentSuccess")}</h3>
            <p className="text-gray-600 dark:text-gray-300 text-lg leading-relaxed mb-8 px-4">
              {t("paymentManagerNotification")}
            </p>
            <button
              onClick={() => {
                onSuccess();
                onClose();
              }}
              className="w-full py-4 rounded-2xl bg-gray-900 dark:bg-white text-white dark:text-gray-900 font-bold hover:opacity-90 transition-all active:scale-95 shadow-xl"
            >
              {t("paymentReturnToPlatform")}
            </button>
          </div>
        )}
        </div>
      </div>
    </div>
  );
}

