                                      {deadlineDate &&
                                        ` • ${t("assignmentDeadline")}: ${formatLocalizedDate(a.deadline, lang, t, { shortMonth: true })}`}
                                    </p>
                                    {isOverdue && (
                                      <span className="inline-block mt-2 text-xs font-medium" style={{ color: "#EF4444" }}>
                                        {t("parentOverdue")}
                                      </span>
                                    )}
                                  </div>
                                </div>
                              </div>
                            </BlurFade>
                            );
                          })}
                        {childAssignmentsData.assignments
                          .filter((a) => a.submitted)
                          .map((a, submittedIndex) => (
                            <BlurFade key={a.id} delay={0.4 + submittedIndex * 0.06} duration={0.4} blur="4px" offset={12} direction="up">
                              <div
                                className="p-4 rounded-lg"
                                style={{ background: isDark ? "rgba(30, 41, 59, 0.4)" : "rgba(0, 0, 0, 0.02)" }}
                              >
                              <div className="flex items-start gap-2">
                                <CheckCircle2 className="w-4 h-4 shrink-0 mt-0.5" style={{ color: "#10B981" }} />
                                <div className="flex-1">
                                  <p className="font-medium" style={{ color: textColors.primary }}>
                                    {a.title}
                                  </p>
                                  <p className="text-xs mt-1" style={{ color: textColors.secondary }}>
                                    {getLocalizedCourseTitle({ title: a.course_title } as any, t)}
                                    {a.grade != null && ` • ${t("assignmentGrade")}: ${a.grade}`}
                                  </p>
                                  {a.teacher_comment && (
                                    <p className="text-sm mt-2 italic" style={{ color: textColors.secondary }}>
                                      "{a.teacher_comment}"
                                    </p>
                                  )}
                                  <span className="inline-block mt-2 text-xs font-medium" style={{ color: "#10B981" }}>
                                    {t("assignmentsSubmitted")}
                                  </span>
                                </div>
                              </div>
                            </div>
                          </BlurFade>
                          ))}
                      </div>
                    )}
                  </div>
                )}
              </div>
            )}
          </div>
          </div>
        </BlurFade>
      )}
    </div>
  );
}

"use client";

import { TrendingUp, BarChart3, Lock } from "lucide-react";
import Link from "next/link";
import { useTheme } from "@/context/ThemeContext";
import { useLanguage } from "@/context/LanguageContext";
import { getDashboardCardStyle, getTextColors } from "@/utils/themeStyles";
import { useQuery } from "@tanstack/react-query";
import { api } from "@/api/client";

export function PerformanceMetricsWidget() {
  const { theme } = useTheme();
  const { t } = useLanguage();
  const cardStyle = getDashboardCardStyle(theme);
  const textColors = getTextColors(theme);
  const isDark = theme === "dark";

  const { data, isLoading } = useQuery({
    queryKey: ["student-performance"],
    queryFn: async () => {
      const { data } = await api.get("/analytics/student/me/performance");
      return data;
    },
  });

  const isPremium = data?.is_premium;
  const performance = data?.performance || [];

  if (isLoading) {
    return (
      <div className="rounded-xl p-5 animate-pulse" style={cardStyle}>
        <div className="h-40 bg-gray-200 dark:bg-gray-700 rounded-lg"></div>
      </div>
    );
  }

  return (
    <div
      className="relative rounded-xl p-5 transition-all duration-300 hover:shadow-lg overflow-hidden"
      style={cardStyle}
    >
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <div
            className="w-10 h-10 rounded-lg flex items-center justify-center"
            style={{
              background: isDark ? "rgba(139, 92, 246, 0.2)" : "rgba(139, 92, 246, 0.1)",
              color: "#8B5CF6",
            }}
          >
            <BarChart3 className="w-5 h-5" />
          </div>
          <h3 className="text-lg font-semibold" style={{ color: textColors.primary }}>
            {t("performanceMetrics")}
          </h3>
        </div>
      </div>

      {/* Metrics grid */}
      <div className="grid grid-cols-3 gap-2.5 mb-4">
        {performance.length > 0 ? (
          performance.slice(-3).map((p: any, index: number) => (
            <div
              key={index}
              className="p-3 rounded-lg text-center"
              style={{
                background: isDark ? "rgba(255, 255, 255, 0.04)" : "rgba(0, 0, 0, 0.02)",
              }}
            >
              <p className="text-2xl font-bold mb-1" style={{ color: textColors.primary }}>
                {p.avg_quiz_score}%
              </p>
              <p className="text-[10px] mb-1.5 line-clamp-1" style={{ color: textColors.secondary }}>
