import type { Lang, TranslationKey } from "@/i18n/translations";

type Achievement = {
  id: number;
  title_key: string;
  description_key: string;
  title: string;
  description: string;
  icon: "trophy" | "award" | "star" | "medal";
  date: string;
  color: string;
};

const getIcon = (icon: Achievement["icon"]) => {
  switch (icon) {
    case "trophy":
      return Trophy;
    case "award":
      return Award;
    case "star":
      return Star;
    case "medal":
      return Medal;
    default:
      return Trophy;
  }
};

function formatAchievementDate(
  dateStr: string,
  translate: (key: TranslationKey) => string,
  lang: Lang,
): string {
  const date = new Date(dateStr);
  const now = new Date();
  const diffDays = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24));
  if (diffDays === 0) return translate("today");
  if (diffDays === 1) return translate("yesterday");
  if (diffDays < 7) return translate("daysAgo").replace("{count}", String(diffDays));
  return formatLocalizedDate(dateStr, lang, translate);
}

