      "bg-gradient-to-br from-slate-300 to-slate-500 ring-2 ring-slate-200/70 dark:ring-slate-500/40",
    crown: "text-slate-50 drop-shadow-sm",
    sparkles: { first: "#94a3b8", second: "#64748b" } as const,
  },
  3: {
    card: "from-orange-50/90 via-amber-50/35 to-transparent dark:from-orange-900/25 dark:via-amber-900/12 dark:to-transparent border-orange-200/70 dark:border-orange-800/45",
    iconBg:
      "bg-gradient-to-br from-orange-400 to-amber-600 ring-2 ring-orange-300/55 dark:ring-orange-600/40",
    crown: "text-orange-50 drop-shadow-sm",
    sparkles: { first: "#fb923c", second: "#d97706" } as const,
  },
} as const;

function clampRank(rank: number): 1 | 2 | 3 {
  if (rank === 1 || rank === 2 || rank === 3) return rank;
  return 3;
}

type Props = {
  item: LeaderboardTopHistoryItem;
  lang: Lang;
  t: (key: TranslationKey) => string;
  /** MagicCard + SparklesText (own profile); plain card for minimal public view when false */
  fancy?: boolean;
};

export function LeaderboardTopAchievementCard({ item, lang, t, fancy = false }: Props) {
  const r = clampRank(item.rank);
  const styles = RANK_STYLES[r];
  const titleKey = `profileAchievementTop${r}` as TranslationKey;
  const title = t(titleKey);
  const coinsLine =
    item.amount > 0
      ? t("profileAchievementTopCoins").replace("{amount}", String(item.amount))
      : null;
  const dateStr = formatLocalizedDate(item.date, lang as any, t);

  const content = (
    <>
      <div
        className={cn(
          "w-11 h-11 sm:w-12 sm:h-12 rounded-full flex items-center justify-center shrink-0 shadow-inner",
          styles.iconBg,
        )}
      >
        <Crown
          className={cn(
            "w-5 h-5 sm:w-6 sm:h-6",
            styles.crown,
            fancy && item.rank === 1 && "animate-bounce",
          )}
        />
      </div>
      <div className="min-w-0 flex-1">
        {fancy ? (
          <SparklesText
            className="text-sm font-semibold text-gray-900 dark:text-white"
            sparklesCount={3}
            colors={styles.sparkles}
          >
            {title}
          </SparklesText>
        ) : (
          <p className="text-sm font-semibold text-gray-800 dark:text-white">{title}</p>
        )}
        <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">{dateStr}</p>
        {coinsLine ? (
          <p className="text-xs text-amber-600 dark:text-amber-400 mt-0.5">{coinsLine}</p>
        ) : null}
      </div>
    </>
  );

  const shellClass = cn(
    "flex items-center gap-3 p-3 rounded-xl border bg-gradient-to-r hover:shadow-md transition-all",
    styles.card,
  );

  if (fancy) {
    return <MagicCard className={shellClass}>{content}</MagicCard>;
  }

  return <div className={shellClass}>{content}</div>;
}

"use client";

import type { ReactNode } from "react";
import { Loader2, Crown } from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";
import type { SafeProfilePreviewData } from "@/types/profiles";
import { formatLocalizedDate } from "@/utils/dateUtils";
import type { TranslationKey } from "@/i18n/translations";
import {
  mapProfileStatus,
  mapEmploymentStatus,
  mapEducationLevel,
  mapSystemRole,
  mapKinshipDegree,
  mapEducationalProcessRole,
  mapStudyForm,
  profileEmptyDash,
  mapCity,
  mapRole,
} from "@/lib/profileFieldLabels";

type ProfilePreviewCardProps = {
  profile: SafeProfilePreviewData;
  className?: string;
  rank?: number;
};

type FieldItem = {
  label: string;
  value: ReactNode;
};

function localizedGender(raw: string | null | undefined, t: (k: TranslationKey) => string) {
  if (!raw) return "";
  const keys: Record<string, TranslationKey> = {
    Мужской: "profileGenderMale",
    Женский: "profileGenderFemale",
    Другое: "profileGenderOther",
  };
  const key = keys[raw];
  return key ? t(key) : raw;
}

type Section = {
  title: string;
  items: FieldItem[];
};

type TFn = (key: TranslationKey) => string;

function hasMeaningfulValue(value: unknown): boolean {
  if (value === null || value === undefined) return false;
  if (typeof value === "string") return value.trim().length > 0;
  if (Array.isArray(value)) return value.length > 0;
  return true;
}

function formatList(values?: string[] | null): string | null {
  if (!values || values.length === 0) return null;
  return values.filter(Boolean).join(", ");
}

function formatDate(value: string | null | undefined, lang: string, t: any): string | null {
  if (!value) return null;
  return formatLocalizedDate(value, lang as any, t);
}

function pickRoleLabel(profile: SafeProfilePreviewData, t: TFn): string {
  return mapRole(profile.role, t);
}

const teacherLikeWorkSection = (profile: SafeProfilePreviewData, t: TFn): Section => ({
  title: t("profileWorkInfo"),
  items: [
    { label: t("profilePosition"), value: profile.position ?? "" },
    { label: t("profileDepartment"), value: profile.department ?? "" },
    { label: t("profileEducation"), value: profile.education ?? "" },
    { label: t("profileAcademicDegree"), value: profile.academic_degree ?? "" },
    { label: t("profileOffice"), value: profile.office ?? "" },
    {
      label: t("profileEmploymentStatus"),
      value: mapEmploymentStatus(profile.employment_status, t) || (profile.employment_status ?? ""),
    },
    { label: t("profileEmployeeNumber"), value: profile.employee_number ?? "" },
    { label: t("profileReceptionHours"), value: profile.reception_hours ?? "" },
    { label: t("profileConsultationLocation"), value: profile.consultation_location ?? "" },
    { label: t("profileCuratedCourses"), value: formatList(profile.curated_courses) ?? "" },
    { label: t("profileSubjectsTaught"), value: formatList(profile.subjects_taught) ?? "" },
    { label: t("profileAcademicInterests"), value: profile.academic_interests ?? "" },
  ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
});

function SectionCard({ title, items, className }: Section & { className?: string }) {
  if (!items.length) return null;

  return (
    <div className={`rounded-2xl border border-gray-200 dark:border-gray-700 bg-gray-50/80 dark:bg-gray-800/60 p-4 ${className ?? ""}`}>
      <h3 className="font-semibold text-gray-800 dark:text-white mb-3">{title}</h3>
      <dl className="grid grid-cols-1 sm:grid-cols-2 gap-3">
        {items.map((item) => (
          <div key={item.label} className="min-w-0">
            <dt className="text-xs uppercase tracking-wide text-gray-500 dark:text-gray-400 mb-1">{item.label}</dt>
            <dd className="text-sm text-gray-700 dark:text-gray-200 break-words">{item.value}</dd>
          </div>
        ))}
      </dl>
    </div>
  );
}

export function ProfilePreviewCard({ profile, className, rank }: ProfilePreviewCardProps) {
  const { t, lang } = useLanguage();

  const roleLabel = pickRoleLabel(profile, t);
  const memberSince = formatDate(profile.created_at, lang, t);

  const isTopThree = rank != null && rank >= 1 && rank <= 3;

  const mappedStatus = mapProfileStatus(profile.status, t);
  const displayStatus = mappedStatus || profile.status;

  const dash = profileEmptyDash(t);

  function maskValue(value: string | null | undefined): string {
    if (!value || value.length < 4) return dash;
    const visibleStart = value.length > 8 ? 3 : 1;
    const visibleEnd = 3;
    const masked = "*".repeat(value.length - visibleStart - visibleEnd);
    return value.substring(0, visibleStart) + masked + value.substring(value.length - visibleEnd);
  }

  const baseSections: Section[] = [
    {
      title: t("profileBasicInfoSection"),
      items: [
        { label: t("profileFullName"), value: profile.full_name },
        { label: t("role"), value: roleLabel },
        { label: t("profileStatus"), value: displayStatus ? displayStatus : dash },
        { label: t("profileGender"), value: localizedGender(profile.gender, t) },
        { label: t("profileNationality"), value: profile.nationality ?? "" },
        { label: t("profileBirthDate"), value: profile.birth_date ? formatDate(profile.birth_date, lang, t) : dash },
        { label: t("profileCity"), value: profile.city ? mapCity(profile.city, t) : dash },
      ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
    },
    {
      title: t("profileContactsSection"),
      items: [
        { label: t("profilePersonalEmail"), value: profile.email },
        { label: t("profilePhone"), value: profile.phone ? profile.phone : dash },
        { label: t("profilePhoneAlternative"), value: profile.phone_alternative ?? "" },
        { label: t("profileWorkEmail"), value: profile.email_work ?? "" },
        { label: t("profileWorkPhone"), value: profile.phone_work ?? "" },
      ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
    },
  ];

  if (profile.role === "student") {
    baseSections.push({
      title: t("profileEducationInfo"),
      items: [
        { label: t("profileSpecialty"), value: profile.specialty ?? "" },
        { label: t("profileCourse"), value: profile.course != null ? String(profile.course) : "" },
        { label: t("profileGroups"), value: profile.group ?? "" },
        { label: t("profileStudyForm"), value: mapStudyForm(profile.study_form, t) || (profile.study_form ?? "") },
        { label: t("profileParent"), value: profile.parent?.full_name ? `${profile.parent.full_name}` : "" },
      ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
    });
    baseSections.push({
      title: t("profileLocationDetails"),
      items: [
        { label: t("profileCountry"), value: profile.country ?? "" },
        { label: t("profilePostalCode"), value: profile.postal_code ?? "" },
        { label: t("profileAddress"), value: profile.address ?? "" },
      ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
    });
    baseSections.push({
      title: t("profileDocumentInfo"),
      items: [
        { label: t("profileIin"), value: maskValue(profile.iin) },
        { label: t("profileIdentityCard"), value: maskValue(profile.identity_card) },
        { label: t("profileStudentIdCardNumber"), value: profile.student_id_card_number ?? "" },
      ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
    });
    baseSections.push({
      title: t("profileAcademicInfo"),
      items: [
        { label: t("profileAdmissionDate"), value: formatDate(profile.admission_date, lang, t) ?? "" },
        { label: t("profileGraduationDatePlanned"), value: formatDate(profile.graduation_date_planned, lang, t) ?? "" },
      ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
    });
  } else if (profile.role === "parent") {
    baseSections.push({
      title: t("profileWorkInfo"),
      items: [
        { label: t("profileWorkPlace"), value: profile.work_place ?? "" },
        { label: t("profilePosition"), value: profile.position ?? "" },
        { label: t("profileEducation"), value: profile.education ?? "" },
        { label: t("profileAcademicDegree"), value: profile.academic_degree ?? "" },
        {
          label: t("profileKinshipDegree"),
          value: mapKinshipDegree(profile.kinship_degree, t) || (profile.kinship_degree ?? ""),
        },
        {
          label: t("profileEducationalProcessRole"),
          value: mapEducationalProcessRole(profile.educational_process_role, t) || (profile.educational_process_role ?? ""),
        },
      ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
    });
  } else if (profile.role === "teacher" || profile.role === "curator") {
    baseSections.push(teacherLikeWorkSection(profile, t));
  } else if (profile.role === "admin" || profile.role === "director") {
    baseSections.push({
      title: t("profileAccessInfo"),
      items: [
        { label: t("profilePosition"), value: profile.position ?? "" },
        { label: t("profileDepartment"), value: profile.department ?? "" },
        {
          label: t("profileEducationLevel"),
          value: mapEducationLevel(profile.education_level, t) || (profile.education_level ?? ""),
        },
        { label: t("profileOffice"), value: profile.office ?? "" },
        {
          label: t("profileSystemRole"),
          value: mapSystemRole(profile.system_role, t) || (profile.system_role ?? ""),
        },
        { label: t("profilePermissions"), value: formatList(profile.permissions) ?? "" },
        { label: t("profileAreasOfResponsibility"), value: formatList(profile.areas_of_responsibility) ?? "" },
      ].filter((item) => hasMeaningfulValue(item.value)) as FieldItem[],
    });
  }

  const extraNotes: string[] = [];
  if (profile.description) extraNotes.push(profile.description);
  if (memberSince) extraNotes.push(`${t("profileMemberSince")} ${memberSince}`);

  const shouldSpanLastSectionFullWidth = baseSections.length % 2 === 1;

  return (
    <div className={className ?? ""}>
      <div className="rounded-[24px] border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 shadow-lg p-5 md:p-6">
        <div className="flex flex-col gap-5">
          <div>
            <p className="text-xs uppercase tracking-wide text-gray-500 dark:text-gray-400 mb-1">{t("profilePublicPreview")}</p>
            <div className="h-px bg-gray-200 dark:bg-gray-700" />
          </div>
          <div className="flex flex-col items-center text-center md:flex-row md:items-start md:text-left gap-4">
            <div className="relative shrink-0 mx-auto md:mx-0">
              <div className="w-20 h-20 rounded-2xl bg-[var(--qit-primary)]/10 flex items-center justify-center overflow-hidden">
                {profile.photo_url ? (
                  <img src={profile.photo_url} alt="" className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-[var(--qit-primary)] font-semibold text-2xl">
                    {profile.full_name.charAt(0).toUpperCase()}
                  </div>
                )}
              </div>
              {isTopThree && (
                <div className="absolute -top-4 -left-3 z-10 pointer-events-none">
                  {rank === 1 && <Crown className="w-10 h-10 text-yellow-500 rotate-[-15deg] drop-shadow-lg animate-bounce" />}
                  {rank === 2 && <Crown className="w-9 h-9 text-gray-400 rotate-[-10deg] drop-shadow-md" />}
                  {rank === 3 && <Crown className="w-9 h-9 text-orange-400 rotate-[-10deg] drop-shadow-md" />}
                </div>
              )}
            </div>
            <div className="min-w-0 flex-1 w-full flex flex-col items-center md:items-start">
              <div className="flex flex-wrap items-center justify-center md:justify-start gap-2 mb-1">
                <span className="inline-flex items-center rounded-full bg-[var(--qit-primary)]/10 px-3 py-1 text-xs font-semibold text-[var(--qit-primary)] dark:text-[#00b0ff]">
                  {roleLabel}
                </span>
                {displayStatus &&
                  (profile.role === "student" ? (
                    <>
                      <span className="hidden sm:inline-flex items-center rounded-full bg-gray-100 dark:bg-gray-700 px-3 py-1 text-xs font-medium text-gray-600 dark:text-gray-300">
                        {displayStatus}
                      </span>

                      <span className="sm:hidden inline-flex items-center justify-center rounded-full bg-[var(--qit-primary)]/10 border border-[var(--qit-primary)]/20 w-9 h-9 shrink-0">
                        <Loader2 className="w-4 h-4 text-[var(--qit-secondary)] animate-spin" />
                      </span>
                    </>
                  ) : (
                    <span className="inline-flex items-center rounded-full bg-gray-100 dark:bg-gray-700 px-3 py-1 text-xs font-medium text-gray-600 dark:text-gray-300">
                      {displayStatus}
                    </span>
                  ))}
              </div>
              <h2 className="text-xl sm:text-2xl font-bold text-gray-900 dark:text-white break-words text-center md:text-left w-full">
                {profile.full_name}
              </h2>
              <div className="mt-2 flex flex-col sm:flex-row sm:flex-wrap items-center md:items-start justify-center md:justify-start gap-x-4 gap-y-1 text-sm text-gray-500 dark:text-gray-400 w-full">
                <span className="mobile-safe-text">{profile.email}</span>
                {profile.phone && <span>{profile.phone}</span>}
                {profile.city && <span>{mapCity(profile.city, t)}</span>}
              </div>
            </div>
          </div>

          {extraNotes.length > 0 && (
            <div className="rounded-2xl bg-gray-50 dark:bg-gray-700/50 px-4 py-3 text-sm text-gray-600 dark:text-gray-300">
              {extraNotes.map((note) => (
                <p key={note} className="break-words">
                  {note}
                </p>
              ))}
            </div>
          )}

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
            {baseSections.map((section, index) => (
              <SectionCard
                key={section.title}
                title={section.title}
                items={section.items}
                className={shouldSpanLastSectionFullWidth && index === baseSections.length - 1 ? "xl:col-span-2" : ""}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Image from "next/image";
import { X, ShoppingCart, Trash2, ArrowLeft, Sparkles } from "lucide-react";
import { motion, AnimatePresence } from "motion/react";
import { useTheme } from "@/context/ThemeContext";
import { useLanguage } from "@/context/LanguageContext";
import { getGlassCardStyle, getTextColors } from "@/utils/themeStyles";
import { cn } from "@/lib/utils";
import { getLocalizedShopItemTitle } from "@/lib/shopUtils";

type ShopItem = {
  id: number;
  title: string;
  description: string | null;
  price_coins: number;
  original_price?: number;
  category: string;
  icon_name: string | null;
  image_url: string | null;
  has_premium_discount?: boolean;
};

type CartItem = ShopItem & {
  shop_item_id: number; // This is the ID of the actual shop item, distinct from the cart item's unique ID
  quantity: number;
};

interface CartSheetProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (itemId: number) => void;
  onUpdateQuantity: (itemId: number, quantity: number) => void;
  onCheckout: () => void;
  totalCost: number;
  userBalance: number;
  IconComponentMap: Record<string, React.ComponentType<{ className?: string }>>;
}

export function CartSheet({
  isOpen,
  onClose,
  items,
  onRemove,
  onUpdateQuantity,
  onCheckout,
  totalCost,
  userBalance,
  IconComponentMap,
}: CartSheetProps) {
  const { theme } = useTheme();
  const { t, lang } = useLanguage();
  const textColors = getTextColors(theme);
  const cardStyle = getGlassCardStyle(theme);
  const canCheckout = userBalance >= totalCost && items.length > 0;

  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 640);
    checkMobile();
    window.addEventListener("resize", checkMobile);
    return () => window.removeEventListener("resize", checkMobile);
  }, []);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => {
      document.body.style.overflow = "";
    };
  }, [isOpen]);

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black/50 backdrop-blur-md"
            onClick={onClose}
          />
          <motion.div
            initial={isMobile ? { y: "100%" } : { x: "100%" }}
            animate={isMobile ? { y: 0 } : { x: 0 }}
            exit={isMobile ? { y: "100%" } : { x: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 300 }}
            className={cn(
              "fixed z-50 overflow-hidden outline-none",
              isMobile 
                ? "inset-x-0 bottom-0 h-[65vh] w-full rounded-t-[2.5rem] border-t" 
                : "right-0 top-0 bottom-0 w-full max-w-md"
            )}
            style={{
              ...cardStyle,
              borderColor: theme === "dark" ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)"
            }}
          >
            <div className="flex h-full flex-col">
              {isMobile && (
                <div className="w-full flex justify-center pt-3 pb-1">
                  <div 
                    className="w-12 h-1.5 rounded-full" 
                    style={{ background: theme === "dark" ? "rgba(255,255,255,0.2)" : "rgba(0,0,0,0.1)" }}
                  />
                </div>
              )}
              <div className="flex items-center justify-between border-b p-4 gap-2" style={{ borderColor: theme === "dark" ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)" }}>
                <button
                  onClick={onClose}
                  className="rounded-lg p-2 transition-colors hover:bg-gray-100 dark:hover:bg-gray-800 flex items-center gap-1.5 shrink-0 min-h-[2.5rem] min-w-[2.5rem] justify-center"
                  aria-label={t("back")}
                >
                  <ArrowLeft className="w-5 h-5" style={{ color: textColors.secondary }} />
                  <span className="text-sm font-medium sm:hidden" style={{ color: textColors.secondary }}>{t("back")}</span>
                </button>
                <div className="flex items-center gap-2 min-w-0 flex-1 justify-center">
                  <ShoppingCart className="w-5 h-5 shrink-0" style={{ color: "#FF4181" }} />
                  <h2 className="text-lg font-semibold truncate" style={{ color: textColors.primary }}>
                    {t("shopCart")}
                  </h2>
                  {items.length > 0 && (
                    <span
                      className="rounded-full px-2 py-0.5 text-xs font-medium shrink-0"
                      style={{
                        background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)",
                        color: "#FFFFFF",
                      }}
                    >
                      {items.length}
                    </span>
                  )}
                </div>
                <button
                  onClick={onClose}
                  className="rounded-lg p-2 transition-colors hover:bg-gray-100 dark:hover:bg-gray-800 shrink-0 hidden sm:flex min-h-[2.5rem] min-w-[2.5rem] justify-center"
                  aria-label={t("back")}
                >
                  <X className="w-5 h-5" style={{ color: textColors.secondary }} />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-4">
                {items.length === 0 ? (
                  <div className="flex h-full flex-col items-center justify-center text-center">
                    <ShoppingCart className="w-16 h-16 mb-4 opacity-20" style={{ color: textColors.secondary }} />
                    <p className="text-lg font-medium mb-2" style={{ color: textColors.primary }}>
                      {t("shopCartEmpty")}
                    </p>
                    <p className="text-sm" style={{ color: textColors.secondary }}>
                      {t("shopAddItemsToCart")}
                    </p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {items.map((item) => {
                      const IconComponent = item.icon_name
                        ? IconComponentMap[item.icon_name] ?? ShoppingCart
                        : ShoppingCart;
                      return (
                        <div
                          key={item.id}
                          className="rounded-lg p-3 flex items-start gap-3"
                          style={{
                            ...cardStyle,
                            border: theme === "dark" ? "1px solid rgba(255,255,255,0.08)" : "1px solid rgba(0,0,0,0.06)",
                          }}
                        >
                          <div
                            className="w-12 h-12 rounded-lg overflow-hidden flex items-center justify-center shrink-0"
                            style={theme === "dark" ? { background: "rgba(255,65,129,0.1)" } : { background: "rgba(255,65,129,0.08)" }}
                          >
                            {item.image_url ? (
                              <Image
                                src={item.image_url}
                                alt={item.title}
                                width={48}
                                height={48}
                                className="w-full h-full object-cover"
                                unoptimized={item.image_url.startsWith("http")}
                              />
                            ) : (
                              <IconComponent className="w-6 h-6 text-[#FF4181]" />
                            )}
                          </div>
                          <div className="flex-1 min-w-0">
                            <h3 className="font-medium truncate" style={{ color: textColors.primary }}>
                              {getLocalizedShopItemTitle(item as any, lang)}
                            </h3>
                            <div className="flex items-center justify-between mt-1">
                              <div className="flex flex-col gap-1">
                                <div className="flex items-center gap-1">
                                  <Image src="/icons/coin.png" alt="" width={14} height={14} />
                                  <span className="text-sm font-medium" style={{ color: "#FBBF24" }}>
                                    {item.price_coins} × {item.quantity}
                                  </span>
                                  {item.has_premium_discount && item.original_price && (
                                    <span className="text-[10px] line-through opacity-40 ml-1" style={{ color: textColors.secondary }}>
                                      {item.original_price * item.quantity}
                                    </span>
                                  )}
                                </div>
                                <div className="flex items-center gap-2 mt-1">
                                  <button
                                    onClick={() => onUpdateQuantity(item.shop_item_id, Math.max(1, item.quantity - 1))}
                                    disabled={item.quantity <= 1}
                                    className="p-1 rounded hover:bg-black/5 dark:hover:bg-white/5 disabled:opacity-30 transition-colors"
                                    style={{ color: textColors.secondary }}
                                  >
                                    <div className="w-4 h-4 flex items-center justify-center font-bold text-lg">-</div>
                                  </button>
                                  <span className="text-xs font-medium w-4 text-center" style={{ color: textColors.primary }}>
                                    {item.quantity}
                                  </span>
                                  <button
                                    onClick={() => onUpdateQuantity(item.shop_item_id, item.quantity + 1)}
                                    className="p-1 rounded hover:bg-black/5 dark:hover:bg-white/5 transition-colors"
                                    style={{ color: textColors.secondary }}
                                  >
                                    <div className="w-4 h-4 flex items-center justify-center font-bold text-lg">+</div>
                                  </button>
                                </div>
                              </div>
                              <button
                                onClick={() => onRemove(item.shop_item_id)}
                                className="p-2 rounded hover:bg-red-500/10 text-red-500 transition-colors min-h-[2.25rem] min-w-[2.25rem] flex items-center justify-center self-end"
                              >
                                <Trash2 className="w-4 h-4" />
                              </button>
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>

              {items.length > 0 && (
                <div
                  className="border-t p-4 space-y-3"
                  style={{ borderColor: theme === "dark" ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)" }}
                >
                  <div className="flex items-center justify-between">
                    <span className="font-medium" style={{ color: textColors.primary }}>
                      {t("shopTotal")}:
                    </span>
                    <div className="flex items-center gap-1">
                      <Image src="/icons/coin.png" alt="" width={18} height={18} />
                      <span className="text-lg font-bold" style={{ color: "#FBBF24" }}>
                        {totalCost}
                      </span>
                    </div>
                  </div>
                  {items.some(i => i.has_premium_discount) && (
                    <div className="flex items-center justify-between text-xs font-medium">
                      <span className="text-pink-500">{t("shopPremiumSavings") || "Premium Savings"}:</span>
                      <div className="flex items-center gap-1 text-pink-500">
                        <Sparkles className="w-3 h-3" />
                        <span>
                          -{items.reduce((sum, i) => sum + ((i.original_price || i.price_coins) - i.price_coins) * i.quantity, 0)} coins
                        </span>
                      </div>
                    </div>
                  )}
                  {userBalance < totalCost && (
                    <p className="text-sm text-red-500">
                      {t("shopNotEnoughCoins")}. {t("shopNeedMoreCoins")} {totalCost - userBalance} coins
                    </p>
                  )}
                  <button
                    onClick={onCheckout}
                    disabled={!canCheckout}
                    className={cn(
                      "w-full py-3 rounded-lg font-medium text-white transition-all min-h-[2.75rem]",
                      canCheckout
                        ? "hover:opacity-90"
                        : "opacity-50 cursor-not-allowed"
                    )}
                    style={
                      canCheckout
                        ? { background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)" }
                        : { background: "rgba(0,0,0,0.1)" }
                    }
                  >
                    {t("shopCheckout")}
                  </button>
                </div>
              )}
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
}

"use client";

import { useState } from "react";
import Image from "next/image";
import { Heart, ShoppingCart, Sparkles } from "lucide-react";
import { motion, AnimatePresence } from "motion/react";
import { MagicCard } from "@/components/ui/magic-card";
import { BorderBeam } from "@/components/ui/border-beam";
import { useTheme } from "@/context/ThemeContext";
import { useLanguage } from "@/context/LanguageContext";
import { getTextColors } from "@/utils/themeStyles";
import { cn } from "@/lib/utils";
import { getLocalizedShopItemTitle, getLocalizedShopItemDesc } from "@/lib/shopUtils";

type ShopItem = {
  id: number;
  title: string;
  description: string | null;
  price_coins: number;
  original_price?: number;
  category: string;
  icon_name: string | null;
  image_url: string | null;
  has_premium_discount?: boolean;
};

interface ProductCardProps {
  item: ShopItem;
  canBuy: boolean;
  isPurchasing: boolean;
  isFavorite: boolean;
  onPurchase: (item: ShopItem) => void;
  onAddToCart: (item: ShopItem) => void;
  onToggleFavorite: (item: ShopItem) => void;
  onSelect: (item: ShopItem) => void;
  IconComponent: React.ComponentType<{ className?: string }>;
  index?: number;
}

export function ProductCard({
  item,
  canBuy,
  isPurchasing,
  isFavorite,
  onPurchase,
  onAddToCart,
  onToggleFavorite,
  onSelect,
  IconComponent,
  index = 0,
}: ProductCardProps) {
  const { t, lang } = useLanguage();
  const { theme } = useTheme();
  const textColors = getTextColors(theme);
  const [isHovered, setIsHovered] = useState(false);
  const [imageLoaded, setImageLoaded] = useState(false);

  return (
    <motion.div
      initial={{ opacity: 0, y: 20, scale: 0.95 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      transition={{
        duration: 0.4,
        delay: index * 0.05,
        ease: [0.25, 0.46, 0.45, 0.94],
      }}
      whileHover={{ y: -8, scale: 1.02 }}
      className="h-full"
    >
      <MagicCard
        className="relative overflow-hidden h-full group"
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        <motion.div
          className="rounded-xl p-4 sm:p-5 flex flex-col cursor-pointer backdrop-blur-sm relative z-10 h-full"
          onClick={() => onSelect(item)}
          role="button"
          tabIndex={0}
          onKeyDown={(e) => e.key === "Enter" && onSelect(item)}
          whileHover={{ scale: 1.01 }}
          transition={{ duration: 0.2 }}
        >
          {/* Header with image and favorite */}
          <div className="flex items-start justify-between mb-4">
            <motion.div
              className="flex items-center gap-3 flex-1 min-w-0"
              initial={false}
              animate={{ x: isHovered ? 2 : 0 }}
              transition={{ duration: 0.3 }}
            >
              <motion.div
                className={cn(
                  "w-14 h-14 rounded-xl overflow-hidden flex items-center justify-center shrink-0 relative",
                  theme === "dark" ? "bg-[rgba(255,65,129,0.15)]" : "bg-[rgba(255,65,129,0.1)]",
                  "shadow-lg shadow-pink-500/20"
                )}
                whileHover={{ scale: 1.1, rotate: 5 }}
                transition={{ type: "spring", stiffness: 300, damping: 20 }}
              >
                {item.image_url ? (
                  <>
                    <motion.div
                      className="absolute inset-0 bg-gradient-to-br from-pink-500/20 to-purple-500/20 opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                    />
                    <Image
                      src={item.image_url}
                      alt={item.title}
                      width={56}
                      height={56}
                      className={cn(
                        "w-full h-full object-cover transition-transform duration-500",
                        isHovered && "scale-110"
                      )}
                      unoptimized={item.image_url.startsWith("http")}
                      onLoad={() => setImageLoaded(true)}
                    />
                    <AnimatePresence>
                      {imageLoaded && (
                        <motion.div
                          initial={{ opacity: 0 }}
                          animate={{ opacity: 1 }}
                          exit={{ opacity: 0 }}
                          className="absolute inset-0"
                        />
                      )}
                    </AnimatePresence>
                  </>
                ) : (
                  <motion.div
                    animate={isHovered ? { rotate: 10 } : { rotate: 0 }}
                    transition={{ duration: 0.5, type: "tween" }}
                  >
                    <IconComponent className="w-7 h-7 text-[#FF4181]" />
                  </motion.div>
                )}
              </motion.div>
              <div className="min-w-0 flex-1">
                <motion.h3
                  className="font-semibold line-clamp-2 sm:line-clamp-1 text-base mb-1 mobile-safe-text"
                  style={{ color: textColors.primary }}
                  whileHover={{ x: 2 }}
                  transition={{ duration: 0.2 }}
                >
                  {getLocalizedShopItemTitle(item as any, lang, t)}
                </motion.h3>
                <motion.div
                  className="flex items-center gap-1.5"
                  initial={false}
                  animate={{ scale: isHovered ? 1.05 : 1 }}
                  transition={{ duration: 0.2 }}
                >
                  <motion.div
                    animate={isHovered ? { rotate: 15 } : { rotate: 0 }}
                    transition={{ duration: 0.6, type: "tween" }}
                  >
                    <Image src="/icons/coin.png" alt="" width={18} height={18} />
                  </motion.div>
                  <div className="flex flex-col">
                    <div className="flex items-center gap-1.5">
                      <motion.span
                        className="font-bold text-lg leading-none"
                        style={{ color: "#FBBF24" }}
                        animate={isHovered ? { scale: [1, 1.1, 1] } : {}}
                        transition={{ duration: 0.4 }}
                      >
                        {item.price_coins}
                      </motion.span>
                      {item.has_premium_discount && item.original_price && (
                        <span className="text-xs line-through opacity-50 font-medium" style={{ color: textColors.secondary }}>
                          {item.original_price}
                        </span>
                      )}
                    </div>
                    {item.has_premium_discount && (
                      <span className="text-[10px] font-bold text-pink-500 uppercase tracking-wider leading-none mt-1">
                        Premium -15%
                      </span>
                    )}
                  </div>
                </motion.div>
              </div>
            </motion.div>
            <motion.button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                onToggleFavorite(item);
              }}
              className={cn(
                "p-2.5 rounded-xl shrink-0 relative overflow-hidden min-h-[2.5rem] min-w-[2.5rem]",
                isFavorite
                  ? "bg-gradient-to-br from-red-500/20 to-pink-500/20 text-red-500"
                  : "bg-transparent text-gray-400 hover:text-red-500"
              )}
              whileHover={{ scale: 1.1, rotate: 10 }}
              whileTap={{ scale: 0.9 }}
              transition={{ type: "spring", stiffness: 400, damping: 17 }}
            >
              <AnimatePresence mode="wait">
                {isFavorite ? (
                  <motion.div
                    key="filled"
                    initial={{ scale: 0, rotate: -180 }}
                    animate={{ scale: 1, rotate: 0 }}
                    exit={{ scale: 0, rotate: 180 }}
                    transition={{ type: "spring", stiffness: 500, damping: 25 }}
                  >
                    <Heart className="w-5 h-5 fill-current" />
                  </motion.div>
                ) : (
                  <motion.div
                    key="outline"
                    initial={{ scale: 1 }}
                    exit={{ scale: 0 }}
                    transition={{ duration: 0.15 }}
                  >
                    <Heart className="w-5 h-5" />
                  </motion.div>
                )}
              </AnimatePresence>
              {isFavorite && (
                <motion.div
                  className="absolute inset-0 bg-red-500/10"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: [0, 1, 0] }}
                  transition={{ duration: 0.6, repeat: Infinity, repeatDelay: 2 }}
                />
              )}
            </motion.button>
          </div>

          {/* Description */}
          {item.description && (
            <motion.p
              className="text-sm mb-4 flex-1 line-clamp-2 leading-relaxed mobile-safe-text"
              style={{ color: textColors.secondary }}
              initial={false}
              animate={{ opacity: isHovered ? 1 : 0.8 }}
              transition={{ duration: 0.2 }}
            >
              {getLocalizedShopItemDesc(item as any, lang, t)}
            </motion.p>
          )}

          {/* Action buttons */}
          <div className="flex gap-2 mt-auto">
            <motion.button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                if (canBuy) {
                  onPurchase(item);
                }
              }}
              disabled={!canBuy || isPurchasing}
              className={cn(
                "flex-1 py-2.5 rounded-xl font-semibold text-sm relative overflow-hidden min-h-[2.75rem]",
                canBuy
                  ? "text-white shadow-lg shadow-pink-500/30"
                  : "cursor-not-allowed",
                theme === "dark"
                  ? canBuy
                    ? ""
                    : "bg-[rgba(26,34,56,0.5)] text-[#94A3B8]"
                  : canBuy
                    ? ""
                    : "bg-[rgba(0,0,0,0.05)] text-[#64748B]"
              )}
              style={
                canBuy
                  ? { background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)" }
                  : undefined
              }
              whileHover={canBuy ? { scale: 1.02, y: -2 } : {}}
              whileTap={canBuy ? { scale: 0.98 } : {}}
              transition={{ type: "spring", stiffness: 400, damping: 17 }}
            >
              {canBuy && (
                <motion.div
                  className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent"
                  animate={{
                    x: ["-100%", "100%"],
                  }}
                  transition={{
                    duration: 2,
                    repeat: Infinity,
                    repeatDelay: 1,
                    ease: "linear",
                  }}
                />
              )}
              <span className="relative z-10">
                {isPurchasing ? (
                  <motion.span
                    className="inline-flex items-center gap-2"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                  >
                    <motion.span
                      animate={{ rotate: 360 }}
                      transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                    >
                      <Sparkles className="w-4 h-4" />
                    </motion.span>
                    {t("purchasing")}
                  </motion.span>
                ) : canBuy ? (
                  t("buyCourse")
                ) : (
                  t("notEnoughCoins")
                )}
              </span>
            </motion.button>
            <motion.button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                onAddToCart(item);
              }}
              disabled={!canBuy}
              className={cn(
                "px-4 py-2.5 rounded-xl relative overflow-hidden min-h-[2.75rem]",
                canBuy
                  ? "bg-gradient-to-br from-blue-500/10 to-cyan-500/10 text-blue-500 hover:from-blue-500/20 hover:to-cyan-500/20 shadow-md shadow-blue-500/10"
                  : "bg-[rgba(0,0,0,0.05)] text-gray-400 cursor-not-allowed"
              )}
              whileHover={canBuy ? { scale: 1.1, rotate: 5 } : {}}
              whileTap={canBuy ? { scale: 0.9 } : {}}
              transition={{ type: "spring", stiffness: 400, damping: 17 }}
              title={t("addToCart")}
            >
              <ShoppingCart className="w-5 h-5" />
              {canBuy && isHovered && (
                <motion.div
                  className="absolute inset-0 bg-blue-500/10"
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: 1.5, opacity: 0 }}
                  transition={{ duration: 0.4 }}
                />
              )}
            </motion.button>
          </div>
        </motion.div>

        {/* Enhanced Border Beam */}
        <BorderBeam
          size={120}
          duration={8}
          colorFrom="#FF4181"
          colorTo="#B938EB"
          delay={0}
          borderWidth={2}
        />

        {/* Hover glow effect */}
        <motion.div
          className="absolute inset-0 opacity-0 group-hover:opacity-100 pointer-events-none"
          style={{
            background: "radial-gradient(circle at 50% 0%, rgba(255, 65, 129, 0.1), transparent 70%)",
          }}
          transition={{ duration: 0.3 }}
        />
      </MagicCard>
    </motion.div>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { motion, AnimatePresence } from "motion/react";
import { CheckCircle, Package, Calendar } from "lucide-react";
import { Confetti, ConfettiRef } from "@/components/ui/confetti";
import { useTheme } from "@/context/ThemeContext";
import { getModalStyle, getTextColors } from "@/utils/themeStyles";
import { cn } from "@/lib/utils";

import { useLanguage } from "@/context/LanguageContext";
import { formatLocalizedDate } from "@/utils/dateUtils";

interface PurchaseSuccessModalProps {
  isOpen: boolean;
  onClose: () => void;
  itemTitle: string;
  estimatedDeliveryDate?: string;
}

export function PurchaseSuccessModal({
  isOpen,
  onClose,
  itemTitle,
  estimatedDeliveryDate,
}: PurchaseSuccessModalProps) {
  const { t, lang } = useLanguage();
  const { theme } = useTheme();
  const textColors = getTextColors(theme);
  const modalStyle = getModalStyle(theme);
  const confettiRef = useRef<ConfettiRef>(null);

  useEffect(() => {
    if (isOpen && confettiRef.current) {
      setTimeout(() => {
        confettiRef.current?.fire({
          particleCount: 100,
          spread: 70,
          origin: { y: 0.6 },
          colors: ["#FF4181", "#B938EB", "#FBBF24", "#06B6D4"],
        });
      }, 100);
    }
  }, [isOpen]);

  const deliveryDate = estimatedDeliveryDate
    ? formatLocalizedDate(estimatedDeliveryDate, lang as any, t)
    : null;

  return (
    <>
      <Confetti ref={confettiRef} manualstart />
      <AnimatePresence>
        {isOpen && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 z-50 flex items-center justify-center p-4"
              style={{ background: theme === "dark" ? "rgba(0,0,0,0.7)" : "rgba(0,0,0,0.5)" }}
              onClick={onClose}
            >
              <motion.div
                initial={{ scale: 0.9, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.9, opacity: 0 }}
                transition={{ type: "spring", damping: 25, stiffness: 300 }}
                className="rounded-2xl shadow-xl max-w-md w-full overflow-hidden relative"
                style={modalStyle}
                onClick={(e) => e.stopPropagation()}
              >
                <div className="p-8 text-center">
                  <motion.div
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    transition={{ delay: 0.2, type: "spring", stiffness: 200 }}
                    className="w-20 h-20 mx-auto mb-6 rounded-full flex items-center justify-center"
                    style={{
                      background: "linear-gradient(135deg, #10B981 0%, #34D399 100%)",
                    }}
                  >
                    <CheckCircle className="w-12 h-12 text-white" />
                  </motion.div>

                  <motion.h2
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ delay: 0.3 }}
                    className="text-2xl font-bold mb-2"
                    style={{ color: textColors.primary }}
                  >
                    {t("shopPurchaseSuccess")}
                  </motion.h2>

                  <motion.p
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ delay: 0.4 }}
                    className="text-lg mb-6"
                    style={{ color: textColors.secondary }}
                  >
                    {itemTitle}
                  </motion.p>

                  <motion.div
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ delay: 0.5 }}
                    className="rounded-xl p-4 mb-6"
                    style={{
                      background: theme === "dark" ? "rgba(6,182,212,0.1)" : "rgba(6,182,212,0.05)",
                      border: theme === "dark" ? "1px solid rgba(6,182,212,0.3)" : "1px solid rgba(6,182,212,0.2)",
                    }}
                  >
                    <p className="text-sm text-center mb-3" style={{ color: textColors.secondary }}>
                      {itemTitle === t("shopCartItems") ? t("shopCartItemsHint") : t("shopDeliveryEstimated")}
                    </p>
                    {deliveryDate && (
                      <div className="flex items-center gap-2 justify-center">
                        <Calendar className="w-4 h-4" style={{ color: "#06B6D4" }} />
                        <p className="text-sm" style={{ color: textColors.secondary }}>
                          {itemTitle === t("shopCartItems") ? t("shopCartItemsDeliveryDate") : t("shopDeliveryDateLabel")} {deliveryDate}
                        </p>
                      </div>
                    )}
                  </motion.div>

                  <motion.button
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ delay: 0.6 }}
                    onClick={onClose}
                    className={cn(
                      "w-full py-3 rounded-lg font-medium text-white transition-all hover:opacity-90"
                    )}
                    style={{ background: "linear-gradient(135deg, #FF4181 0%, #B938EB 100%)" }}
                  >
                    {t("shopGreat")}
                  </motion.button>
                </div>
              </motion.div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </>
  );
}

"use client";

import { useLanguage } from "@/context/LanguageContext";
import { getLocalizedCourseTitle, getLocalizedTopicTitle } from "@/lib/courseUtils";
import { cn } from "@/lib/utils";

type Topic = { id: number; title: string };

interface AddTaskPanelProps {
  selectedDate: Date;
  courseId: number | "";
  topicId: number | "";
  notes: string;
  error: string;
  courses: Array<{ id: number; title: string }>;
  topics: Topic[];
  isPending: boolean;
  onCourseChange: (courseId: number | "") => void;
  onTopicChange: (topicId: number | "") => void;
  onNotesChange: (notes: string) => void;
  onSubmit: () => void;
  onCancel: () => void;
}

export function AddTaskPanel({
  selectedDate,
  courseId,
  topicId,
  notes,
  error,
  courses,
  topics,
  isPending,
  onCourseChange,
  onTopicChange,
  onNotesChange,
  onSubmit,
  onCancel,
}: AddTaskPanelProps) {
  const { t } = useLanguage();

  return (
    <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg border border-gray-100 dark:border-gray-700 p-6 h-fit">
      <h2 className="font-semibold text-gray-800 dark:text-white text-lg mb-4">
        {t("scheduleAddTask")}
      </h2>

      {error && (
        <div className="mb-4 p-3 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-sm">
          {error}
        </div>
      )}

      <div className="space-y-4">
        <div>
          <select
            value={courseId}
            onChange={(e) => onCourseChange(Number(e.target.value) || "")}
            className={cn(
              "w-full border dark:border-gray-600 rounded-lg px-3 py-2.5",
              "dark:bg-gray-700 dark:text-white",
              "focus:ring-2 focus:ring-[var(--qit-primary)] focus:border-[var(--qit-primary)]",
              "transition-colors"
            )}
          >
            <option value="">{t("scheduleSelectCourse")}</option>
            {courses.map((c) => (
              <option key={c.id} value={c.id}>
                {getLocalizedCourseTitle(c as any, t)}
              </option>
            ))}
          </select>
        </div>

        {courseId && topics.length > 0 && (
          <div>
            <select
              value={topicId}
              onChange={(e) => onTopicChange(Number(e.target.value) || "")}
              className={cn(
                "w-full border dark:border-gray-600 rounded-lg px-3 py-2.5",
                "dark:bg-gray-700 dark:text-white",
                "focus:ring-2 focus:ring-[var(--qit-primary)]",
                "transition-colors"
              )}
            >
              <option value="">{t("scheduleSelectTopic")}</option>
              {topics.map((topic) => (
                <option key={topic.id} value={topic.id}>
                  {getLocalizedTopicTitle(topic.title, t)}
                </option>
              ))}
            </select>
          </div>
        )}

        <div>
          <input
            type="text"
            placeholder={t("scheduleNotes")}
            value={notes}
            onChange={(e) => onNotesChange(e.target.value)}
            className={cn(
              "w-full border dark:border-gray-600 rounded-lg px-3 py-2.5",
              "dark:bg-gray-700 dark:text-white",
              "focus:ring-2 focus:ring-[var(--qit-primary)]",
              "transition-colors"
            )}
          />
        </div>

        <div className="flex gap-2 pt-2">
          <button
            type="button"
            onClick={onSubmit}
            disabled={isPending}
            className={cn(
              "py-2.5 px-5 rounded-lg text-white font-medium",
              "disabled:opacity-50 disabled:cursor-not-allowed",
              "transition-all hover:opacity-90"
            )}
            style={{ background: "var(--qit-primary)" }}
          >
            {t("scheduleAdd")}
          </button>
          <button
            type="button"
            onClick={onCancel}
            className={cn(
              "py-2.5 px-5 rounded-lg border dark:border-gray-600",
              "hover:bg-gray-100 dark:hover:bg-gray-700",
              "text-gray-700 dark:text-gray-300",
              "transition-colors"
            )}
          >
            {t("cancel")}
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

import { Filter, X } from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";

type Course = { id: number; title: string };

interface CalendarFiltersProps {
  courses: Course[];
  selectedCourseId: number | "";
  selectedStatus: "all" | "completed" | "pending";
  dateFrom: string;
  dateTo: string;
  sortType: "none" | "status" | "course" | "time";
  onCourseChange: (courseId: number | "") => void;
  onStatusChange: (status: "all" | "completed" | "pending") => void;
  onDateFromChange: (date: string) => void;
  onDateToChange: (date: string) => void;
  onSortChange: (sortType: "none" | "status" | "course" | "time") => void;
  onClear: () => void;
}

export function CalendarFilters({
  courses,
  selectedCourseId,
  selectedStatus,
  dateFrom,
  dateTo,
  sortType,
  onCourseChange,
  onStatusChange,
  onDateFromChange,
  onDateToChange,
  onSortChange,
  onClear,
}: CalendarFiltersProps) {
  const { t } = useLanguage();
  const hasFilters = selectedCourseId !== "" || selectedStatus !== "all" || dateFrom !== "" || dateTo !== "";

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-4 space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold text-gray-800 dark:text-white flex items-center gap-2">
          <Filter className="w-4 h-4" />
          {t("scheduleFilters")}
        </h3>
        {hasFilters && (
          <button
            type="button"
            onClick={onClear}
            className="text-xs text-[#7C3AED] hover:opacity-80 flex items-center gap-1"
          >
            <X className="w-3 h-3" />
            {t("scheduleClearFilters")}
          </button>
        )}
      </div>

      {/* Course filter */}
      <div>
        <label className="text-xs font-medium text-gray-600 dark:text-gray-400 block mb-1">
          {t("assignmentCourse")}
        </label>
        <select
          value={selectedCourseId}
          onChange={(e) => onCourseChange(e.target.value === "" ? "" : Number(e.target.value))}
          className="w-full px-3 py-2 text-sm rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-800 dark:text-white"
        >
          <option value="">{t("scheduleAllCourses")}</option>
          {courses.map((course) => (
            <option key={course.id} value={course.id}>
              {course.title}
            </option>
          ))}
        </select>
      </div>

      {/* Status filter */}
      <div>
        <label className="text-xs font-medium text-gray-600 dark:text-gray-400 block mb-1">
          {t("scheduleStatus")}
        </label>
        <select
          value={selectedStatus}
          onChange={(e) => onStatusChange(e.target.value as "all" | "completed" | "pending")}
          className="w-full px-3 py-2 text-sm rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-800 dark:text-white"
        >
          <option value="all">{t("scheduleAllStatus" as any)}</option>
          <option value="completed">{t("scheduleCompleted" as any)}</option>
          <option value="pending">{t("schedulePending" as any)}</option>
        </select>
      </div>

      {/* Date range filters */}
      <div className="space-y-2">
        <div>
          <label className="text-xs font-medium text-gray-600 dark:text-gray-400 block mb-1">
            {t("scheduleDateFrom")}
          </label>
          <input
            type="date"
            value={dateFrom}
            onChange={(e) => onDateFromChange(e.target.value)}
            className="w-full px-3 py-2 text-sm rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-800 dark:text-white"
          />
        </div>
        <div>
          <label className="text-xs font-medium text-gray-600 dark:text-gray-400 block mb-1">
            {t("scheduleDateTo")}
          </label>
          <input
            type="date"
            value={dateTo}
            onChange={(e) => onDateToChange(e.target.value)}
            className="w-full px-3 py-2 text-sm rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-800 dark:text-white"
          />
        </div>
      </div>

      {/* Sort */}
      <div>
        <label className="text-xs font-medium text-gray-600 dark:text-gray-400 block mb-1">
          {t("scheduleSort")}
        </label>
        <select
          value={sortType}
          onChange={(e) => onSortChange(e.target.value as "none" | "status" | "course" | "time")}
          className="w-full px-3 py-2 text-sm rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-800 dark:text-white"
        >
          <option value="none">{t("scheduleSortNone")}</option>
          <option value="status">{t("scheduleSortByStatus")}</option>
          <option value="course">{t("scheduleSortByCourse")}</option>
          <option value="time">{t("scheduleSortByTime")}</option>
        </select>
      </div>
    </div>
  );
}

