                      className="w-full px-4 py-3 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500/40"
                      style={{ ...inputStyle, color: textColors.primary }}
                    />
                    {titleError ? (
                      <p className="text-xs" style={{ color: "#F87171" }}>
