"use client";

import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { 
  CheckCircle2, 
  XCircle, 
  AlertCircle, 
  Info, 
  X 
} from "lucide-react";
import { NotificationType, Notification, useNotificationStore } from "@/store/notificationStore";
import { useTheme } from "@/context/ThemeContext";
import { getGlassCardStyle, getTextColors } from "@/utils/themeStyles";
import { cn } from "@/lib/utils";

const ICONS: Record<NotificationType, React.ReactNode> = {
  success: <CheckCircle2 className="w-5 h-5 text-emerald-500" />,
  error: <XCircle className="w-5 h-5 text-rose-500" />,
  warning: <AlertCircle className="w-5 h-5 text-amber-500" />,
  info: <Info className="w-5 h-5 text-sky-500" />,
};

const BORDERS: Record<NotificationType, string> = {
  success: "border-emerald-500/50 dark:border-emerald-500/30",
  error: "border-rose-500/50 dark:border-rose-500/30",
  warning: "border-amber-500/50 dark:border-amber-500/30",
  info: "border-sky-500/50 dark:border-sky-500/30",
};

interface ToastProps {
  notification: Notification;
}

export function Toast({ notification }: ToastProps) {
  const { removeNotification } = useNotificationStore();
  const { theme } = useTheme();
  const glassStyle = getGlassCardStyle(theme);
  const textColors = getTextColors(theme);

  const [progress, setProgress] = useState(100);
  const duration = notification.duration || 5000;

  useEffect(() => {
    if (duration === Infinity) return;

    const startTime = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - startTime;
      const remaining = Math.max(0, 100 - (elapsed / duration) * 100);
      setProgress(remaining);

      if (remaining === 0) {
        clearInterval(interval);
      }
    }, 50);

    return () => clearInterval(interval);
  }, [duration]);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 50, scale: 0.8 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      exit={{ opacity: 0, scale: 0.5, transition: { duration: 0.2 } }}
      className={cn(
        "relative group flex items-start gap-4 p-4 pr-12 rounded-2xl shadow-2xl mb-3 w-[320px] sm:w-[400px] border-l-4",
        BORDERS[notification.type]
      )}
      style={glassStyle}
    >
      <div className="shrink-0 mt-0.5">
        {ICONS[notification.type]}
      </div>

      <div className="flex-1 min-w-0">
        <p className="text-sm font-medium leading-relaxed" style={{ color: textColors.primary }}>
          {notification.message}
        </p>
      </div>

      <button
        type="button"
        onClick={() => removeNotification(notification.id)}
        className="absolute top-3 right-3 p-1 rounded-full opacity-0 group-hover:opacity-100 hover:bg-black/5 dark:hover:bg-white/5 transition-all"
        style={{ color: textColors.secondary }}
      >
        <X className="w-4 h-4" />
      </button>

      {duration !== Infinity && (
        <div className="absolute bottom-0 left-0 w-full h-1 bg-black/5 dark:bg-white/5 overflow-hidden rounded-b-2xl">
          <motion.div
            className={cn(
              "h-full rounded-full",
              notification.type === "success" && "bg-emerald-500",
              notification.type === "error" && "bg-rose-500",
              notification.type === "warning" && "bg-amber-500",
              notification.type === "info" && "bg-sky-500"
            )}
            initial={{ width: "100%" }}
            animate={{ width: `${progress}%` }}
            transition={{ ease: "linear" }}
          />
        </div>
      )}
    </motion.div>
  );
}

"use client"

import {
  useCallback,
  useEffect,
  useId,
  useRef,
  useState,
  type ComponentPropsWithoutRef,
} from "react"
import { motion } from "motion/react"

import { cn } from "@/lib/utils"

export interface AnimatedGridPatternProps extends ComponentPropsWithoutRef<"svg"> {
  width?: number
  height?: number
  x?: number
  y?: number
  strokeDasharray?: number
  numSquares?: number
  maxOpacity?: number
  duration?: number
  repeatDelay?: number
}

type Square = {
  id: number
  pos: [number, number]
  iteration: number
}

export function AnimatedGridPattern({
  width = 40,
  height = 40,
  x = -1,
  y = -1,
  strokeDasharray = 0,
  numSquares = 50,
  className,
  maxOpacity = 0.5,
  duration = 4,
  repeatDelay = 0.5,
  ...props
}: AnimatedGridPatternProps) {
  const id = useId()
  const containerRef = useRef<SVGSVGElement | null>(null)
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 })
  const [squares, setSquares] = useState<Array<Square>>([])

  const getPos = useCallback((): [number, number] => {
    return [
      Math.floor((Math.random() * dimensions.width) / width),
      Math.floor((Math.random() * dimensions.height) / height),
    ]
  }, [dimensions.height, dimensions.width, height, width])

  const generateSquares = useCallback(
    (count: number) => {
      return Array.from({ length: count }, (_, i) => ({
        id: i,
        pos: getPos(),
        iteration: 0,
      }))
    },
    [getPos]
  )

  const updateSquarePosition = useCallback(
    (squareId: number) => {
      setSquares((currentSquares) => {
        const current = currentSquares[squareId]
        if (!current || current.id !== squareId) return currentSquares

        const nextSquares = currentSquares.slice()
        nextSquares[squareId] = {
          ...current,
          pos: getPos(),
          iteration: current.iteration + 1,
        }

        return nextSquares
      })
    },
    [getPos]
  )

  useEffect(() => {
    if (dimensions.width && dimensions.height) {
      setSquares(generateSquares(numSquares))
    }
  }, [dimensions.width, dimensions.height, generateSquares, numSquares])

  useEffect(() => {
    const element = containerRef.current
    if (!element) return

    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setDimensions((currentDimensions) => {
          const nextWidth = entry.contentRect.width
          const nextHeight = entry.contentRect.height
          if (
            currentDimensions.width === nextWidth &&
            currentDimensions.height === nextHeight
          ) {
            return currentDimensions
          }
          return { width: nextWidth, height: nextHeight }
        })
      }
    })

    resizeObserver.observe(element)

    return () => {
      resizeObserver.disconnect()
    }
  }, [])

  return (
    <svg
      ref={containerRef}
      aria-hidden="true"
      className={cn(
        "pointer-events-none absolute inset-0 h-full w-full fill-gray-400/30 stroke-gray-400/30",
        className
      )}
      {...props}
    >
      <defs>
        <pattern
          id={id}
          width={width}
          height={height}
          patternUnits="userSpaceOnUse"
          x={x}
          y={y}
        >
          <path
            d={`M.5 ${height}V.5H${width}`}
            fill="none"
            strokeDasharray={strokeDasharray}
          />
        </pattern>
      </defs>
      <rect width="100%" height="100%" fill={`url(#${id})`} />
      <svg x={x} y={y} className="overflow-visible">
        {squares.map(({ pos: [squareX, squareY], id, iteration }, index) => (
          <motion.rect
            initial={{ opacity: 0 }}
            animate={{ opacity: maxOpacity }}
            transition={{
              duration,
              repeat: 1,
              delay: index * 0.1,
              repeatType: "reverse",
              repeatDelay,
            }}
            onAnimationComplete={() => updateSquarePosition(id)}
            key={`${id}-${iteration}`}
            width={width - 1}
            height={height - 1}
            x={squareX * width + 1}
            y={squareY * height + 1}
            fill="currentColor"
            strokeWidth="0"
          />
        ))}
      </svg>
    </svg>
  )
}

"use client"

import { useRef } from "react"
import {
  AnimatePresence,
  motion,
  useInView,
  type MotionProps,
  type UseInViewOptions,
  type Variants,
} from "motion/react"

type MarginType = UseInViewOptions["margin"]

interface BlurFadeProps extends MotionProps {
  children: React.ReactNode
  className?: string
  variant?: {
    hidden: { y: number }
    visible: { y: number }
  }
  duration?: number
  delay?: number
  offset?: number
  direction?: "up" | "down" | "left" | "right" | "diagonal-top-left" | "diagonal-top-right" | "diagonal-bottom-left" | "diagonal-bottom-right" | "scale"
  inView?: boolean
  inViewMargin?: MarginType
  blur?: string
  scale?: boolean
  rotation?: number
}

const getFilter = (v: Variants[string]) =>
  typeof v === "function" ? undefined : v.filter

export function BlurFade({
  children,
  className,
  variant,
  duration = 0.8,
  delay = 0,
  offset = 50,
  direction = "down",
  inView = false,
  inViewMargin = "-100px",
  blur = "12px",
  scale = false,
  rotation = 0,
  ...props
}: BlurFadeProps) {
  const ref = useRef(null)
  const inViewResult = useInView(ref, { once: true, margin: inViewMargin })
  const isInView = !inView || inViewResult

  // Создаем более драматичные варианты анимации
  const getDefaultVariants = (): Variants => {
    const baseHidden: any = {
      opacity: 0,
      filter: `blur(${blur})`,
    }
    const baseVisible: any = {
      opacity: 1,
      filter: `blur(0px)`,
    }

    switch (direction) {
      case "diagonal-top-left":
        return {
          hidden: {
            ...baseHidden,
            x: -offset * 1.5,
            y: -offset * 1.5,
            scale: scale ? 0.8 : 1,
            rotate: rotation || -5,
          },
          visible: {
            ...baseVisible,
            x: 0,
            y: 0,
            scale: 1,
            rotate: 0,
          },
        }
      case "diagonal-top-right":
        return {
          hidden: {
            ...baseHidden,
            x: offset * 1.5,
            y: -offset * 1.5,
            scale: scale ? 0.8 : 1,
            rotate: rotation || 5,
          },
          visible: {
            ...baseVisible,
            x: 0,
            y: 0,
            scale: 1,
            rotate: 0,
          },
        }
      case "diagonal-bottom-left":
        return {
          hidden: {
            ...baseHidden,
            x: -offset * 1.5,
            y: offset * 1.5,
            scale: scale ? 0.8 : 1,
            rotate: rotation || -5,
          },
          visible: {
            ...baseVisible,
            x: 0,
            y: 0,
            scale: 1,
            rotate: 0,
          },
        }
      case "diagonal-bottom-right":
        return {
          hidden: {
            ...baseHidden,
            x: offset * 1.5,
            y: offset * 1.5,
            scale: scale ? 0.8 : 1,
            rotate: rotation || 5,
          },
          visible: {
            ...baseVisible,
            x: 0,
            y: 0,
            scale: 1,
            rotate: 0,
          },
        }
      case "scale":
        return {
          hidden: {
            ...baseHidden,
            scale: 0.7,
            y: offset * 0.5,
          },
          visible: {
            ...baseVisible,
            scale: 1,
            y: 0,
          },
        }
      case "left":
        return {
          hidden: {
            ...baseHidden,
            x: -offset * 1.2,
            scale: scale ? 0.9 : 1,
            rotate: rotation || -3,
          },
          visible: {
            ...baseVisible,
            x: 0,
            scale: 1,
            rotate: 0,
          },
        }
      case "right":
        return {
          hidden: {
            ...baseHidden,
            x: offset * 1.2,
            scale: scale ? 0.9 : 1,
            rotate: rotation || 3,
          },
          visible: {
            ...baseVisible,
            x: 0,
            scale: 1,
            rotate: 0,
          },
        }
      case "up":
        return {
          hidden: {
            ...baseHidden,
            y: offset * 1.2,
            scale: scale ? 0.9 : 1,
          },
          visible: {
            ...baseVisible,
            y: 0,
            scale: 1,
          },
        }
      case "down":
      default:
        return {
          hidden: {
            ...baseHidden,
            y: -offset * 1.2,
            scale: scale ? 0.9 : 1,
          },
          visible: {
            ...baseVisible,
            y: 0,
            scale: 1,
          },
        }
    }
  }

  const defaultVariants = getDefaultVariants()
  const combinedVariants = variant ?? defaultVariants

  const hiddenFilter = getFilter(combinedVariants.hidden)
  const visibleFilter = getFilter(combinedVariants.visible)

  const shouldTransitionFilter =
    hiddenFilter != null &&
    visibleFilter != null &&
    hiddenFilter !== visibleFilter

  // Более драматичная easing функция с bounce эффектом
  const dramaticEase: [number, number, number, number] = [0.34, 1.56, 0.64, 1]

  return (
    <AnimatePresence>
      <motion.div
        ref={ref}
        initial="hidden"
        animate={isInView ? "visible" : "hidden"}
        exit="hidden"
        variants={combinedVariants}
        transition={{
          delay: delay,
          duration,
          ease: dramaticEase,
          ...(shouldTransitionFilter ? { filter: { duration: duration * 0.8, ease: dramaticEase } } : {}),
        }}
        className={className}
        {...props}
      >
        {children}
      </motion.div>
    </AnimatePresence>
  )
}

"use client"

import type { ReactNode } from "react"
import React, {
  createContext,
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
} from "react"
// @ts-ignore - canvas-confetti doesn't have type definitions
import type {
  GlobalOptions as ConfettiGlobalOptions,
  CreateTypes as ConfettiInstance,
  Options as ConfettiOptions,
} from "canvas-confetti"
import confetti from "canvas-confetti"

type Api = {
  fire: (options?: ConfettiOptions) => void
}

type Props = React.ComponentPropsWithRef<"canvas"> & {
  options?: ConfettiOptions
  globalOptions?: ConfettiGlobalOptions
  manualstart?: boolean
  children?: ReactNode
}

export type ConfettiRef = Api | null

const ConfettiContext = createContext<Api>({} as Api)

const ConfettiComponent = forwardRef<ConfettiRef, Props>((props, ref) => {
  const {
    options,
    globalOptions = { resize: true, useWorker: true },
    manualstart = false,
    children,
    ...rest
  } = props
  const instanceRef = useRef<ConfettiInstance | null>(null)

  const canvasRef = useCallback(
    (node: HTMLCanvasElement) => {
      if (node !== null) {
        if (instanceRef.current) return
        instanceRef.current = confetti.create(node, {
          ...globalOptions,
          resize: true,
        })
      } else {
        if (instanceRef.current) {
          instanceRef.current.reset()
          instanceRef.current = null
        }
      }
    },
    [globalOptions]
  )

  const fire = useCallback(
    async (opts = {}) => {
      try {
        await instanceRef.current?.({ ...options, ...opts })
      } catch (error) {
        console.error("Confetti error:", error)
      }
    },
    [options]
  )

  const api = useMemo(
    () => ({
      fire,
    }),
    [fire]
  )

  useImperativeHandle(ref, () => api, [api])

  useEffect(() => {
    if (!manualstart) {
      ;(async () => {
        try {
          await fire()
        } catch (error) {
          console.error("Confetti effect error:", error)
        }
      })()
    }
  }, [manualstart, fire])

  return (
    <ConfettiContext.Provider value={api}>
      <canvas ref={canvasRef} {...rest} />
      {children}
    </ConfettiContext.Provider>
  )
})

ConfettiComponent.displayName = "Confetti"

export const Confetti = ConfettiComponent

export const useConfetti = () => {
  return React.useContext(ConfettiContext)
}

